export const ATTACK_GENERATED: GeneratedTechnique[] = [{"id":"T1001","name":"Data Obfuscation","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1001","summary":"Adversaries may obfuscate command and control traffic to make it more difficult to detect.","description":"Adversaries may obfuscate command and control traffic to make it more difficult to detect. Command and control (C2) communications are hidden (but not necessarily encrypted) in an attempt to make the content more difficult to discover or decipher and to make the communication less conspicuous and hide commands from being seen. This encompasses many methods, such as adding junk data to protocol traffic, using steganography, or impersonating legitimate protocols.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Process Creation"],"examples":["DarkGate will retrieved encrypted commands from its command and control server for follow-on actions such as cryptocurrency mining.","FRAMESTING can send and receive zlib compressed data within POST requests.","FlawedAmmyy may obfuscate portions of the initial C2 handshake.","FunnyDream can send compressed and obfuscated packets to C2."],"examplesTotal":15,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate some obfuscation activity…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1003","name":"OS Credential Dumping","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1003","summary":"Adversaries may attempt to dump credentials to obtain account login and credential material, normally in the form of a hash or a clear text password.","description":"Adversaries may attempt to dump credentials to obtain account login and credential material, normally in the form of a hash or a clear text password. Credentials can be obtained from OS caches, memory, or structures. Credentials can then be used to perform Lateral Movement and access restricted information. Several of the tools mentioned in associated sub-techniques may be used by both adversaries and professional security testers. Additional custom tools likely exist as well.","platforms":["Linux","macOS","Windows"],"detection":["Active Directory Object Access","File Access","Process Access","Process Creation","Process Metadata"],"examples":["APT28 regularly deploys both publicly available (ex: Mimikatz) and custom password retrieval tools on victims.","APT32 used GetPassword_x64 to harvest credentials.","APT39 has used different versions of Mimikatz to obtain credentials.","Axiom has been known to dump credentials."],"examplesTotal":20,"mitigations":[{"name":"Encrypt Sensitive Information","text":"Ensure Domain Controller backups are properly secured.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to secure LSASS and prevent credential stealing.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Password Policies","text":"Ensure that local administrator accounts have complex, unique passwords across all systems on the network.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"User Training","text":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Privileged Account Management","text":"Windows: Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a…","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1003.001","name":"LSASS Memory","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1003/001","summary":"Adversaries may attempt to access credential material stored in the process memory of the Local Security Authority Subsystem Service (LSASS).","description":"Adversaries may attempt to access credential material stored in the process memory of the Local Security Authority Subsystem Service (LSASS). After a user logs on, the system generates and stores a variety of credential materials in LSASS process memory. These credential materials can be harvested by an administrative user or SYSTEM and used to conduct Lateral Movement using Use Alternate Authentication Material.","platforms":["Windows"],"detection":["File Creation","Process Access","Process Creation","User Account Metadata","Windows Registry Key Modification"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used Mimikatz to capture and use legitimate credentials.","During the 2025 Poland Wiper Attacks, the adversaries attempted to dump credentials utilizing LSASS.","APT1 has been known to use credential dumping using Mimikatz.","APT28 regularly deploys both publicly available (ex: Mimikatz) and custom password retrieval tools on victims. They have also dumped the LSASS process memory using the MiniDump function."],"examplesTotal":79,"mitigations":[{"name":"Operating System Configuration","text":"Consider disabling or restricting NTLM. Consider disabling WDigest authentication.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"Credential Access Protection","text":"With Windows 10, Microsoft implemented new protections called Credential Guard to protect the LSA secrets that can be used to obtain credentials through forms of credential…","url":"https://attack.mitre.org/mitigations/M1043"},{"name":"Privileged Process Integrity","text":"On Windows 8.1 and Windows Server 2012 R2, enable Protected Process Light for LSA.","url":"https://attack.mitre.org/mitigations/M1025"},{"name":"Privileged Account Management","text":"Do not put user or admin domain accounts in the local administrator groups across systems unless they are tightly controlled, as this is often equivalent to having a local…","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"User Training","text":"Limit credential overlap across accounts and systems by training users and administrators not to use the same password for multiple accounts.","url":"https://attack.mitre.org/mitigations/M1017"}]},{"id":"T1005","name":"Data from Local System","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1005","summary":"Adversaries may search local system sources, such as file systems, configuration files, local databases, virtual machine files, or process memory, to find files of interest and sensitive data prior to Exfiltration.","description":"Adversaries may search local system sources, such as file systems, configuration files, local databases, virtual machine files, or process memory, to find files of interest and sensitive data prior to Exfiltration. Adversaries may do this using a Command and Scripting Interpreter, such as cmd as well as a Network Device CLI, which have functionality to interact with the file system to gather information. Adversaries may also use Automated Collection on the local system.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Access","File Creation","Process Creation"],"examples":["APT1 has collected files from a local victim.","APT28 has retrieved internal documents from machines inside victim environments, including by using Forfiles to stage documents before exfiltration.","APT29 has stolen data from compromised hosts.","APT3 will identify Microsoft Office documents on the victim's computer."],"examplesTotal":229,"mitigations":[{"name":"Data Loss Prevention","text":"Data loss prevention can restrict access to sensitive data and detect sensitive data that is unencrypted.","url":"https://attack.mitre.org/mitigations/M1057"}]},{"id":"T1006","name":"Direct Volume Access","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1006","summary":"Adversaries may directly access a volume to bypass file access controls and file system monitoring.","description":"Adversaries may directly access a volume to bypass file access controls and file system monitoring. Windows allows programs to have direct access to logical volumes. Programs with direct access may read and write files directly from the drive by analyzing file system data structures. This technique may bypass Windows file access controls as well as file system monitoring tools. Utilities, such as NinjaCopy, exist to perform these actions in PowerShell.","platforms":["Network Devices","Windows"],"detection":["Command Execution","Process Access","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries copied volume shadow copies through executing vssadmin in order to dump the NTDS.dit file.","During APT28 Nearest Neighbor Campaign, APT28 accessed volume shadow copies through executing vssadmin in order to dump the NTDS.dit file.","Scattered Spider has created volume shadow copies of virtual domain controller disks to extract the NTDS.dit file.","Volt Typhoon has executed the Windows-native vssadmin command to create volume shadow copies."],"examplesTotal":5,"mitigations":[{"name":"Behavior Prevention on Endpoint","text":"Some endpoint security solutions can be configured to block some types of behaviors related to efforts by an adversary to create backups, such as command execution or preventing…","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"User Account Management","text":"Ensure only accounts required to configure and manage backups have the privileges to do so. Monitor these accounts for unauthorized backup activity.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1007","name":"System Service Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1007","summary":"Adversaries may try to gather information about registered local system services.","description":"Adversaries may try to gather information about registered local system services. Adversaries may obtain information about services using tools as well as OS utility commands such as sc query, tasklist /svc, systemctl --type=service, and net start. Adversaries may also gather information about schedule tasks via commands such as schtasks on Windows or crontab -l on Linux and macOS.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","Process Creation"],"examples":["APT1 used the commands net start and tasklist to get a listing of the services on the system.","Aquatic Panda has attempted to discover services for third party EDR products.","BBSRAT can query service configuration information.","BRONZE BUTLER has used TROJ_GETVERSION to discover system services."],"examplesTotal":69},{"id":"T1008","name":"Fallback Channels","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1008","summary":"Adversaries may use fallback or alternate communication channels if the primary channel is compromised or inaccessible in order to maintain reliable command and control and to avoid data transfer thresholds.","description":"Adversaries may use fallback or alternate communication channels if the primary channel is compromised or inaccessible in order to maintain reliable command and control and to avoid data transfer thresholds.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Network Connection Creation","Network Traffic Flow"],"examples":["APT41 used the Steam community page as a fallback mechanism for C2.","Anchor can use secondary C2 servers for communication after establishing connectivity and relaying victim information to primary C2 servers.","AppleSeed can use a second channel for C2 when the primary channel is in upload mode.","BISCUIT malware contains a secondary fallback command and control server that is contacted after the primary command and control server."],"examplesTotal":55,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1010","name":"Application Window Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1010","summary":"Adversaries may attempt to get a listing of open application windows.","description":"Adversaries may attempt to get a listing of open application windows. Window listings could convey information about how the system is used. For example, information about application windows could be used identify potential data to collect as well as identifying security tooling (Security Software Discovery) to evade. Adversaries typically abuse system features for this type of enumeration.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","OS API Execution","Process Access","Process Creation"],"examples":["Aria-body has the ability to identify the titles of running windows on a compromised host.","Attor can obtain application window titles and then determines which windows to perform Screen Capture on.","Cadelspy has the ability to identify open windows on the compromised host.","Catchamas obtains application windows titles and then determines which windows to perform Screen Capture on."],"examplesTotal":37},{"id":"T1011","name":"Exfiltration Over Other Network Medium","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1011","summary":"Adversaries may attempt to exfiltrate data over a different network medium than the command and control channel.","description":"Adversaries may attempt to exfiltrate data over a different network medium than the command and control channel. If the command and control network is a wired Internet connection, the exfiltration may occur, for example, over a WiFi connection, modem, cellular data connection, Bluetooth, or another radio frequency (RF) channel.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Creation","Host Status","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Disable WiFi connection, modem, cellular data connection, Bluetooth, or another radio frequency (RF) channel in local computer security settings or by group policy if it is not…","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Operating System Configuration","text":"Prevent the creation of new network adapters where possible.","url":"https://attack.mitre.org/mitigations/M1028"}]},{"id":"T1012","name":"Query Registry","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1012","summary":"Adversaries may interact with the Windows Registry to gather information about the system, configuration, and installed software.","description":"Adversaries may interact with the Windows Registry to gather information about the system, configuration, and installed software. The Registry contains a significant amount of information about the operating system, configuration, software, and security. Information can easily be queried using the Reg utility, though other means to access the Registry exist. Some of the information may help adversaries to further their operation within a network.","platforms":["Windows"],"detection":["Command Execution","Process Creation","Windows Registry Key Modification"],"examples":["ADVSTORESHELL can enumerate registry keys.","APT32's backdoor can query the Windows Registry to gather system information.","APT39 has used various strains of malware to query the Registry.","APT41 queried registry values to determine items such as configured RDP ports and network configurations."],"examplesTotal":119},{"id":"T1014","name":"Rootkit","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1014","summary":"Adversaries may use rootkits to hide the presence of programs, files, network connections, services, drivers, and other system components.","description":"Adversaries may use rootkits to hide the presence of programs, files, network connections, services, drivers, and other system components. Rootkits are programs that hide the existence of malware by intercepting/hooking and modifying operating system API calls that supply system information. Rootkits or rootkit enabling functionality may reside at the user or kernel level in the operating system or lower, to include a hypervisor or System Firmware.","platforms":["Linux","macOS","Windows"],"detection":["Driver Load","File Creation","File Modification","Module Load","Process Creation","Service Creation"],"examples":["APT28 has used a UEFI (Unified Extensible Firmware Interface) rootkit known as LoJax.","APT41 deployed rootkits on Linux systems.","ArcaneDoor included hooking the processHostScanReply() function on victim Cisco ASA devices.","COATHANGER hooks or replaces multiple legitimate processes and other functions on victim devices."],"examplesTotal":32},{"id":"T1016","name":"System Network Configuration Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1016","summary":"Adversaries may look for details about the network configuration and settings, such as IP and/or MAC addresses, of systems they access or through information discovery of remote systems.","description":"Adversaries may look for details about the network configuration and settings, such as IP and/or MAC addresses, of systems they access or through information discovery of remote systems. Several operating system administration utilities exist that can be used to gather this information. Examples include Arp, ipconfig/ifconfig, nbtstat, and route.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries gathered network configuration details utilizing arp -a and nslookup commands.","APT1 used the ipconfig /all command to gather network configuration information.","APT19 used an HTTP malware variant and a Port 22 malware variant to collect the MAC address and IP address from the victim’s machine.","A keylogging tool used by APT3 gathers network information from the victim, including the MAC address, IP address, WINS, DHCP server, and gateway."],"examplesTotal":285},{"id":"T1018","name":"Remote System Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1018","summary":"Adversaries may attempt to get a listing of other systems by IP address, hostname, or other logical identifier on a network that may be used for Lateral Movement from the current system.","description":"Adversaries may attempt to get a listing of other systems by IP address, hostname, or other logical identifier on a network that may be used for Lateral Movement from the current system. Functionality could exist within remote access tools to enable this, but utilities available on the operating system could also be used such as Ping, net view using Net, or, on ESXi servers, esxcli network diag ping.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Access","Network Connection Creation","Process Creation"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team remotely discovered systems over LAN connections. OT systems were visible from the IT network as well, giving adversaries the ability to discover operational assets.","During the 2016 Ukraine Electric Power Attack, Sandworm Team checked for connectivity to resources within the network and used LDAP to query Active Directory, discovering information about computers listed in AD.","APT3 has a tool that can detect the existence of remote systems.","APT32 has enumerated DC servers using the command net group \"Domain Controllers\" /domain. The group has also used the ping command."],"examplesTotal":102},{"id":"T1020","name":"Automated Exfiltration","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1020","summary":"Adversaries may exfiltrate data, such as sensitive documents, through the use of automated processing after being gathered during Collection.","description":"Adversaries may exfiltrate data, such as sensitive documents, through the use of automated processing after being gathered during Collection. When automated exfiltration is used, other exfiltration techniques likely apply as well to transfer the information out of the network, such as Exfiltration Over C2 Channel and Exfiltration Over Alternative Protocol.","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["Network Connection Creation","Process Creation","Scheduled Job Creation"],"examples":["ArcaneDoor included scripted exfiltration of collected data.","Attor has a file uploader plugin that automatically exfiltrates the collected data and log files to the C2 server.","CosmicDuke exfiltrates collected files automatically over FTP to remote servers.","Crutch has automatically exfiltrated stolen files to Dropbox."],"examplesTotal":30},{"id":"T1021","name":"Remote Services","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1021","summary":"Adversaries may use Valid Accounts to log into a service that accepts remote connections, such as telnet, SSH, and VNC.","description":"Adversaries may use Valid Accounts to log into a service that accepts remote connections, such as telnet, SSH, and VNC. The adversary may then perform actions as the logged-on user. In an enterprise environment, servers and workstations can be organized into domains. Domains provide centralized identity management, allowing users to login using one set of credentials across the entire network.","platforms":["Linux","macOS","Windows","IaaS","ESXi"],"detection":["Command Execution","Logon Session Creation","Network Connection Creation","Process Creation"],"examples":["Aquatic Panda used remote scheduled tasks to install malicious software on victim systems during lateral movement actions.","Brute Ratel C4 has the ability to use RPC for lateral movement.","Ember Bear uses valid network credentials gathered through credential harvesting to move laterally within victim networks, often employing the Impacket framework to do so.","Kivars has the ability to remotely trigger keyboard input and mouse clicks."],"examplesTotal":7,"mitigations":[{"name":"Limit Access to Resource Over Network","text":"Prevent unnecessary remote access to file shares, hypervisors, sensitive systems, etc. Mechanisms to limit access may include use of network concentrators, RDP gateways, etc.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Audit","text":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"User Account Management","text":"Limit the accounts that may use remote services. Limit the permissions for accounts that are at higher risk of compromise; for example, configure SSH so users can only run…","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Disable or Remove Feature or Program","text":"If remote services, such as the ability to make direct connections to cloud virtual machines, are not required, disable these connection types where feasible.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Multi-factor Authentication","text":"Use multi-factor authentication on remote service logons where possible.","url":"https://attack.mitre.org/mitigations/M1032"}]},{"id":"T1025","name":"Data from Removable Media","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1025","summary":"Adversaries may search connected removable media on computers they have compromised to find files of interest.","description":"Adversaries may search connected removable media on computers they have compromised to find files of interest. Sensitive data can be collected from any removable media (optical disk drive, USB memory, etc.) connected to the compromised system prior to Exfiltration. Interactive command shells may be in use, and common functionality within cmd may be used to gather information. Some adversaries may also use Automated Collection on removable media.","platforms":["Linux","macOS","Windows"],"detection":["Drive Creation","File Access","Process Creation"],"examples":["An APT28 backdoor may collect the entire contents of an inserted USB device.","AppleSeed can find and collect data from removable media devices.","Aria-body has the ability to collect data from USB devices.","BADNEWS copies files with certain extensions from USB devices to a predefined directory."],"examplesTotal":24,"mitigations":[{"name":"Data Loss Prevention","text":"Data loss prevention can restrict access to sensitive data and detect sensitive data that is unencrypted.","url":"https://attack.mitre.org/mitigations/M1057"}]},{"id":"T1027","name":"Obfuscated Files or Information","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1027","summary":"Adversaries may attempt to make an executable or file difficult to discover or analyze by encrypting, encoding, or otherwise obfuscating its contents on the system or in transit.","description":"Adversaries may attempt to make an executable or file difficult to discover or analyze by encrypting, encoding, or otherwise obfuscating its contents on the system or in transit. This is common behavior that can be used across different platforms and the network to evade defenses. Payloads may be compressed, archived, or encrypted in order to avoid detection. These payloads may be used during Initial Access or later to mitigate detection.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Creation","File Metadata","File Modification","Network Traffic Content","OS API Execution","Process Creation"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used heavily obfuscated code with Industroyer in its Windows Notepad backdoor.","During the 3CX Supply Chain Attack, AppleJeus payloads use AES-256 GCM cipher to encrypt data to include ICONICSTEALER and VEILEDSIGNAL.","Most of the strings in ADVSTORESHELL are encrypted with an XOR-based algorithm; some strings are also encrypted with 3DES and reversed. API function names are also reversed, presumably to avoid detection in memory.","ANELLDR code implements anti-analysis techniques including control flow flattening and Mixed Boolean Arithmetic (MBA)."],"examplesTotal":160,"mitigations":[{"name":"Audit","text":"Consider periodic review of common fileless storage locations (such as the Registry or WMI repository) to potentially identify abnormal and malicious data.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10+, enable Attack Surface Reduction (ASR) rules to prevent execution of potentially obfuscated payloads.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"User Training","text":"Ensure that a finite amount of ingress points to a software deployment system exist with restricted access for those required to allow and enable newly deployed software.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Antivirus/Antimalware","text":"Anti-virus can be used to automatically detect and quarantine suspicious files. Consider utilizing the Antimalware Scan Interface (AMSI) on Windows 10+ to analyze commands after…","url":"https://attack.mitre.org/mitigations/M1049"}]},{"id":"T1027.002","name":"Software Packing","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1027/002","summary":"Adversaries may perform software packing or virtual machine software protection to conceal their code.","description":"Adversaries may perform software packing or virtual machine software protection to conceal their code. Software packing is a method of compressing or encrypting an executable. Packing an executable changes the file signature in an attempt to avoid signature-based detection. Most decompression techniques decompress the executable code in memory. Virtual machine software protection translates an executable's original code into a special format that only a special virtual machine can run.","platforms":["Linux","macOS","Windows"],"detection":["Process Access","Process Creation","Process Modification"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used UPX to pack a copy of Mimikatz.","APT29 used UPX to pack files.","APT3 has been known to pack their tools.","APT38 has used several code packing methods such as Themida, Enigma, VMProtect, and Obsidium, to pack their implants."],"examplesTotal":103,"mitigations":[{"name":"Antivirus/Antimalware","text":"Employ heuristic-based malware detection. Ensure updated virus definitions and create custom signatures for observed malware.","url":"https://attack.mitre.org/mitigations/M1049"}]},{"id":"T1029","name":"Scheduled Transfer","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1029","summary":"Adversaries may schedule data exfiltration to be performed only at certain times of day or at certain intervals.","description":"Adversaries may schedule data exfiltration to be performed only at certain times of day or at certain intervals. This could be done to blend traffic patterns with normal activity or availability. When scheduled exfiltration is used, other exfiltration techniques likely apply as well to transfer the information out of the network, such as Exfiltration Over C2 Channel or Exfiltration Over Alternative Protocol.","platforms":["Linux","macOS","Windows"],"detection":["Network Connection Creation","Network Traffic Flow","Process Creation","Scheduled Job Metadata"],"examples":["ADVSTORESHELL collects, compresses, encrypts, and exfiltrates data to the C2 server every 10 minutes.","Chrommme can set itself to sleep before requesting a new command from C2.","Cobalt Strike can set its Beacon payload to reach out to the C2 server on an arbitrary and random interval.","ComRAT has been programmed to sleep outside local business hours (9 to 5, Monday to Friday)."],"examplesTotal":18,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1030","name":"Data Transfer Size Limits","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1030","summary":"An adversary may exfiltrate data in fixed size chunks instead of whole files or limit packet sizes below certain thresholds.","description":"An adversary may exfiltrate data in fixed size chunks instead of whole files or limit packet sizes below certain thresholds. This approach may be used to avoid triggering network data transfer threshold alerts.","platforms":["Linux","macOS","Windows","ESXi"],"detection":["Network Connection Creation","Network Traffic Flow"],"examples":["APT28 has split archived exfiltration files into chunks smaller than 1MB.","APT41 transfers post-exploitation files dividing the payload into fixed-size chunks to evade detection.","AppleSeed has divided files if the size is 0x1000000 bytes or more.","During C0015, the threat actors limited Rclone's bandwidth setting during exfiltration."],"examplesTotal":21,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1033","name":"System Owner/User Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1033","summary":"Adversaries may attempt to identify the primary user, currently logged in user, set of users that commonly uses a system, or whether a user is actively using the system.","description":"Adversaries may attempt to identify the primary user, currently logged in user, set of users that commonly uses a system, or whether a user is actively using the system. They may do this, for example, by retrieving account usernames or by using OS Credential Dumping.","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","OS API Execution","Process Creation"],"examples":["APT19 used an HTTP malware variant and a Port 22 malware variant to collect the victim’s username.","An APT3 downloader uses the Windows command \"cmd.exe\" /C whoami to verify that it is running with the elevated privileges of “System.”","APT32 collected the victim's username and executed the whoami command on the victim's machine. APT32 executed shellcode to collect the username on the victim's machine.","APT37 identifies the victim username."],"examplesTotal":241},{"id":"T1036","name":"Masquerading","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1036","summary":"Adversaries may attempt to manipulate features of their artifacts to make them appear legitimate or benign to users and/or security tools.","description":"Adversaries may attempt to manipulate features of their artifacts to make them appear legitimate or benign to users and/or security tools. Masquerading occurs when the name or location of an object, legitimate or malicious, is manipulated or abused for the sake of evading defenses and observation. This may include manipulating file metadata, tricking users into misidentifying the file type, and giving legitimate task or service names.","platforms":["Containers","ESXi","Linux","macOS","Windows"],"detection":["Command Execution","File Metadata","File Modification","Image Metadata","Process Creation","Process Metadata","Service Creation","Service Metadata"],"examples":["APT28 has renamed the WinRAR utility to avoid detection.","APT32 has disguised a Cobalt Strike beacon as a Flash Installer.","Agrius used the Plink tool for tunneling and connections to remote machines, renaming it systems.exe in some instances.","Aoqin Dragon has used fake icons including antivirus and external drives to disguise malicious payloads."],"examplesTotal":60,"mitigations":[{"name":"Audit","text":"Audit user accounts to ensure that each one has a defined purpose.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"User Account Management","text":"Consider defining and enforcing a naming convention for user accounts to more easily spot generic account names that do not fit the typical schema.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"User Training","text":"Train users not to open email attachments or click unknown links (URLs). Such training fosters more secure habits within your organization and will limit many of the risks.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Code Signing","text":"Require signed binaries.","url":"https://attack.mitre.org/mitigations/M1045"},{"name":"Behavior Prevention on Endpoint","text":"Implement security controls on the endpoint, such as a Host Intrusion Prevention System (HIPS), to identify and prevent execution of potentially malicious files (such as those…","url":"https://attack.mitre.org/mitigations/M1040"}]},{"id":"T1037","name":"Boot or Logon Initialization Scripts","tactics":["Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1037","summary":"Adversaries may use scripts automatically executed at boot or logon initialization to establish persistence.","description":"Adversaries may use scripts automatically executed at boot or logon initialization to establish persistence. Initialization scripts can be used to perform administrative functions, which may often execute other programs or send information to an internal logging server. These scripts can vary based on operating system and whether applied locally or remotely. Adversaries may use these scripts to maintain persistence on a single system.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["File Access","File Metadata","File Modification","Process Creation","Scheduled Job Creation","Script Execution","Service Metadata","Windows Registry Key Modification"],"examples":["APT29 has hijacked legitimate application-specific startup scripts to enable malware to execute on system startup.","APT41 used a hidden shell script in /etc/rc.d/init.d to leverage the ADORE.XSECbackdoor and Adore-NG rootkit.","ArcaneDoor used malicious boot scripts to install the Line Runner backdoor on victim devices.","Rocke has installed an \"init.d\" startup script to maintain persistence."],"examplesTotal":8,"mitigations":[{"name":"Restrict Registry Permissions","text":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for logon scripts that may lead to persistence.","url":"https://attack.mitre.org/mitigations/M1024"},{"name":"Restrict File and Directory Permissions","text":"Restrict write access to logon scripts to specific administrators.","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1039","name":"Data from Network Shared Drive","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1039","summary":"Adversaries may search network shares on computers they have compromised to find files of interest.","description":"Adversaries may search network shares on computers they have compromised to find files of interest. Sensitive data can be collected from remote systems via shared network drives (host shared directory, network file server, etc.) that are accessible from the current system prior to Exfiltration. Interactive command shells may be in use, and common functionality within cmd may be used to gather information.","platforms":["Linux","macOS","Windows"],"detection":["Drive Access","File Access","File Creation","Network Share Access"],"examples":["APT28 has collected files from network shared drives.","When it first starts, BADNEWS crawls the victim's mapped drives and collects documents with the following extensions: .doc, .docx, .pdf, .ppt, .pptx, and .txt.","BRONZE BUTLER has exfiltrated files stolen from file shares.","During C0015, the threat actors collected files from network shared drives prior to network encryption."],"examplesTotal":13},{"id":"T1040","name":"Network Sniffing","tactics":["Credential Access","Discovery"],"url":"https://attack.mitre.org/techniques/T1040","summary":"Adversaries may passively sniff network traffic to capture information about an environment, including authentication material passed over the network.","description":"Adversaries may passively sniff network traffic to capture information about an environment, including authentication material passed over the network. Network sniffing refers to using the network interface on a system to monitor or capture information sent over a wired or wireless connection. An adversary may place a network interface into promiscuous mode to passively access data in transit over the network, or use span ports to capture a larger amount of data.","platforms":["IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Cloud Service Modification","Command Execution","Network Traffic Content","Process Creation","Service Creation","User Account Authentication"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team used BlackEnergy’s network sniffer module to discover user credentials being sent over the network between the local LAN and the power grid’s industrial control systems.","APT28 deployed the open source tool Responder to conduct NetBIOS Name Service poisoning, which captured usernames and hashed passwords that allowed access to legitimate credentials.","APT33 has used SniffPass to collect credentials by sniffing network traffic.","ArcaneDoor included network packet capture and sniffing for data collection in victim environments."],"examplesTotal":28,"mitigations":[{"name":"User Account Management","text":"In cloud environments, ensure that users are not granted permissions to create or modify traffic mirrors unless this is explicitly required.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Multi-factor Authentication","text":"Use multi-factor authentication wherever possible.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Encrypt Sensitive Information","text":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may…","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Network Segmentation","text":"Deny direct access of broadcasts and multicast sniffing, and prevent attacks such as Name Resolution Poisoning and SMB Relay","url":"https://attack.mitre.org/mitigations/M1030"}]},{"id":"T1041","name":"Exfiltration Over C2 Channel","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1041","summary":"Adversaries may steal data by exfiltrating it over an existing command and control channel.","description":"Adversaries may steal data by exfiltrating it over an existing command and control channel. Stolen data is encoded into the normal communications channel using the same protocol as command and control communications.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["File Access","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["ADVSTORESHELL exfiltrates data over the same channel used for C2.","APT3 has a tool that exfiltrates data over the C2 channel.","APT32's backdoor has exfiltrated data using the already opened channel with its C&C server.","APT39 has exfiltrated stolen victim data through C2 communications."],"examplesTotal":201,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Data Loss Prevention","text":"Data loss prevention can detect and block sensitive data being sent over unencrypted protocols.","url":"https://attack.mitre.org/mitigations/M1057"}]},{"id":"T1046","name":"Network Service Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1046","summary":"Adversaries may attempt to get a listing of services running on remote hosts and local network infrastructure devices, including those that may be vulnerable to remote software exploitation.","description":"Adversaries may attempt to get a listing of services running on remote hosts and local network infrastructure devices, including those that may be vulnerable to remote software exploitation. Common methods to acquire this information include port, vulnerability, and/or wordlist scans using tools that are brought onto a system. Within cloud environments, adversaries may attempt to discover services running on other cloud hosts.","platforms":["Containers","IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries utilized Ping, the Advanced Port Scanner and Advanced IP Scanner to enumerate network devices.","APT32 performed network scanning on the network to search for open ports, services, OS finger-printing, and other vulnerabilities.","APT39 has used CrackMapExec and a custom port scanner known as BLUETORCH for network scanning.","APT41 used a malware variant called WIDETONE to conduct port scans on specified subnets."],"examplesTotal":73,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Ensure that unnecessary ports and services are closed to prevent risk of discovery and potential exploitation.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Network Intrusion Prevention","text":"Use network intrusion detection/prevention systems to detect and prevent remote service scans.","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Network Segmentation","text":"Ensure proper network segmentation is followed to protect critical servers and devices.","url":"https://attack.mitre.org/mitigations/M1030"}]},{"id":"T1047","name":"Windows Management Instrumentation","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1047","summary":"Adversaries may abuse Windows Management Instrumentation (WMI) to execute malicious commands and payloads.","description":"Adversaries may abuse Windows Management Instrumentation (WMI) to execute malicious commands and payloads. WMI is designed for programmers and is the infrastructure for management data and operations on Windows systems. WMI is an administration feature that provides a uniform environment to access Windows system components.","platforms":["Windows"],"detection":["Network Connection Creation","Process Creation","WMI Creation"],"examples":["During the 2016 Ukraine Electric Power Attack, WMI in scripts were used for remote execution and system surveys.","APT-C-36 has used WMI to execute PowerShell.","APT29 used WMI to steal credentials and execute backdoors at a future time.","APT32 used WMI to deploy their tools on remote machines and to gather information about the Outlook process."],"examplesTotal":147,"mitigations":[{"name":"Privileged Account Management","text":"Prevent credential overlap across systems of administrator and privileged accounts.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block processes created by WMI commands from running.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"User Account Management","text":"By default, only administrators are allowed to connect remotely using WMI. Restrict other users who are allowed to connect, or disallow all users to connect remotely to WMI.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Execution Prevention","text":"Use application control configured to block execution of wmic.exe if it is not required for a given system or network to prevent potential misuse by adversaries.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1048","name":"Exfiltration Over Alternative Protocol","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1048","summary":"Adversaries may steal data by exfiltrating it over a different protocol than that of the existing command and control channel.","description":"Adversaries may steal data by exfiltrating it over a different protocol than that of the existing command and control channel. The data may also be sent to an alternate network location from the main command and control server. Alternate protocols include FTP, SMTP, HTTP/S, DNS, SMB, or any other network protocol not being used as the main command and control channel. Adversaries may also opt to encrypt and/or obfuscate these alternate channels.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"detection":["Cloud Storage Access","Command Execution","File Access","File Creation","File Modification","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["AADInternals can directly download cloud user data such as OneDrive files.","Bundlore uses the curl -s -L -o command to exfiltrate archived data to a URL.","Chaes has exfiltrated its collected data from the infected machine to the C2, sometimes using the MIME protocol.","FrameworkPOS can use DNS tunneling for exfiltration of credit card data."],"examplesTotal":9,"mitigations":[{"name":"Network Segmentation","text":"Follow best practices for network firewall configurations to allow only necessary ports and traffic to enter and exit the network.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Data Loss Prevention","text":"Data loss prevention can detect and block sensitive data being uploaded via web browsers.","url":"https://attack.mitre.org/mitigations/M1057"},{"name":"Filter Network Traffic","text":"Enforce proxies and use dedicated servers for services such as DNS and only allow those systems to communicate over respective ports/protocols, instead of all systems within a…","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary command and control infrastructure and malware can be…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Restrict File and Directory Permissions","text":"Use access control lists on cloud storage systems and objects.","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1049","name":"System Network Connections Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1049","summary":"Adversaries may attempt to get a listing of network connections to or from the compromised system they are currently accessing or from remote systems by querying for information over the network.","description":"Adversaries may attempt to get a listing of network connections to or from the compromised system they are currently accessing or from remote systems by querying for information over the network. An adversary who gains access to a system that is part of a cloud-based environment may map out Virtual Private Clouds or Virtual Networks in order to determine what systems and services are connected.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Network Traffic Content","OS API Execution","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries identified network connections utilizing netstat -nao and netstat -r.","APT1 used the net use command to get a listing on network connections.","APT3 has a tool that can enumerate current network connections.","APT32 used the netstat -anpo tcp command to display TCP connections on the victim's machine."],"examplesTotal":97},{"id":"T1052","name":"Exfiltration Over Physical Medium","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1052","summary":"Adversaries may attempt to exfiltrate data via a physical medium, such as a removable drive.","description":"Adversaries may attempt to exfiltrate data via a physical medium, such as a removable drive. In certain circumstances, such as an air-gapped network compromise, exfiltration could occur via a physical medium or device introduced by a user. Such media could be an external hard drive, USB drive, cellular phone, MP3 player, or other removable storage and processing device. The physical medium or device could be used as the final exfiltration point or to hop between otherwise disconnected systems.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","Drive Creation","File Access","File Creation","Process Creation"],"mitigations":[{"name":"Data Loss Prevention","text":"Data loss prevention can detect and block sensitive data being copied to physical mediums.","url":"https://attack.mitre.org/mitigations/M1057"},{"name":"Limit Hardware Installation","text":"Limit the use of USB devices and removable media within a network.","url":"https://attack.mitre.org/mitigations/M1034"},{"name":"Disable or Remove Feature or Program","text":"Disable Autorun if it is unnecessary. Disallow or restrict removable media at an organizational policy level if they are not required for business operations.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1053","name":"Scheduled Task/Job","tactics":["Execution","Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1053","summary":"Adversaries may abuse task scheduling functionality to facilitate initial or recurring execution of malicious code.","description":"Adversaries may abuse task scheduling functionality to facilitate initial or recurring execution of malicious code. Utilities exist within all major operating systems to schedule programs or scripts to be executed at a specified date and time. A task can also be scheduled on a remote system, provided the proper authentication is met (ex: RPC and file and printer sharing in Windows environments).","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Creation","File Modification","Process Creation","Scheduled Job Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries set FortiGate scheduled tasks to run the adversary generated CLI scripts weekly.","Lokibot's second stage DLL has set a timer using “timeSetEvent” to schedule its next execution."],"examplesTotal":2,"mitigations":[{"name":"User Account Management","text":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Operating System Configuration","text":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"Restrict File and Directory Permissions","text":"Restrict access by setting directory and file permissions that are not specific to users or privileged accounts.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"Privileged Account Management","text":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Audit","text":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate…","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1053.005","name":"Scheduled Task","tactics":["Execution","Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1053/005","summary":"Adversaries may abuse the Windows Task Scheduler to perform task scheduling for initial or recurring execution of malicious code.","description":"Adversaries may abuse the Windows Task Scheduler to perform task scheduling for initial or recurring execution of malicious code. There are multiple ways to access the Task Scheduler in Windows. The schtasks utility can be run directly on the command line, or the Task Scheduler can be opened through the GUI within the Administrator Tools section of the Control Panel.","platforms":["Windows"],"detection":["File Creation","Process Creation","Scheduled Job Creation","Scheduled Job Modification","Windows Registry Key Modification"],"examples":["During the 2022 Ukraine Electric Power Attack, Sandworm Team leveraged Scheduled Tasks through a Group Policy Object (GPO) to execute CaddyWiper at a predetermined time.","APT-C-36 has used a macro function to set scheduled tasks, disguised as those used by Google.","APT29 has used named and hijacked scheduled tasks to establish persistence.","An APT3 downloader creates persistence by creating the following scheduled task: schtasks /create /tn \"mysc\" /tr C:\\Users\\Public\\test.exe /sc ONLOGON /ru \"System\"."],"examplesTotal":190,"mitigations":[{"name":"Privileged Account Management","text":"Configure the Increase Scheduling Priority option to only allow the Administrators group the rights to schedule a priority process.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"User Account Management","text":"Limit privileges of user accounts and remediate Privilege Escalation vectors so only authorized administrators can create scheduled tasks on remote systems.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Audit","text":"Toolkits like the PowerSploit framework contain PowerUp modules that can be used to explore systems for permission weaknesses in scheduled tasks that could be used to escalate…","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Operating System Configuration","text":"Configure settings for scheduled tasks to force tasks to run under the context of the authenticated account instead of allowing them to run as SYSTEM.","url":"https://attack.mitre.org/mitigations/M1028"}]},{"id":"T1055","name":"Process Injection","tactics":["Stealth","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1055","summary":"Adversaries may inject code into processes in order to evade process-based defenses as well as possibly elevate privileges.","description":"Adversaries may inject code into processes in order to evade process-based defenses as well as possibly elevate privileges. Process injection is a method of executing arbitrary code in the address space of a separate live process. Running code in the context of another process may allow access to the process's memory, system/network resources, and possibly elevated privileges.","platforms":["Linux","macOS","Windows"],"detection":["File Access","Module Load","OS API Execution","Process Access","Process Creation","Process Metadata","Process Modification"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team loaded BlackEnergy into svchost.exe, which then launched iexplore.exe for their C2.","During the 3CX Supply Chain Attack, AppleJeus's VEILEDSIGNAL uses process injection to inject the C2 communication module code in the first found process instance of Chrome, Firefox, or Edge web browsers.","ABK has the ability to inject shellcode into svchost.exe.","ANDROMEDA can inject into the wuauclt.exe process to perform C2 actions."],"examplesTotal":87,"mitigations":[{"name":"Privileged Account Management","text":"Utilize Yama (ex: /proc/sys/kernel/yama/ptrace_scope) to mitigate ptrace based process injection by restricting the use of ptrace to privileged users only.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Behavior Prevention on Endpoint","text":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process.","url":"https://attack.mitre.org/mitigations/M1040"}]},{"id":"T1055.012","name":"Process Hollowing","tactics":["Stealth","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1055/012","summary":"Adversaries may inject malicious code into suspended and hollowed processes in order to evade process-based defenses.","description":"Adversaries may inject malicious code into suspended and hollowed processes in order to evade process-based defenses. Process hollowing is a method of executing arbitrary code in the address space of a separate live process. Process hollowing is commonly performed by creating a process in a suspended state then unmapping/hollowing its memory, which can then be replaced with malicious code.","platforms":["Windows"],"detection":["OS API Execution","Process Access","Process Creation","Process Modification"],"examples":["APT-C-36 has used process hollowing to execute malware in the memory of legitimate processes.","Agent Tesla has used process hollowing to create and manipulate processes through sections of unmapped memory by reallocating that space with its malicious code.","Astaroth can create a new process in a suspended state from a targeted legitimate process in order to unmap its memory and replace it with malicious code.","Azorult can decrypt the payload into memory, create a new suspended process of itself, then inject a decrypted payload to the new process and resume new process execution."],"examplesTotal":43,"mitigations":[{"name":"Behavior Prevention on Endpoint","text":"Some endpoint security solutions can be configured to block some types of process injection based on common sequences of behavior that occur during the injection process.","url":"https://attack.mitre.org/mitigations/M1040"}]},{"id":"T1056","name":"Input Capture","tactics":["Collection","Credential Access"],"url":"https://attack.mitre.org/techniques/T1056","summary":"Adversaries may use methods of capturing user input to obtain credentials or collect information.","description":"Adversaries may use methods of capturing user input to obtain credentials or collect information. During normal system usage, users often provide credentials to various different locations, such as login pages/portals or system dialog boxes. Input capture mechanisms may be transparent to the user (e.g. Credential API Hooking) or rely on deceiving the user into providing input into what they believe to be a genuine service (e.g. Web Portal Capture).","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["File Access","File Modification","Network Connection Creation","Network Traffic Content","OS API Execution","Process Access","Process Creation","Process Metadata"],"examples":["APT39 has utilized tools to capture mouse movements.","APT42 has used credential harvesting websites.","Chaes has a module to perform any API hooking it desires.","FlawedAmmyy can collect mouse events."],"examplesTotal":12},{"id":"T1057","name":"Process Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1057","summary":"Adversaries may attempt to get information about running processes on a system.","description":"Adversaries may attempt to get information about running processes on a system. Information obtained could be used to gain an understanding of common software/applications running on systems within the network. Administrator or otherwise elevated access may provide better process details.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Access","Process Access","Process Creation","Process Metadata"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries enumerated current running processes using tasklist.","4H RAT has the capability to obtain a listing of running processes (including loaded modules).","ADVSTORESHELL can list running processes.","APT1 gathered a list of running processes on the system using tasklist /v."],"examplesTotal":318},{"id":"T1059","name":"Command and Scripting Interpreter","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1059","summary":"Adversaries may abuse command and script interpreters to execute commands, scripts, or binaries.","description":"Adversaries may abuse command and script interpreters to execute commands, scripts, or binaries. These interfaces and languages provide ways of interacting with computer systems and are a common feature across many different platforms. Most systems come with some built-in command-line interface and scripting capabilities, for example, macOS and Linux distributions include some flavor of Unix Shell while Windows installations include the Windows Command Shell and PowerShell.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"detection":["Command Execution","Process Creation","User Account Authentication"],"examples":["APT19 downloaded and launched code within a SCT file.","APT32 has used COM scriptlets to download Cobalt Strike beacons.","APT37 has used Ruby scripts to execute payloads.","APT39 has utilized custom scripts to perform internal reconnaissance."],"examplesTotal":44,"mitigations":[{"name":"Limit Software Installation","text":"Prevent user installation of unrequired command and scripting interpreters.","url":"https://attack.mitre.org/mitigations/M1033"},{"name":"Code Signing","text":"Where possible, only permit execution of signed scripts.","url":"https://attack.mitre.org/mitigations/M1045"},{"name":"Disable or Remove Feature or Program","text":"Disable or remove any unnecessary or unused shells or interpreters.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Execution Prevention","text":"Use application control where appropriate. For example, PowerShell Constrained Language mode can be used to restrict access to sensitive or otherwise dangerous language elements…","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Antivirus/Antimalware","text":"Anti-virus can be used to automatically quarantine suspicious files.","url":"https://attack.mitre.org/mitigations/M1049"}]},{"id":"T1068","name":"Exploitation for Privilege Escalation","tactics":["Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1068","summary":"Adversaries may exploit software vulnerabilities in an attempt to elevate privileges.","description":"Adversaries may exploit software vulnerabilities in an attempt to elevate privileges. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code.","platforms":["Containers","Linux","macOS","Windows"],"detection":["Container Enumeration","Driver Load","Logon Session Creation","Logon Session Metadata","Module Load","Process Access","Process Creation"],"examples":["APT28 has exploited CVE-2014-4076, CVE-2015-2387, CVE-2015-1701, CVE-2017-0263, and CVE-2022-38028 to escalate privileges.","APT29 has exploited CVE-2021-36934 to escalate privileges on a compromised host.","APT32 has used CVE-2016-7255 to escalate privileges.","APT33 has used a publicly available exploit for CVE-2017-0213 to escalate privileges on a local system."],"examplesTotal":43,"mitigations":[{"name":"Update Software","text":"Update software regularly by employing patch management for internal enterprise endpoints and servers.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Exploit Protection","text":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Application Isolation and Sandboxing","text":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing.","url":"https://attack.mitre.org/mitigations/M1048"},{"name":"Threat Intelligence Program","text":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization.","url":"https://attack.mitre.org/mitigations/M1019"},{"name":"Execution Prevention","text":"Consider blocking the execution of known vulnerable drivers that adversaries may exploit to execute code in kernel mode.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1069","name":"Permission Groups Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1069","summary":"Adversaries may attempt to discover group and permission settings.","description":"Adversaries may attempt to discover group and permission settings. This information can help adversaries determine which user accounts and groups are available, the membership of users in particular groups, and which users and groups have elevated permissions. Adversaries may attempt to discover group permission settings in many different ways. This data may provide the adversary with information about the compromised environment that can be used in follow-on activity and targeting.","platforms":["Containers","IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Command Execution","Process Creation"],"examples":["APT3 has a tool that can enumerate the permissions associated with Windows groups.","APT41 used net group commands to enumerate various Windows user groups and permissions.","Carbon uses the net group command.","FIN13 has enumerated all users and roles from a victim's main treasury system."],"examplesTotal":13},{"id":"T1070","name":"Indicator Removal","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1070","summary":"Adversaries may selectively delete or modify artifacts generated to reduce indications of their presence and blend in with legitimate activity.","description":"Adversaries may selectively delete or modify artifacts generated to reduce indications of their presence and blend in with legitimate activity. Rather than broadly removing evidence, adversaries may target specific artifacts that appear anomalous or are likely to draw scrutiny, while leaving sufficient data intact to maintain the appearance of normal system behavior.","platforms":["Containers","ESXi","Linux","macOS","Network Devices","Office Suite","Windows"],"detection":["Application Log Content","File Deletion","File Metadata","File Modification","Scheduled Job Modification","Windows Registry Key Modification"],"examples":["APT42 has cleared Chrome browser history.","APT5 has used the THINBLOOD utility to clear SSL VPN log files located at /home/runtime/logs.","BPFDoor clears the file location /proc/<PID>/environ removing all environment variables for the process.","Bankshot deletes all artifacts associated with the malware from the infected machine."],"examplesTotal":33,"mitigations":[{"name":"Encrypt Sensitive Information","text":"Obfuscate/encrypt event files locally and in transit to avoid giving feedback to an adversary.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Remote Data Storage","text":"Automatically forward events to a log server or data repository to prevent conditions in which the adversary can locate and manipulate data on the local system.","url":"https://attack.mitre.org/mitigations/M1029"},{"name":"Restrict File and Directory Permissions","text":"Protect generated event files that are stored locally with proper permissions and authentication and limit opportunities for adversaries to increase privileges by preventing…","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1070.006","name":"Timestomp","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1070/006","summary":"Adversaries may modify file time attributes to hide new files or changes to existing files.","description":"Adversaries may modify file time attributes to hide new files or changes to existing files. Timestomping is a technique that modifies the timestamps of a file (the modify, access, create, and change times), often to mimic files that are in the same folder and blend malicious files with legitimate files. In Windows systems, both the $STANDARD_INFORMATION ($SI) and $FILE_NAME ($FN) attributes record times in a Master File Table (MFT) file.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Command Execution","File Access","File Metadata","File Modification","OS API Execution","Process Creation"],"examples":["3PARA RAT has a command to set certain attributes such as creation/modification timestamps on files.","APT28 has performed timestomping on victim files.","APT29 has used timestomping to alter the Standard Information timestamps on their web shells to match other files in the same directory.","APT32 has used scheduled task raw XML with a backdated timestamp of June 2, 2016. The group has also set the creation time of the files dropped by the second stage of the exploit to match the creation time of kernel32.dll."],"examplesTotal":58},{"id":"T1071","name":"Application Layer Protocol","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1071","summary":"Adversaries may communicate using OSI application layer protocols to avoid detection/network filtering by blending in with existing traffic.","description":"Adversaries may communicate using OSI application layer protocols to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. Adversaries may utilize many different protocols, including those used for web browsing, transferring files, electronic mail, DNS, or publishing/subscribing.","platforms":["Linux","macOS","Windows","Network Devices","ESXi"],"detection":["Command Execution","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["Clambling has the ability to use Telnet for communication.","Duqu uses a custom command and control protocol that communicates over commonly used ports, and is frequently encapsulated by application layer protocols.","During FrostyGoop Incident, the adversary initiated Layer Two Tunnelling Protocol (L2TP) connections to Moscow-based IP addresses.","Hildegard has used an IRC channel for C2 communications."],"examplesTotal":16,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Filter Network Traffic","text":"Use network appliances to filter ingress or egress traffic and perform protocol-based filtering. Configure software on endpoints to filter network traffic.","url":"https://attack.mitre.org/mitigations/M1037"}]},{"id":"T1071.004","name":"DNS","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1071/004","summary":"Adversaries may communicate using the Domain Name System (DNS) application layer protocol to avoid detection/network filtering by blending in with existing traffic.","description":"Adversaries may communicate using the Domain Name System (DNS) application layer protocol to avoid detection/network filtering by blending in with existing traffic. Commands to the remote system, and often the results of those commands, will be embedded within the protocol traffic between the client and server. The DNS protocol serves an administrative function in computer networking and thus may be very common in environments.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["APT18 uses DNS for C2 communications.","APT39 has used remote access tools that leverage DNS in communications with C2.","APT41 used DNS for C2 communications.","Variants of Anchor can use DNS tunneling to communicate with C2."],"examplesTotal":55,"mitigations":[{"name":"Filter Network Traffic","text":"Consider filtering DNS requests to unknown, untrusted, or known bad domains and resources. Resolving DNS requests with on-premise/proxy servers may also disrupt adversary attempts…","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1072","name":"Software Deployment Tools","tactics":["Execution","Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1072","summary":"Adversaries may gain access to and use centralized software suites installed within an enterprise to execute commands and move laterally through the network.","description":"Adversaries may gain access to and use centralized software suites installed within an enterprise to execute commands and move laterally through the network. Configuration management and software deployment applications may be used in an enterprise network or cloud environment for routine administration purposes. These systems may also be integrated into CI/CD pipelines.","platforms":["Linux","macOS","Network Devices","SaaS","Windows"],"detection":["Application Log Content","Command Execution","Network Traffic Flow","Process Creation"],"examples":["APT32 compromised McAfee ePO to move laterally by distributing malware as a software deployment task.","During C0018, the threat actors used PDQ Deploy to move AvosLocker and tools across the network.","Medusa Group has utilized software deployment and management solutions to deploy their encryption payload to include BigFix and PDQ Deploy.","Mustang Panda has leveraged legitimate software tools such as AntiVirus Agents, Security Services, and App Development tools to execute scripts and to side-load dlls."],"examplesTotal":9,"mitigations":[{"name":"User Account Management","text":"Ensure that any accounts used by third-party providers to access these systems are traceable to the third-party and are not used throughout the network or used by other…","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Active Directory Configuration","text":"Ensure proper system and access isolation for critical network systems through use of group policy.","url":"https://attack.mitre.org/mitigations/M1015"},{"name":"Update Software","text":"Patch deployment systems regularly to prevent potential remote access through Exploitation for Privilege Escalation.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Privileged Account Management","text":"Grant access to application deployment systems only to a limited number of authorized administrators.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Password Policies","text":"Verify that account credentials that may be used to access deployment systems are unique and not used throughout the enterprise network.","url":"https://attack.mitre.org/mitigations/M1027"}]},{"id":"T1074","name":"Data Staged","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1074","summary":"Adversaries may stage collected data in a central location or directory prior to Exfiltration.","description":"Adversaries may stage collected data in a central location or directory prior to Exfiltration. Data may be kept in separate files or combined into one file through techniques such as Archive Collected Data. Interactive command shells may be used, and common functionality within cmd and bash may be used to copy data into a staging location. In cloud environments, adversaries may stage data within a particular instance or virtual machine before exfiltration.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"detection":["Cloud Storage Access","Command Execution","File Access","File Creation","Process Creation"],"examples":["INC Ransom has staged data on compromised hosts prior to exfiltration.","Kevin can create directories to store logs and other collected data.","Kobalos can write captured SSH connection credentials to a file under the /var/run directory with a .pid extension for exfiltration.","QUIETCANARY has the ability to stage data prior to exfiltration."],"examplesTotal":9},{"id":"T1078","name":"Valid Accounts","tactics":["Stealth","Persistence","Privilege Escalation","Initial Access"],"url":"https://attack.mitre.org/techniques/T1078","summary":"Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion.","description":"Adversaries may obtain and abuse credentials of existing accounts as a means of gaining Initial Access, Persistence, Privilege Escalation, or Defense Evasion. Compromised credentials may be used to bypass access controls placed on various resources on systems within the network and may even be used for persistent access to remote systems and externally available services, such as VPNs, Outlook Web Access, network devices, and remote desktop.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"detection":["Logon Session Creation","Logon Session Metadata","Process Creation","User Account Authentication"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team used valid accounts on the corporate network to escalate privileges, move laterally, and establish persistence within the corporate network.","During 3CX Supply Chain Attack, AppleJeus has gained access to the 3CX corporate environment through legitimate VPN credentials.","APT18 actors leverage legitimate credentials to log into external remote services.","APT28 has used legitimate credentials to gain initial access, maintain access, and exfiltrate data from a victim network. The group has specifically used credentials stolen through a spearphishing email to login to the DCCC network."],"examplesTotal":63,"mitigations":[{"name":"Password Policies","text":"Applications and appliances that utilize default username and password should be changed immediately after the installation, and before deployment to a production environment.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"User Account Management","text":"Regularly audit user accounts for activity and deactivate or remove any that are no longer needed.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Privileged Account Management","text":"Audit domain and local accounts as well as their permission levels routinely to look for situations that could allow an adversary to gain wide access by obtaining credentials of a…","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Multi-factor Authentication","text":"Implement multi-factor authentication (MFA) across all account types, including default, local, domain, and cloud accounts, to prevent unauthorized access, even if credentials are…","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Application Developer Guidance","text":"Ensure that applications do not store sensitive data or credentials insecurely. (e.g. plaintext credentials in code, published credentials in repositories, or credentials in…","url":"https://attack.mitre.org/mitigations/M1013"}]},{"id":"T1080","name":"Taint Shared Content","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1080","summary":"Adversaries may deliver payloads to remote systems by adding content to shared storage locations, such as network drives or internal code repositories.","description":"Adversaries may deliver payloads to remote systems by adding content to shared storage locations, such as network drives or internal code repositories. Content stored on network drives or in other shared locations may be tainted by adding malicious programs, scripts, or exploit code to otherwise valid files. Once a user opens the shared tainted content, the malicious portion can be executed to run the adversary's code on a remote system.","platforms":["Windows","SaaS","Linux","macOS","Office Suite"],"detection":["File Creation","File Modification","Network Share Access"],"examples":["BRONZE BUTLER has placed malware on file shares and given it the same name as legitimate documents on the share.","Cinnamon Tempest has deployed ransomware from a batch file in a network share.","Conti can spread itself by infecting other remote machines via network shared drives.","Darkhotel used a virus that propagates by infecting executables stored on shared drives."],"examplesTotal":12,"mitigations":[{"name":"Antivirus/Antimalware","text":"Anti-virus can be used to automatically quarantine suspicious files.","url":"https://attack.mitre.org/mitigations/M1049"},{"name":"Execution Prevention","text":"Identify potentially malicious software that may be used to taint content or may result from it and audit and/or block the unknown programs by using application control tools,…","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Restrict File and Directory Permissions","text":"Protect shared folders by minimizing users who have write access.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"Exploit Protection","text":"Use utilities that detect or mitigate common features used in exploitation, such as the Microsoft Enhanced Mitigation Experience Toolkit (EMET).","url":"https://attack.mitre.org/mitigations/M1050"}]},{"id":"T1082","name":"System Information Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1082","summary":"An adversary may attempt to get detailed information about the operating system and hardware, including version, patches, hotfixes, service packs, and architecture.","description":"An adversary may attempt to get detailed information about the operating system and hardware, including version, patches, hotfixes, service packs, and architecture. Adversaries may use this information to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions. This behavior is distinct from Local Storage Discovery which is an adversary's discovery of local drive, disks and/or volumes.","platforms":["ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Instance Enumeration","Process Creation","Windows Registry Key Modification"],"examples":["4H RAT sends an OS version identifier in its beacons.","ADVSTORESHELL can run Systeminfo to gather information about the victim.","APT18 can collect system information from the victim’s machine.","APT19 collected system architecture information. APT19 used an HTTP malware variant and a Port 22 malware variant to gather the hostname and CPU information from the victim’s machine."],"examplesTotal":424},{"id":"T1083","name":"File and Directory Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1083","summary":"Adversaries may enumerate files and directories or may search in specific locations of a host or network share for certain information within a file system.","description":"Adversaries may enumerate files and directories or may search in specific locations of a host or network share for certain information within a file system. Adversaries may use the information from File and Directory Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions. Many command shell utilities can be used to obtain this information.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Access","File Creation","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries obtained the contents of users’ directories using dir /s /b C:\\Users command.","3PARA RAT has a command to retrieve metadata for files on disk as well as a command to list the current working directory.","4H RAT has the capability to obtain file and directory listings.","ADVSTORESHELL can list files and directories."],"examplesTotal":369},{"id":"T1087","name":"Account Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1087","summary":"Adversaries may attempt to get a listing of valid accounts, usernames, or email addresses on a system or within a compromised environment.","description":"Adversaries may attempt to get a listing of valid accounts, usernames, or email addresses on a system or within a compromised environment. This information can help adversaries determine which accounts exist, which can aid in follow-on behavior such as brute-forcing, spear-phishing attacks, or account takeovers (e.g., Valid Accounts).","platforms":["ESXi","IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Cloud Service Enumeration","Command Execution","File Access","Group Enumeration","Process Creation","Script Execution","User Account Metadata"],"examples":["During the Anthropic AI-orchestrated Campaign, the adversary used Claude Code to query internal database user account tables to enumerate accounts and identify high-privilege accounts within compromised environments.","Aquatic Panda used the last command in Linux environments to identify recently logged-in users on victim machines.","FIN13 has enumerated all users and their roles from a victim's main treasury system.","Havoc can identify privileged user accounts on infected systems."],"examplesTotal":10,"mitigations":[{"name":"Operating System Configuration","text":"Prevent administrator accounts from being enumerated when an application is elevating through UAC since it can lead to the disclosure of account names.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"User Account Management","text":"Manage the creation, modification, use, and permissions associated to user accounts.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1090","name":"Proxy","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1090","summary":"Adversaries may use a connection proxy to direct network traffic between systems or act as an intermediary for network communications to a command and control server to avoid direct connections to their infrastructure.","description":"Adversaries may use a connection proxy to direct network traffic between systems or act as an intermediary for network communications to a command and control server to avoid direct connections to their infrastructure. Many tools exist that enable traffic redirection through proxies or port redirection, including HTRAN, ZXProxy, and ZXPortMap.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Firewall Rule Modification","Network Connection Creation","Network Traffic Flow","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries utilized the rsocx tool identified as r.exe and rsocx.exe to tunnel within the internal infrastructure using a Reverse SOCKS Proxy.","APT41 used a tool called CLASSFON to covertly proxy network communications.","Aria-body has the ability to use a reverse SOCKS proxy module.","AuditCred can utilize proxy for communications."],"examplesTotal":75,"mitigations":[{"name":"Filter Network Traffic","text":"Traffic to known anonymity networks and C2 infrastructure can be blocked through the use of network allow and block lists.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"SSL/TLS Inspection","text":"If it is possible to inspect HTTPS traffic, the captures can be analyzed for connections that appear to be domain fronting.","url":"https://attack.mitre.org/mitigations/M1020"}]},{"id":"T1091","name":"Replication Through Removable Media","tactics":["Lateral Movement","Initial Access"],"url":"https://attack.mitre.org/techniques/T1091","summary":"Adversaries may move onto systems, possibly those on disconnected or air-gapped networks, by copying malware to removable media and taking advantage of Autorun features when the media is inserted into a system and executes.","description":"Adversaries may move onto systems, possibly those on disconnected or air-gapped networks, by copying malware to removable media and taking advantage of Autorun features when the media is inserted into a system and executes. In the case of Lateral Movement, this may occur through modification of executable files stored on removable media or by copying malware and renaming it to look like a legitimate file to trick users into executing it on a separate system.","platforms":["Windows"],"detection":["Drive Creation","File Access","File Creation","Process Creation"],"examples":["ANDROMEDA has been spread via infected USB keys.","APT28 uses a tool to infect connected USB devices and transmit itself to air-gapped computers when the infected USB device is inserted.","Agent.btz drops itself onto removable media devices and creates an autorun.inf file with an instruction to run that file. When the device is inserted into another system, it opens autorun.inf and loads the malware.","Aoqin Dragon has used a dropper that employs a worm infection strategy using a removable device to breach a secure network environment."],"examplesTotal":28,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Disable Autorun if it is unnecessary. Disallow or restrict removable media at an organizational policy level if it is not required for business operations.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Limit Hardware Installation","text":"Limit the use of USB devices and removable media within a network.","url":"https://attack.mitre.org/mitigations/M1034"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block unsigned/untrusted executable files (such as .exe, .dll, or .scr) from running from USB removable drives.","url":"https://attack.mitre.org/mitigations/M1040"}]},{"id":"T1092","name":"Communication Through Removable Media","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1092","summary":"Adversaries can perform command and control between compromised hosts on potentially disconnected networks using removable media to transfer commands from system to system.","description":"Adversaries can perform command and control between compromised hosts on potentially disconnected networks using removable media to transfer commands from system to system. Both systems would need to be compromised, with the likelihood that an Internet-connected system was compromised first and the second through lateral movement by Replication Through Removable Media.","platforms":["Linux","macOS","Windows"],"detection":["Drive Creation","File Creation","Process Creation"],"examples":["APT28 uses a tool that captures information from air-gapped computers via an infected USB and transfers it to network-connected computer when the USB is inserted.","Part of APT28's operation involved using CHOPSTICK modules to copy itself to air-gapped machines, using files written to USB sticks to transfer data and command traffic.","USBStealer drops commands for a second victim onto a removable media drive inserted into the first victim, and commands are executed when the drive is inserted into the second victim."],"examplesTotal":3,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Disable Autoruns if it is unnecessary.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Operating System Configuration","text":"Disallow or restrict removable media at an organizational policy level if they are not required for business operations.","url":"https://attack.mitre.org/mitigations/M1028"}]},{"id":"T1095","name":"Non-Application Layer Protocol","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1095","summary":"Adversaries may use an OSI non-application layer protocol for communication between host and C2 server or among infected hosts within a network.","description":"Adversaries may use an OSI non-application layer protocol for communication between host and C2 server or among infected hosts within a network. The list of possible protocols is extensive. Specific examples include use of network layer protocols, such as the Internet Control Message Protocol (ICMP), transport layer protocols, such as the User Datagram Protocol (UDP), session layer protocols, such as Socket Secure (SOCKS), as well as redirected/tunneled protocols, such as Serial over LAN (SOL).","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Network Traffic Flow"],"examples":["During the 2022 Ukraine Electric Power Attack, Sandworm Team proxied C2 communications within a TLS-based tunnel.","An APT3 downloader establishes SOCKS5 connections for its initial C2.","Anchor has used ICMP in C2 communications.","Aria-body has used TCP in C2 communications."],"examplesTotal":108,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Audit","text":"Periodically investigate ESXi hosts for open VMCI ports. Running the lsof -A command and inspecting results with a type of SOCKET_VMCI will reveal processes that have open VMCI…","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Filter Network Traffic","text":"Filter network traffic to prevent use of protocols across the network boundary that are unnecessary.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Segmentation","text":"Properly configure firewalls and proxies to limit outgoing traffic to only necessary ports and through proper network gateway systems.","url":"https://attack.mitre.org/mitigations/M1030"}]},{"id":"T1098","name":"Account Manipulation","tactics":["Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1098","summary":"Adversaries may manipulate accounts to maintain and/or elevate access to victim systems.","description":"Adversaries may manipulate accounts to maintain and/or elevate access to victim systems. Account manipulation may consist of any action that preserves or modifies adversary access to a compromised account, such as modifying credentials or permission groups. These actions could also include account activity designed to subvert security policies, such as performing iterative password updates to bypass password duration policies and preserve the life of compromised credentials.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"detection":["Active Directory Object Modification","File Modification","Process Creation","User Account Modification"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used the sp_addlinkedsrvlogin command in MS-SQL to create a link between a created account and other servers in the network.","Calisto adds permissions and remote logins to all users.","HAFNIUM has granted privileges to domain accounts and reset the password for default admin accounts.","Lazarus Group malware WhiskeyDelta-Two contains a function that attempts to rename the administrator’s account."],"examplesTotal":8,"mitigations":[{"name":"Network Segmentation","text":"Configure access controls and firewalls to limit access to critical systems and domain controllers.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Disable or Remove Feature or Program","text":"Remove unnecessary and potentially abusable authentication and authorization mechanisms where possible.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"User Account Management","text":"Ensure that low-privileged user accounts do not have permissions to modify accounts or account-related policies.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Restrict File and Directory Permissions","text":"Restrict access to potentially sensitive files that deal with authentication and/or authorization.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"Multi-factor Authentication","text":"Use multi-factor authentication for user and privileged accounts.","url":"https://attack.mitre.org/mitigations/M1032"}]},{"id":"T1102","name":"Web Service","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1102","summary":"Adversaries may use an existing, legitimate external Web service as a means for relaying data to/from a compromised system.","description":"Adversaries may use an existing, legitimate external Web service as a means for relaying data to/from a compromised system. Popular websites, cloud services, and social media acting as a mechanism for C2 may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to a compromise. Using common services, such as those offered by Google, Microsoft, or Twitter, makes it easier for adversaries to hide in expected noise.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Network Traffic Flow"],"examples":["APT32 has used Dropbox, Amazon S3, and Google Drive to host malicious downloads.","APT41 DUST used compromised Google Workspace accounts for command and control.","APT42 has used various links, such as links with typo-squatted domains, links to Dropbox files and links to fake Google sites, in spearphishing operations.","AshTag can download malicious payloads from file sharing services."],"examplesTotal":49,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Restrict Web-Based Content","text":"Web proxies can be used to enforce external network communication policy that prevents use of unauthorized external services.","url":"https://attack.mitre.org/mitigations/M1021"}]},{"id":"T1104","name":"Multi-Stage Channels","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1104","summary":"Adversaries may create multiple stages for command and control that are employed under different conditions or for certain functions.","description":"Adversaries may create multiple stages for command and control that are employed under different conditions or for certain functions. Use of multiple stages may obfuscate the command and control channel to make detection more difficult. Remote access tools will call back to the first-stage command and control server for instructions. The first stage may have automated capabilities to collect basic host information, update tools, and upload additional files.","platforms":["Linux","macOS","Windows","ESXi"],"detection":["Network Connection Creation","Network Traffic Flow","Process Creation"],"examples":["An APT3 downloader first establishes a SOCKS5 connection to 192.157.198[.]103 using TCP port 1913; once the server response is verified, it then requests a connection to 192.184.60[.]229 on TCP port 81.","APT41 used the storescyncsvc.dll BEACON backdoor to download a secondary backdoor.","BACKSPACE attempts to avoid detection by checking a first stage command and control server to determine if it should connect to the second stage server, which performs \"louder\" interactions with the malware.","BLACKCOFFEE uses Microsoft’s TechNet Web portal to obtain an encoded tag containing the IP address of a command and control server and then communicates separately with that IP address for C2."],"examplesTotal":15,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1105","name":"Ingress Tool Transfer","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1105","summary":"Adversaries may transfer tools or other files from an external system into a compromised environment.","description":"Adversaries may transfer tools or other files from an external system into a compromised environment. Tools or files may be copied from an external adversary-controlled system to the victim network through the command and control channel or through alternate protocols such as ftp. Once present, adversaries may also transfer/spread tools between victim devices within a compromised environment (i.e. Lateral Tool Transfer).","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Creation","Network Connection Creation","Network Traffic Flow","Process Creation"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team pushed additional malicious tools onto an infected system to steal user credentials, move laterally, and destroy data.","During the 2025 Poland Wiper Attacks, the adversaries downloaded malicious payloads to the victim server.","ABK has the ability to download files from C2.","ANDROMEDA can download additional payloads from C2."],"examplesTotal":515,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware or unusual data transfer over known protocols…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Filter Network Traffic","text":"Use network filtering to block outbound traffic from compromised systems to unapproved external destinations.","url":"https://attack.mitre.org/mitigations/M1037"}]},{"id":"T1106","name":"Native API","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1106","summary":"Adversaries may interact with the native OS application programming interface (API) to execute behaviors.","description":"Adversaries may interact with the native OS application programming interface (API) to execute behaviors. Native APIs provide a controlled means of calling low-level OS services within the kernel, such as those involving hardware/devices, memory, and processes. These native APIs are leveraged by the OS during system boot (when other system components are not yet initialized) as well as carrying out tasks and requests during routine operations.","platforms":["Linux","macOS","Windows"],"detection":["Module Load","Process Access","Process Creation"],"examples":["ADVSTORESHELL is capable of starting a process using CreateProcess.","ANELLDR can use the ZwSetInformationThread to enable debugger evasion.","APT37 leverages the Windows API calls: VirtualAlloc(), WriteProcessMemory(), and CreateRemoteThread() for process injection.","APT38 has used the Windows API to execute code within a victim's system."],"examplesTotal":228,"mitigations":[{"name":"Execution Prevention","text":"Identify and block potentially malicious software executed that may be executed through this technique by using application control tools, like Windows Defender Application…","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office VBA macros from calling Win32 APIs.","url":"https://attack.mitre.org/mitigations/M1040"}]},{"id":"T1110","name":"Brute Force","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1110","summary":"Adversaries may use brute force techniques to gain access to accounts when passwords are unknown or when password hashes are obtained.","description":"Adversaries may use brute force techniques to gain access to accounts when passwords are unknown or when password hashes are obtained. Without knowledge of the password for an account or set of accounts, an adversary may systematically guess the password using a repetitive or iterative mechanism. Brute forcing passwords can take place via interaction with a service that will check the validity of those credentials or offline against previously acquired credential data, such as password hashes.","platforms":["Containers","ESXi","IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"detection":["User Account Authentication"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used a script to attempt RPC authentication against a number of hosts.","APT28 can perform brute force attacks to obtain credentials.","APT38 has used brute force techniques to attempt account access when passwords are unknown or when password hashes are unavailable.","APT39 has used Ncrack to reveal credentials."],"examplesTotal":24,"mitigations":[{"name":"User Account Management","text":"Proactively reset accounts that are known to be part of breached credentials either immediately, or after detecting bruteforce attempts.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Account Use Policies","text":"Set account lockout policies after a certain number of failed login attempts to prevent passwords from being guessed.","url":"https://attack.mitre.org/mitigations/M1036"},{"name":"Multi-factor Authentication","text":"Use multi-factor authentication. Where possible, also enable multi-factor authentication on externally facing services.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Password Policies","text":"Refer to NIST guidelines when creating password policies.","url":"https://attack.mitre.org/mitigations/M1027"}]},{"id":"T1111","name":"Multi-Factor Authentication Interception","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1111","summary":"Adversaries may target multi-factor authentication (MFA) mechanisms, (i.e., smart cards, token generators, etc.) to gain access to credentials that can be used to access systems, services, and network resources.","description":"Adversaries may target multi-factor authentication (MFA) mechanisms, (i.e., smart cards, token generators, etc.) to gain access to credentials that can be used to access systems, services, and network resources. Use of MFA is recommended and provides a higher level of security than usernames and passwords alone, but organizations should be aware of techniques that could be used to intercept and bypass these security mechanisms.","platforms":["Linux","macOS","Windows"],"detection":["Driver Load","Logon Session Creation","OS API Execution","Process Access","Process Creation","Windows Registry Key Modification"],"examples":["APT42 has intercepted SMS-based one-time passwords and has set up two-factor authentication. Additionally, APT42 has used cloned or fake websites to capture MFA tokens.","Chimera has registered alternate phone numbers for compromised users to intercept 2FA codes sent via SMS.","Kimsuky has used a proprietary tool to intercept one time passwords required for two-factor authentication.","LAPSUS$ has replayed stolen session token and passwords to trigger simple-approval MFA prompts in hope of the legitimate user will grant necessary approval."],"examplesTotal":9,"mitigations":[{"name":"User Training","text":"Remove smart cards when not in use.","url":"https://attack.mitre.org/mitigations/M1017"}]},{"id":"T1112","name":"Modify Registry","tactics":["Defense Impairment","Persistence"],"url":"https://attack.mitre.org/techniques/T1112","summary":"Adversaries may interact with the Windows Registry as part of a variety of other techniques to aid in defense evasion, persistence, and execution.","description":"Adversaries may interact with the Windows Registry as part of a variety of other techniques to aid in defense evasion, persistence, and execution. Access to specific areas of the Registry depends on account permissions, with some keys requiring administrator-level access. The built-in Windows command-line utility Reg may be used for local or remote Registry modification.","platforms":["Windows"],"detection":["Process Creation","Windows Registry Key Modification"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team modified in-registry Internet settings to lower internet security before launching rundll32.exe, which in-turn launches the malware and communicates with C2 servers over the…","AADInternals can modify registry keys as part of setting a new pass-through authentication agent.","ADVSTORESHELL is capable of setting and deleting Registry values.","APT19 uses a Port 22 malware variant to modify several Registry keys."],"examplesTotal":173,"mitigations":[{"name":"Restrict Registry Permissions","text":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys for system components that may lead to privilege escalation.","url":"https://attack.mitre.org/mitigations/M1024"}]},{"id":"T1113","name":"Screen Capture","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1113","summary":"Adversaries may attempt to take screen captures of the desktop to gather information over the course of an operation.","description":"Adversaries may attempt to take screen captures of the desktop to gather information over the course of an operation. Screen capturing functionality may be included as a feature of a remote access tool used in post-compromise operations. Taking a screenshot is also typically possible through native utilities or API calls, such as CopyFromScreen, xwd, or screencapture.","platforms":["Linux","macOS","Windows"],"detection":["Module Load","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries captured screenshots of devices using nircmd console through the command nircmd.exe “savescreenshot C:\\Windows\\Temp\\imagetmp.png.","APT28 has used tools to take screenshots from victims.","APT39 has used a screen capture utility to take screenshots on a compromised host.","APT42 has used malware, such as GHAMBAR and POWERPOST, to take screenshots."],"examplesTotal":171},{"id":"T1114","name":"Email Collection","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1114","summary":"Adversaries may target user email to collect sensitive information.","description":"Adversaries may target user email to collect sensitive information. Emails may contain sensitive data, including trade secrets or personal information, that can prove valuable to adversaries. Emails may also contain details of ongoing incident response operations, which may allow adversaries to adjust their techniques in order to maintain persistence or evade defenses. Adversaries can collect or forward email from mail servers or clients.","platforms":["Windows","macOS","Linux","Office Suite"],"detection":["Application Log Content","Command Execution","File Access","Logon Session Creation","Network Connection Creation","Network Share Access","Process Creation"],"examples":["Ember Bear attempts to collect mail from accessed systems and servers.","Emotet has been observed leveraging a module that can scrape email addresses from Outlook.","Magic Hound has compromised email credentials in order to steal sensitive data.","Scattered Spider searched the victim’s Microsoft Exchange for emails about the intrusion and incident response."],"examplesTotal":6,"mitigations":[{"name":"Multi-factor Authentication","text":"Use of multi-factor authentication for public-facing webmail servers is a recommended best practice to minimize the usefulness of usernames and passwords to adversaries.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Out-of-Band Communications Channel","text":"Use secure out-of-band authentication methods to verify the authenticity of critical actions initiated via email, such as password resets, financial transactions, or access…","url":"https://attack.mitre.org/mitigations/M1060"},{"name":"Encrypt Sensitive Information","text":"Use of encryption provides an added layer of security to sensitive information sent over email.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Audit","text":"Enterprise email solutions have monitoring mechanisms that may include the ability to audit auto-forwarding rules on a regular basis.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1115","name":"Clipboard Data","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1115","summary":"Adversaries may collect data stored in the clipboard from users copying information within or between applications.","description":"Adversaries may collect data stored in the clipboard from users copying information within or between applications. For example, on Windows adversaries can access clipboard data by using clip.exe or Get-Clipboard. Additionally, adversaries may monitor then replace users’ clipboard with their data (e.g., Transmitted Data Manipulation). macOS and Linux also have commands, such as pbpaste, to grab clipboard contents.","platforms":["Linux","macOS","Windows"],"detection":["Process Access","Process Creation"],"examples":["APT38 used a Trojan called KEYLIME to collect data from the clipboard.","APT39 has used tools capable of stealing contents of the clipboard.","Agent Tesla can steal data from the victim’s clipboard.","Astaroth collects information from the clipboard by using the OpenClipboard() and GetClipboardData() libraries."],"examplesTotal":46},{"id":"T1119","name":"Automated Collection","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1119","summary":"Once established within a system or network, an adversary may use automated techniques for collecting internal data.","description":"Once established within a system or network, an adversary may use automated techniques for collecting internal data. Methods for performing this technique could include use of a Command and Scripting Interpreter to search for and copy information fitting set criteria such as file type, location, or name at specific time intervals.","platforms":["IaaS","Linux","macOS","Office Suite","SaaS","Windows"],"detection":["File Access","File Creation","Process Creation","Script Execution","User Account Authentication"],"examples":["APT1 used a batch script to perform a series of discovery techniques and saves it to a text file.","APT28 used a publicly available tool to gather and compress multiple documents on the DCCC and DNC networks.","APT41 DUST used tools such as SQLULDR2 and PINEGROVE to gather local system and database information.","Agrius used a custom tool, sql.net4.exe, to query SQL databases and then identify and extract personally identifiable information."],"examplesTotal":73,"mitigations":[{"name":"Remote Data Storage","text":"Encryption and off-system storage of sensitive information may be one way to mitigate collection of files, but may not stop an adversary from acquiring the information if an…","url":"https://attack.mitre.org/mitigations/M1029"},{"name":"Encrypt Sensitive Information","text":"Encryption and off-system storage of sensitive information may be one way to mitigate collection of files, but may not stop an adversary from acquiring the information if an…","url":"https://attack.mitre.org/mitigations/M1041"}]},{"id":"T1120","name":"Peripheral Device Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1120","summary":"Adversaries may attempt to gather information about attached peripheral devices and components connected to a computer system.","description":"Adversaries may attempt to gather information about attached peripheral devices and components connected to a computer system. Peripheral devices could include auxiliary resources that support a variety of functionalities such as keyboards, printers, cameras, smart card readers, or removable storage. The information may be used to enhance their awareness of the system and network environment or may be used for further actions.","platforms":["Linux","macOS","Windows"],"detection":["Drive Access","File Access","Process Access","Process Creation"],"examples":["ADVSTORESHELL can list connected devices.","APT28 uses a module to receive a notification every time a USB mass storage device is inserted into a victim.","APT37 has a Bluetooth device harvester, which uses Windows Bluetooth APIs to find information on connected Bluetooth devices.","AcidPour includes functionality to identify MMC and SD cards connected to the victim device."],"examplesTotal":58},{"id":"T1123","name":"Audio Capture","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1123","summary":"An adversary can leverage a computer's peripheral devices (e.g., microphones and webcams) or applications (e.g., voice and video call services) to capture audio recordings for the purpose of listening into sensitive conversations to…","description":"An adversary can leverage a computer's peripheral devices (e.g., microphones and webcams) or applications (e.g., voice and video call services) to capture audio recordings for the purpose of listening into sensitive conversations to gather information. Malware or scripts may be used to interact with the devices through an available API provided by the operating system or an application to capture audio. Audio files may be written to disk and exfiltrated later.","platforms":["Linux","macOS","Windows"],"detection":["File Access","File Creation","OS API Execution","Process Access","Process Creation"],"examples":["APT37 has used an audio capturing utility known as SOUNDWAVE that captures microphone input.","Attor's has a plugin that is capable of recording audio using available input sound devices.","Bandook has modules that are capable of capturing audio.","Cadelspy has the ability to record audio from the compromised host."],"examplesTotal":32},{"id":"T1124","name":"System Time Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1124","summary":"An adversary may gather the system time and/or time zone settings from a local or remote system.","description":"An adversary may gather the system time and/or time zone settings from a local or remote system. The system time is set and stored by services, such as the Windows Time Service on Windows or systemsetup on macOS. These time settings may also be synchronized between systems and services in an enterprise network, typically accomplished with a network time server within a domain.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","File Creation","File Modification","Module Load","OS API Execution","Process Access","Process Creation","Process Metadata","Scheduled Job Creation","Scheduled Job Metadata"],"examples":["Agent Tesla can collect the timestamp from the victim’s machine.","AppleSeed can pull a timestamp from the victim's machine.","Astaroth collects the timestamp from the infected machine.","AsyncRAT can check whether the current system hour and day of the week are within operating hours defined it its configuration."],"examplesTotal":98},{"id":"T1125","name":"Video Capture","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1125","summary":"An adversary can leverage a computer's peripheral devices (e.g., integrated cameras or webcams) or applications (e.g., video call services) to capture video recordings for the purpose of gathering information.","description":"An adversary can leverage a computer's peripheral devices (e.g., integrated cameras or webcams) or applications (e.g., video call services) to capture video recordings for the purpose of gathering information. Images may also be captured from devices or applications, potentially in specified intervals, in lieu of video files. Malware or scripts may be used to interact with the devices through an available API provided by the operating system or an application to capture video or images.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Access","File Creation","Module Load","Network Connection Creation","Network Traffic Content","OS API Execution","Process Creation","Process Metadata"],"examples":["Agent Tesla can access the victim’s webcam and record video.","AsyncRAT can record screen content on targeted systems.","Bandook has modules that are capable of capturing video from a victim's webcam.","Clambling can record screen content in AVI format."],"examplesTotal":35},{"id":"T1127","name":"Trusted Developer Utilities Proxy Execution","tactics":["Stealth","Execution"],"url":"https://attack.mitre.org/techniques/T1127","summary":"Adversaries may take advantage of trusted developer utilities to proxy execution of malicious payloads.","description":"Adversaries may take advantage of trusted developer utilities to proxy execution of malicious payloads. There are many utilities used for software development related tasks that can be used to execute code in various forms to assist in development, debugging, and reverse engineering.","platforms":["Windows"],"detection":["File Creation","Module Load","Network Connection Creation","Process Creation","Process Metadata"],"mitigations":[{"name":"Execution Prevention","text":"Certain developer utilities should be blocked or restricted if not required.","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Restrict Web-Based Content","text":"Consider disabling software installation or execution from the internet via developer utilities.","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Disable or Remove Feature or Program","text":"Specific developer utilities may not be necessary within a given environment and should be removed if not used.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1129","name":"Shared Modules","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1129","summary":"Adversaries may execute malicious payloads via loading shared modules.","description":"Adversaries may execute malicious payloads via loading shared modules. Shared modules are executable files that are loaded into processes to provide access to reusable code, such as specific custom functions or invoking OS API functions (i.e., Native API). Adversaries may use this functionality as a way to execute arbitrary payloads on a victim system.","platforms":["Linux","macOS","Windows"],"detection":["File Access","File Creation","Module Load","Network Connection Creation","Network Traffic Content","Process Creation","Process Metadata"],"examples":["Astaroth uses the LoadLibraryExW() function to load additional modules.","Attor's dispatcher can execute additional plugins by loading the respective DLLs.","BLINDINGCAN has loaded and executed DLLs in memory during runtime on a victim machine.","BOOSTWRITE has used the DWriteCreateFactory() function to load additional modules."],"examplesTotal":22,"mitigations":[{"name":"Execution Prevention","text":"Identify and block potentially malicious software executed through this technique by using application control tools capable of preventing unknown modules from being loaded.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1132","name":"Data Encoding","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1132","summary":"Adversaries may encode data to make the content of command and control traffic more difficult to detect.","description":"Adversaries may encode data to make the content of command and control traffic more difficult to detect. Command and control (C2) information can be encoded using a standard data encoding system. Use of data encoding may adhere to existing protocol specifications and includes use of ASCII, Unicode, Base64, MIME, or other binary-to-text and character encoding systems. Some data encoding systems may also result in data compression, such as gzip.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Command Execution","Network Connection Creation","Network Traffic Content","Process Creation","User Account Authentication"],"examples":["After encrypting C2 data, BADNEWS converts it into a hexadecimal representation and then encodes it into base64.","H1N1 obfuscates C2 traffic with an altered version of base64.","LAMEHUG can encode queries sent to LLMs.","Linux Rabbit sends the payload from the C2 server as an encoded URL parameter."],"examplesTotal":8,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1133","name":"External Remote Services","tactics":["Persistence","Initial Access"],"url":"https://attack.mitre.org/techniques/T1133","summary":"Adversaries may leverage external-facing remote services to initially access and/or persist within a network.","description":"Adversaries may leverage external-facing remote services to initially access and/or persist within a network. Remote services such as VPNs, Citrix, and other access mechanisms allow users to connect to internal enterprise network resources from external locations. There are often remote service gateways that manage connections and credential authentication for these services. Services such as Windows Remote Management and VNC can also be used externally.","platforms":["Containers","Linux","macOS","Windows"],"detection":["Application Log Content","Logon Session Metadata","Network Connection Creation","Network Traffic Flow","User Account Authentication"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team installed a modified Dropbear SSH client as the backdoor to target systems.","During the 2025 Poland Wiper Attacks, threat actors leveraged the FortiGate VPN interface that was exposed to the internet to gain access to the victim environment.","APT-C-36 has used VPNs in their operational infrastructure.","APT18 actors leverage legitimate credentials to log into external remote services."],"examplesTotal":43,"mitigations":[{"name":"Restrict Web-Based Content","text":"Restrict all traffic to and from public Tor nodes.","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Network Segmentation","text":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Disable or Remove Feature or Program","text":"Disable or block remotely available services that may be unnecessary.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Limit Access to Resource Over Network","text":"Limit access to remote services through centrally managed concentrators such as VPNs and other managed remote access systems.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Multi-factor Authentication","text":"Use strong two-factor or multi-factor authentication for remote service accounts to mitigate an adversary's ability to leverage stolen credentials, but be aware of Multi-Factor…","url":"https://attack.mitre.org/mitigations/M1032"}]},{"id":"T1134","name":"Access Token Manipulation","tactics":["Stealth","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1134","summary":"Adversaries may modify access tokens to operate under a different user or system security context to perform actions and bypass access controls.","description":"Adversaries may modify access tokens to operate under a different user or system security context to perform actions and bypass access controls. Windows uses access tokens to determine the ownership of a running process. A user can manipulate access tokens to make a running process appear as though it is the child of a different process or belongs to someone other than the user that started the process.","platforms":["Windows"],"detection":["Active Directory Object Modification","Logon Session Metadata","OS API Execution","Process Access","Process Creation"],"examples":["AppleSeed can gain system level privilege by passing SeDebugPrivilege to the AdjustTokenPrivilege API.","BlackCat has the ability modify access tokens.","Blue Mockingbird has used JuicyPotato to abuse the SeImpersonate token privilege to escalate from web application pool accounts to NT Authority\\SYSTEM.","During C0017, APT41 used a ConfuserEx obfuscated BADPOTATO exploit to abuse named-pipe impersonation for local NT AUTHORITY\\SYSTEM privilege escalation."],"examplesTotal":23,"mitigations":[{"name":"User Account Management","text":"An adversary must already have administrator level access on the local system to make full use of this technique; be sure to restrict users and accounts to the least privileges…","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Privileged Account Management","text":"Limit permissions so that users and user groups cannot create tokens. This setting should be defined for the local system account only.","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1135","name":"Network Share Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1135","summary":"Adversaries may look for folders and drives shared on remote systems as a means of identifying sources of information to gather as a precursor for Collection and to identify potential systems of interest for Lateral Movement.","description":"Adversaries may look for folders and drives shared on remote systems as a means of identifying sources of information to gather as a precursor for Collection and to identify potential systems of interest for Lateral Movement. Networks often contain shared network drives and folders that enable users to access file directories on various systems across a network. File sharing over a Windows network occurs over the SMB protocol.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","Named Pipe Metadata","Network Connection Creation","Network Traffic Flow","OS API Execution","Process Creation"],"examples":["APT1 listed connected network shares.","APT32 used the net view command to show all shares available, including the administrative shares such as C$ and ADMIN$.","APT38 has enumerated network shares on a compromised host.","APT39 has used the post exploitation tool CrackMapExec to enumerate network shares."],"examplesTotal":77,"mitigations":[{"name":"Operating System Configuration","text":"Enable Windows Group Policy “Do Not Allow Anonymous Enumeration of SAM Accounts and Shares” security setting to limit users who can enumerate network shares.","url":"https://attack.mitre.org/mitigations/M1028"}]},{"id":"T1136","name":"Create Account","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1136","summary":"Adversaries may create an account to maintain access to victim systems.","description":"Adversaries may create an account to maintain access to victim systems. With a sufficient level of access, creating such accounts may be used to establish secondary credentialed access that do not require persistent remote access tools to be deployed on the system. Accounts may be created on the local system or within a domain or cloud tenant. In cloud environments, adversaries may create accounts that only have access to specific services, which can reduce the chance of detection.","platforms":["Windows","IaaS","Linux","macOS","Network Devices","Containers","SaaS","Office Suite","Identity Provider","ESXi"],"detection":["Command Execution","File Modification","Process Creation","User Account Creation","User Account Modification"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team added a login to a SQL Server with sp_addlinkedsrvlogin.","Indrik Spider used wmic.exe to add a new user to the system.","LockBit 2.0 has been observed creating accounts for persistence using simple names like \"a\".","Salt Typhoon has created Linux-level users on compromised network devices through modification of /etc/shadow and /etc/passwd."],"examplesTotal":5,"mitigations":[{"name":"Network Segmentation","text":"Configure access controls and firewalls to limit access to domain controllers and systems used to create and manage accounts.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Operating System Configuration","text":"Protect domain controllers by ensuring proper security configuration for critical servers.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"Multi-factor Authentication","text":"Use multi-factor authentication for user and privileged accounts.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Privileged Account Management","text":"Limit the number of accounts with permissions to create other accounts. Do not allow domain administrator accounts to be used for day-to-day operations that may expose them to…","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1137","name":"Office Application Startup","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1137","summary":"Adversaries may leverage Microsoft Office-based applications for persistence between startups.","description":"Adversaries may leverage Microsoft Office-based applications for persistence between startups. Microsoft Office is a fairly common application suite on Windows-based operating systems within an enterprise network. There are multiple mechanisms that can be used with Office for persistence when an Office-based application is started; this can include the use of Office Template Macros and add-ins.","platforms":["Windows","Office Suite"],"detection":["Application Log Content","File Creation","Process Creation","User Account Modification","Windows Registry Key Modification"],"examples":["APT32 have replaced Microsoft Outlook's VbaProject.OTM file to install a backdoor macro for persistence.","Gamaredon Group has inserted malicious macros into existing documents, providing persistence when they are reopened. Gamaredon Group has loaded the group's previously delivered VBA project by relaunching Microsoft Outlook with the /altvba…"],"examplesTotal":2,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Follow Office macro security best practices suitable for your environment. Disable Office VBA macros from executing. Disable Office add-ins.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent Office applications from creating child processes and from writing potentially malicious executable content…","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Update Software","text":"For the Outlook methods, blocking macros may be ineffective as the Visual Basic engine used for these features is separate from the macro scripting engine.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Software Configuration","text":"For the Office Test method, create the Registry key used to execute it and set the permissions to \"Read Control\" to prevent easy access to the key without administrator…","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1140","name":"Deobfuscate/Decode Files or Information","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1140","summary":"Adversaries may use Obfuscated Files or Information to hide artifacts of an intrusion from analysis.","description":"Adversaries may use Obfuscated Files or Information to hide artifacts of an intrusion from analysis. They may require separate mechanisms to decode or deobfuscate that information depending on how they intend to use it. Methods for doing that include built-in functionality of malware or by using utilities present on the system. One such example is the use of certutil to decode a remote access tool portable executable file that has been hidden inside a certificate file.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Command Execution","File Creation","Process Access","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries decoded a Base64-encoded ZIP archive using the built-in certutil.","ABK has the ability to decrypt AES encrypted payloads.","ANELLDR can decrypt encrypted payload data using AES-256-CBC and subsequently execute the payload in memory.","An APT19 HTTP malware variant decrypts strings using single-byte XOR keys."],"examplesTotal":350},{"id":"T1176","name":"Software Extensions","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1176","summary":"Adversaries may abuse software extensions to establish persistent access to victim systems.","description":"Adversaries may abuse software extensions to establish persistent access to victim systems. Software extensions are modular components that enhance or customize the functionality of software applications, including web browsers, Integrated Development Environments (IDEs), and other platforms. Extensions are typically installed via official marketplaces, app stores, or manually loaded by users, and they often inherit the permissions and access levels of the host application.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Creation","Network Connection Creation","Network Traffic Flow","Process Creation","Windows Registry Key Modification"],"mitigations":[{"name":"Limit Software Installation","text":"Only install extensions from trusted sources that can be verified.","url":"https://attack.mitre.org/mitigations/M1033"},{"name":"Audit","text":"Ensure extensions that are installed are the intended ones, as many malicious extensions may masquerade as legitimate ones.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"User Training","text":"Train users to minimize extension use, and to only install trusted extensions.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Update Software","text":"Ensure operating systems and software are using the most current version.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Execution Prevention","text":"Set an extension allow or deny list as appropriate for your security policy.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1185","name":"Browser Session Hijacking","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1185","summary":"Adversaries may take advantage of security vulnerabilities and inherent functionality in browser software to change content, modify user-behaviors, and intercept information as part of various browser session hijacking techniques.","description":"Adversaries may take advantage of security vulnerabilities and inherent functionality in browser software to change content, modify user-behaviors, and intercept information as part of various browser session hijacking techniques. A specific example is when an adversary injects software into a browser that allows them to inherit cookies, HTTP sessions, and SSL client certificates of a user then use the browser as a way to pivot into an authenticated intranet.","platforms":["Windows"],"detection":["Logon Session Creation","Logon Session Metadata","Module Load","Network Connection Creation","Process Access","Process Modification","User Account Metadata"],"examples":["Agent Tesla has the ability to use form-grabbing to extract data from web data forms.","Carberp has captured credentials when a user performs login through a SSL session.","Chaes has used the Puppeteer module to hook and monitor the Chrome web browser to collect user information from infected hosts.","Cobalt Strike can perform browser pivoting and inject into a user's browser to inherit cookies, authenticated HTTP sessions, and client SSL certificates."],"examplesTotal":15,"mitigations":[{"name":"User Training","text":"Close all browser sessions regularly and when they are no longer needed.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"User Account Management","text":"Since browser pivoting requires a high integrity process to launch from, restricting user permissions and addressing Privilege Escalation and Bypass User Account Control…","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1187","name":"Forced Authentication","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1187","summary":"Adversaries may gather credential material by invoking or forcing a user to automatically provide authentication information through a mechanism in which they can intercept.","description":"Adversaries may gather credential material by invoking or forcing a user to automatically provide authentication information through a mechanism in which they can intercept. The Server Message Block (SMB) protocol is commonly used in Windows networks for authentication and communication between systems for access to resources and file sharing.","platforms":["Windows"],"detection":["File Creation","File Modification","Network Traffic Content","Network Traffic Flow"],"examples":["DarkHydrus used Template Injection to launch an authentication window for users to enter their credentials.","Dragonfly has gathered hashed user credentials over SMB using spearphishing attachments with external resource links and by modifying .LNK file icon resources to collect credentials from virtualized systems.","EnvyScout can use protocol handlers to coax the operating system to send NTLMv2 authentication responses to attacker-controlled infrastructure."],"examplesTotal":3,"mitigations":[{"name":"Password Policies","text":"Use strong passwords to increase the difficulty of credential hashes from being cracked if they are obtained.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"Filter Network Traffic","text":"Block SMB traffic from exiting an enterprise network with egress filtering or by blocking TCP ports 139, 445 and UDP port 137.","url":"https://attack.mitre.org/mitigations/M1037"}]},{"id":"T1189","name":"Drive-by Compromise","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1189","summary":"Adversaries may gain access to a system through a user visiting a website over the normal course of browsing.","description":"Adversaries may gain access to a system through a user visiting a website over the normal course of browsing. Multiple ways of delivering exploit code to a browser exist (i.e., Drive-by Target), including: A legitimate website is compromised, allowing adversaries to inject malicious code Script files served to a legitimate website from a publicly writeable cloud storage bucket are modified by an adversary Malicious ads are paid for and served through legitimate ad providers (i.e., Malvertising)…","platforms":["Identity Provider","Linux","macOS","Windows"],"detection":["Application Log Content","File Creation","Logon Session Creation","Network Connection Creation","Network Traffic Content","Process Creation","Process Modification","User Account Authentication","User Account Metadata"],"examples":["During the 3CX Supply Chain Attack, AppleJeus compromised the www.tradingtechnologies[.]com website hosting a hidden IFRAME to exploit visitors, two months before the site was known to deliver a compromised version of the X_TRADER software…","APT19 performed a watering hole attack on forbes.com in 2014 to compromise targets.","APT28 has compromised targets via strategic web compromise utilizing custom exploit kits. APT28 used reflected cross-site scripting (XSS) against government websites to redirect users to phishing webpages.","APT32 has infected victims by tricking them into visiting compromised watering hole websites."],"examplesTotal":44,"mitigations":[{"name":"Exploit Protection","text":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Update Software","text":"Ensuring that all browsers and plugins are kept updated can help prevent the exploit phase of this technique. Use modern browsers with security features turned on.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Application Isolation and Sandboxing","text":"Browser sandboxes can be used to mitigate some of the impact of exploitation, but sandbox escapes may still exist.","url":"https://attack.mitre.org/mitigations/M1048"},{"name":"Restrict Web-Based Content","text":"Adblockers can help prevent malicious code served through ads from executing in the first place. Script blocking extensions can also help to prevent the execution of JavaScript.","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"User Training","text":"Train users to be aware of access or manipulation attempts by an adversary to reduce the risk of successful spearphishing, social engineering, and other techniques that involve…","url":"https://attack.mitre.org/mitigations/M1017"}]},{"id":"T1190","name":"Exploit Public-Facing Application","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1190","summary":"Adversaries may attempt to exploit a weakness in an Internet-facing host or system to initially access a network.","description":"Adversaries may attempt to exploit a weakness in an Internet-facing host or system to initially access a network. The weakness in the system can be a software bug, a temporary glitch, or a misconfiguration. Exploited applications are often websites/web servers, but can also include databases (like SQL), standard services (like SMB or SSH), network device administration and management protocols (like SNMP and Smart Install), and any other system with Internet-accessible open sockets.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Application Log Content","Module Load","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["APT28 has used a variety of public exploits, including CVE 2020-0688 and CVE 2020-17144, to gain execution on vulnerable Microsoft Exchange; they have also conducted SQL injection attacks against external websites.","APT29 has exploited CVE-2019-19781 for Citrix, CVE-2019-11510 for Pulse Secure VPNs, CVE-2018-13379 for FortiGate VPNs, and CVE-2019-9670 in Zimbra software to gain access.","APT39 has used SQL injection for initial compromise.","APT41 exploited CVE-2020-10189 against Zoho ManageEngine Desktop Central through unsafe deserialization, and CVE-2019-19781 to compromise Citrix Application Delivery Controllers (ADC) and gateway devices."],"examplesTotal":73,"mitigations":[{"name":"Application Isolation and Sandboxing","text":"Application isolation will limit what other processes and system features the exploited target can access.","url":"https://attack.mitre.org/mitigations/M1048"},{"name":"Filter Network Traffic","text":"Restrict outbound network traffic from public-facing servers to prevent unauthorized connections from initiating communications with attacker-controlled infrastructure.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Segmentation","text":"Segment externally facing servers and services from the rest of the network with a DMZ or on separate hosting infrastructure.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Vulnerability Scanning","text":"Regularly scan externally facing systems for vulnerabilities and establish procedures to rapidly patch systems when critical vulnerabilities are discovered through scanning and…","url":"https://attack.mitre.org/mitigations/M1016"},{"name":"Privileged Account Management","text":"Use least privilege for service accounts will limit what permissions the exploited process gets on the rest of the system.","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1195","name":"Supply Chain Compromise","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1195","summary":"Adversaries may manipulate products or product delivery mechanisms prior to receipt by a final consumer for the purpose of data or system compromise.","description":"Adversaries may manipulate products or product delivery mechanisms prior to receipt by a final consumer for the purpose of data or system compromise. Supply chain compromise can take place at any stage of the supply chain including: Manipulation of development tools Manipulation of a development environment Manipulation of source code repositories (public or private) Manipulation of source code in open-source dependencies Manipulation of software update/distribution mechanisms…","platforms":["Linux","Windows","macOS","SaaS"],"detection":["File Creation","File Metadata","File Modification","Module Load","Network Traffic Flow","Process Creation","Process Modification"],"examples":["Ember Bear has compromised information technology providers and software developers providing services to targets of interest, building initial access to ultimate victims at least in part through compromise of service providers that work…","Lumma Stealer has been delivered through cracked software downloads.","OilRig has leveraged compromised organizations to conduct supply chain attacks on government entities.","Raccoon Stealer has been distributed through cracked software downloads."],"examplesTotal":5,"mitigations":[{"name":"Boot Integrity","text":"Use secure methods to boot a system and verify the integrity of the operating system and loading mechanisms.","url":"https://attack.mitre.org/mitigations/M1046"},{"name":"Application Developer Guidance","text":"Application developers should be cautious when selecting third-party libraries to integrate into their application.","url":"https://attack.mitre.org/mitigations/M1013"},{"name":"Update Software","text":"A patch management process should be implemented to check unused dependencies, unmaintained and/or previously vulnerable dependencies, unnecessary features, components, files, and…","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"User Account Management","text":"Implement robust user account management practices to limit permissions associated with software execution.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Vulnerability Scanning","text":"Continuous monitoring of vulnerability sources and the use of automatic and manual code review tools should also be implemented as well.","url":"https://attack.mitre.org/mitigations/M1016"}]},{"id":"T1197","name":"BITS Jobs","tactics":["Stealth","Persistence","Execution"],"url":"https://attack.mitre.org/techniques/T1197","summary":"Adversaries may abuse BITS jobs to persistently execute code and perform various background tasks.","description":"Adversaries may abuse BITS jobs to persistently execute code and perform various background tasks. Windows Background Intelligent Transfer Service (BITS) is a low-bandwidth, asynchronous file transfer mechanism exposed through Component Object Model (COM). BITS is commonly used by updaters, messengers, and other applications preferred to operate in the background (using available idle bandwidth) without interrupting other networked applications.","platforms":["Windows"],"detection":["Command Execution","Network Connection Creation","Process Creation","Service Creation"],"examples":["APT39 has used the BITS protocol to exfiltrate stolen data from a compromised host.","APT41 used BITSAdmin to download and install payloads.","BITSAdmin can be used to create BITS Jobs to launch a malicious process.","Bazar has been downloaded via Windows BITS functionality."],"examplesTotal":13,"mitigations":[{"name":"User Account Management","text":"Consider limiting access to the BITS interface to specific users or groups.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Filter Network Traffic","text":"Modify network and/or host firewall rules, as well as other network controls, to only allow legitimate BITS traffic.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Operating System Configuration","text":"Consider reducing the default BITS job lifetime in Group Policy or by editing the JobInactivityTimeout and MaxDownloadTime Registry values in…","url":"https://attack.mitre.org/mitigations/M1028"}]},{"id":"T1199","name":"Trusted Relationship","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1199","summary":"Adversaries may breach or otherwise leverage organizations who have access to intended victims.","description":"Adversaries may breach or otherwise leverage organizations who have access to intended victims. Access through trusted third party relationship abuses an existing connection that may not be protected or receives less scrutiny than standard mechanisms of gaining access to a network. Organizations often grant elevated access to second or third-party external providers in order to allow them to manage internal systems as well as cloud-based environments.","platforms":["IaaS","Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","Logon Session Creation","Logon Session Metadata","Network Connection Creation","Network Traffic Content"],"examples":["Once APT28 gained access to the DCCC network, the group then proceeded to use that access to compromise the DNC network.","APT29 has compromised IT, cloud services, and managed services providers to gain broad access to multiple customers for subsequent operations.","GOLD SOUTHFIELD has breached Managed Service Providers (MSP's) to deliver malware to MSP customers.","HAFNIUM has used stolen API keys and credentials associated with privilege access management (PAM), cloud app providers, and cloud data management companies to access downstream customer environments."],"examplesTotal":13,"mitigations":[{"name":"Multi-factor Authentication","text":"Require MFA for all delegated administrator accounts.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"User Account Management","text":"Properly manage accounts and permissions used by parties in trusted relationships to minimize potential abuse by the party and if the party is compromised by an adversary.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Network Segmentation","text":"Network segmentation can be used to isolate infrastructure components that do not require broad network access.","url":"https://attack.mitre.org/mitigations/M1030"}]},{"id":"T1200","name":"Hardware Additions","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1200","summary":"Adversaries may physically introduce computer accessories, networking hardware, or other computing devices into a system or network that can be used as a vector to gain access.","description":"Adversaries may physically introduce computer accessories, networking hardware, or other computing devices into a system or network that can be used as a vector to gain access. Rather than just connecting and distributing payloads via removable storage (i.e. Replication Through Removable Media), more robust hardware additions can be used to introduce new functionalities and/or features into a system that can then be abused.","platforms":["Windows","Linux","macOS"],"detection":["Application Log Content","Drive Creation","Driver Load","File Creation","Module Load","Network Connection Creation","Network Traffic Flow","Process Creation"],"examples":["DarkVishnya physically connected Bash Bunny, Raspberry Pi, netbooks, and inexpensive laptops to the target organization's environment to access the company’s local network."],"examplesTotal":1,"mitigations":[{"name":"Limit Access to Resource Over Network","text":"Establish network access control policies, such as using device certificates and the 802.1x standard.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Limit Hardware Installation","text":"Block unknown devices and accessories by endpoint security configuration and monitoring agent.","url":"https://attack.mitre.org/mitigations/M1034"}]},{"id":"T1201","name":"Password Policy Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1201","summary":"Adversaries may attempt to access detailed information about the password policy used within an enterprise network or cloud environment.","description":"Adversaries may attempt to access detailed information about the password policy used within an enterprise network or cloud environment. Password policies are a way to enforce complex passwords that are difficult to guess or crack through Brute Force. This information may help the adversary to create a list of common passwords and launch dictionary and/or brute force attacks which adheres to the policy (e.g.","platforms":["Windows","Linux","macOS","IaaS","Network Devices","Identity Provider","SaaS","Office Suite"],"detection":["Active Directory Object Access","Command Execution","Process Creation","User Account Metadata"],"examples":["Chimera has used the NtdsAudit utility to collect information related to accounts and passwords.","CrackMapExec can discover the password policies applied to the target system.","Kwampirs collects password policy information with the command net accounts.","The net accounts and net accounts /domain commands with Net can be used to obtain password policy information."],"examplesTotal":8,"mitigations":[{"name":"Password Policies","text":"Ensure only valid password filters are registered. Filter DLLs must be present in Windows installation directory (C:\\Windows\\System32\\ by default) of a domain controller and/or…","url":"https://attack.mitre.org/mitigations/M1027"}]},{"id":"T1202","name":"Indirect Command Execution","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1202","summary":"Adversaries may abuse utilities that allow for command execution to bypass security restrictions that limit the use of command-line interpreters.","description":"Adversaries may abuse utilities that allow for command execution to bypass security restrictions that limit the use of command-line interpreters. Various Windows utilities may be used to execute commands, possibly without invoking cmd. For example, Forfiles, the Program Compatibility Assistant (pcalua.exe), components of the Windows Subsystem for Linux (WSL), Scriptrunner.exe, as well as other utilities may invoke the execution of programs and commands from a Command and Scripting Interpreter,…","platforms":["Windows"],"detection":["File Creation","Network Connection Creation","Process Creation"],"examples":["Forfiles can be used to subvert controls and possibly conceal command execution by not directly invoking cmd.","Lazarus Group persistence mechanisms have used forfiles.exe to execute .htm files.","RedCurl has used pcalua.exe to obfuscate binary execution and remote connections.","Revenge RAT uses the Forfiles utility to execute commands on the system."],"examplesTotal":4},{"id":"T1203","name":"Exploitation for Client Execution","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1203","summary":"Adversaries may exploit software vulnerabilities in client applications to execute code.","description":"Adversaries may exploit software vulnerabilities in client applications to execute code. Vulnerabilities can exist in software due to unsecure coding practices that can lead to unanticipated behavior. Adversaries can take advantage of certain vulnerabilities through targeted exploitation for the purpose of arbitrary code execution.","platforms":["Linux","macOS","Windows"],"detection":["Application Log Content","File Access","File Creation","File Modification","Network Connection Creation","Network Traffic Flow","Process Creation"],"examples":["During the 3CX Supply Chain Attack, AppleJeus leveraged the Chrome vulnerability, CVE-2022-0609, in combination with a Drive-by Compromise website.","APT12 has exploited multiple vulnerabilities for execution, including Microsoft Office vulnerabilities (CVE-2009-3129, CVE-2012-0158) and vulnerabilities in Adobe Reader and Flash (CVE-2009-4324, CVE-2009-0927, CVE-2011-0609,…","APT28 has exploited Microsoft Office vulnerability CVE-2017-0262 for execution.","APT29 has used multiple software exploits for common client software, like Microsoft Word, Exchange, and Adobe Reader, to gain code execution."],"examplesTotal":60,"mitigations":[{"name":"Exploit Protection","text":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Update Software","text":"Perform regular software updates to mitigate exploitation risk. Keeping software up-to-date with the latest security patches helps prevent adversaries from exploiting known…","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Application Isolation and Sandboxing","text":"Browser sandboxes can be used to mitigate some of the impact of exploitation, but sandbox escapes may still exist.","url":"https://attack.mitre.org/mitigations/M1048"}]},{"id":"T1204","name":"User Execution","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1204","summary":"An adversary may rely upon specific actions by a user in order to gain execution.","description":"An adversary may rely upon specific actions by a user in order to gain execution. Users may be subjected to social engineering to get them to execute malicious code by, for example, opening a malicious document file or link. These user actions will typically be observed as follow-on behavior from forms of Phishing.","platforms":["Linux","Windows","macOS","IaaS","Containers"],"detection":["Application Log Content","Container Creation","Container Start","File Access","File Creation","File Modification","Instance Creation","Instance Start","Network Connection Creation","Network Traffic Content"],"examples":["LAPSUS$ has recruited target organization employees or contractors who provide credentials and approve an associated MFA prompt, or install remote management software onto a corporate workstation, allowing LAPSUS$ to take control of an…","Lumma Stealer has been distributed through a fake CAPTCHA that presents instructions to the victim to open Windows Run window (“Windows Button + R”) and paste clipboard contents (“CTRL + V”) and press “Enter” to execute a Base64-encoded…","Raspberry Robin execution can rely on users directly interacting with malicious LNK files.","Scattered Spider has impersonated organization IT and helpdesk staff to instruct victims to execute commercial remote access tools to gain initial access."],"examplesTotal":5,"mitigations":[{"name":"User Training","text":"Use user training as a way to bring awareness to common phishing and spearphishing techniques and how to raise suspicion for potentially malicious events.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Execution Prevention","text":"Application control may be able to prevent the running of executables masquerading as other files.","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent executable files from running unless they meet a prevalence, age, or trusted list criteria and to prevent…","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Restrict Web-Based Content","text":"If a link is being visited by a user, block unknown or unused files in transit by default that should not be downloaded or by policy from suspicious sites as a best practice to…","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Network Intrusion Prevention","text":"If a link is being visited by a user, network intrusion prevention systems and systems designed to scan and remove malicious downloads can be used to block activity.","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1205","name":"Traffic Signaling","tactics":["Stealth","Persistence","Command and Control"],"url":"https://attack.mitre.org/techniques/T1205","summary":"Adversaries may use traffic signaling to hide open ports or other malicious functionality used for persistence or command and control.","description":"Adversaries may use traffic signaling to hide open ports or other malicious functionality used for persistence or command and control. Traffic signaling involves the use of a magic value or sequence that must be sent to a system to trigger a special response, such as opening a closed port or executing a malicious task. This may take the form of sending a series of packets with certain characteristics before a port will be opened that the adversary can use for command and control.","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["BRUSHFIRE has monitored inbound VPN traffic to compromised appliances until specific inbound packets contain a specific magic string/pattern instead of external beaconing.","BUSHWALK can modify the DSUserAgentCap.pm Perl module on Ivanti Connect Secure VPNs and either activate or deactivate depending on the value of the user agent in incoming HTTP requests.","Chaos provides a reverse shell is triggered upon receipt of a packet with a special string, sent to any port.","During Cutting Edge, threat actors sent a magic 48-byte sequence to enable the PITSOCK backdoor to communicate via the /tmp/clientsDownload.sock socket."],"examplesTotal":22,"mitigations":[{"name":"Filter Network Traffic","text":"Mitigation of some variants of this technique could be achieved through the use of stateful firewalls, depending upon how it is implemented.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Disable or Remove Feature or Program","text":"Disable Wake-on-LAN if it is not needed within an environment.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1207","name":"Rogue Domain Controller","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1207","summary":"Adversaries may register a rogue Domain Controller to enable manipulation of Active Directory data.","description":"Adversaries may register a rogue Domain Controller to enable manipulation of Active Directory data. DCShadow may be used to create a rogue Domain Controller (DC). DCShadow is a method of manipulating Active Directory (AD) data, including objects and schemas, by registering (or reusing an inactive registration) and simulating the behavior of a DC. Once registered, a rogue DC may be able to inject and replicate changes into AD infrastructure for any domain object, including credentials and keys.","platforms":["Windows"],"detection":["Active Directory Credential Request","Active Directory Object Access","Active Directory Object Creation","Active Directory Object Modification","Network Traffic Content"],"examples":["Mimikatz’s LSADUMP::DCShadow module can be used to make AD updates by temporarily setting a computer to be a DC."],"examplesTotal":1},{"id":"T1210","name":"Exploitation of Remote Services","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1210","summary":"Adversaries may exploit remote services to gain unauthorized access to internal systems once inside of a network.","description":"Adversaries may exploit remote services to gain unauthorized access to internal systems once inside of a network. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code. A common goal for post-compromise exploitation of remote services is for lateral movement to enable access to a remote system.","platforms":["Linux","Windows","macOS","ESXi"],"detection":["Application Log Content","File Creation","Module Load","Network Connection Creation","Network Traffic Content","Process Access","Process Creation"],"examples":["APT28 exploited a Windows SMB Remote Code Execution Vulnerability to conduct lateral movement.","Bad Rabbit used the EternalRomance SMB exploit to spread through victim networks.","Conficker exploited the MS08-067 Windows vulnerability for remote code execution through a crafted RPC request.","Dragonfly has exploited a Windows Netlogon vulnerability (CVE-2020-1472) to obtain access to Windows Active Directory servers."],"examplesTotal":24,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Minimize available services to only those that are necessary.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Vulnerability Scanning","text":"Regularly scan the internal network for available services to identify new and potentially vulnerable services.","url":"https://attack.mitre.org/mitigations/M1016"},{"name":"Exploit Protection","text":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Network Segmentation","text":"Segment networks and systems appropriately to reduce access to critical systems and services to controlled methods.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Threat Intelligence Program","text":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization.","url":"https://attack.mitre.org/mitigations/M1019"}]},{"id":"T1211","name":"Exploitation for Stealth","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1211","summary":"Adversaries may exploit vulnerabilities to evade detection by hiding activity, suppressing logging, or operating within trusted or unmonitored components.","description":"Adversaries may exploit vulnerabilities to evade detection by hiding activity, suppressing logging, or operating within trusted or unmonitored components. Adversaries may exploit a system or application vulnerability to avoid detection while maintaining access within an environment. Exploitation occurs when an adversary leverages a programming flaw to execute code in a manner that minimizes visibility or blends in with legitimate activity.","platforms":["Linux","Windows","macOS","SaaS","IaaS"],"detection":["Application Log Content","Module Load","Process Creation"],"examples":["APT28 has used CVE-2015-4902 to bypass security features.","Velvet Ant exploited CVE-2024-20399 in Cisco Switches to which the threat actor was already able to authenticate in order to escape the NX-OS command line interface and gain access to the underlying operating system for arbitrary command…"],"examplesTotal":2,"mitigations":[{"name":"Exploit Protection","text":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Update Software","text":"Update software regularly by employing patch management for internal enterprise endpoints and servers.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Threat Intelligence Program","text":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization.","url":"https://attack.mitre.org/mitigations/M1019"},{"name":"Application Isolation and Sandboxing","text":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing.","url":"https://attack.mitre.org/mitigations/M1048"}]},{"id":"T1212","name":"Exploitation for Credential Access","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1212","summary":"Adversaries may exploit software vulnerabilities in an attempt to collect credentials.","description":"Adversaries may exploit software vulnerabilities in an attempt to collect credentials. Exploitation of a software vulnerability occurs when an adversary takes advantage of a programming error in a program, service, or within the operating system software or kernel itself to execute adversary-controlled code.","platforms":["Linux","Windows","macOS","Identity Provider"],"detection":["Application Log Content","Process Access","Process Creation","User Account Authentication"],"examples":["Leviathan exploited vulnerable network appliances during Leviathan Australian Intrusions, leading to the collection and exfiltration of valid credentials.","UNC3886 exploited CVE-2022-22948 in VMware vCenter to obtain encrypted credentials from the vCenter postgresDB."],"examplesTotal":2,"mitigations":[{"name":"Exploit Protection","text":"Security applications that look for behavior used during exploitation such as Windows Defender Exploit Guard (WDEG) and the Enhanced Mitigation Experience Toolkit (EMET) can be…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Update Software","text":"Update software regularly by employing patch management for internal enterprise endpoints and servers.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Application Developer Guidance","text":"Application developers should consider taking measures to validate authentication requests by enabling one-time passwords, providing timestamps or sequence numbers for messages…","url":"https://attack.mitre.org/mitigations/M1013"},{"name":"Threat Intelligence Program","text":"Develop a robust cyber threat intelligence capability to determine what types and levels of threat may use software exploits and 0-days against a particular organization.","url":"https://attack.mitre.org/mitigations/M1019"},{"name":"Application Isolation and Sandboxing","text":"Make it difficult for adversaries to advance their operation through exploitation of undiscovered or unpatched vulnerabilities by using sandboxing.","url":"https://attack.mitre.org/mitigations/M1048"}]},{"id":"T1213","name":"Data from Information Repositories","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1213","summary":"Adversaries may leverage information repositories to mine valuable information.","description":"Adversaries may leverage information repositories to mine valuable information. Information repositories are tools that allow for storage of information, typically to facilitate collaboration or information sharing between users, and can store a wide variety of data that may aid adversaries in further objectives, such as Credential Access, Lateral Movement, or Defense Evasion, or direct access to the target information.","platforms":["Linux","Windows","macOS","SaaS","IaaS","Office Suite"],"detection":["Application Log Content","Cloud Service Modification","Cloud Storage Access","Command Execution","File Access","Network Connection Creation","Network Share Access","Process Creation"],"examples":["APT28 has collected files from various information repositories.","Raccoon Stealer gathers information from repositories associated with cryptocurrency wallets and the Telegram messaging service.","During the SolarWinds Compromise, APT29 accessed victims' internal knowledge repositories (wikis) to view sensitive corporate information on products, services, and internal business operations.","Troll Stealer gathers information from the Government Public Key Infrastructure (GPKI) folder, associated with South Korean government public key infrastructure, on infected systems."],"examplesTotal":4,"mitigations":[{"name":"Multi-factor Authentication","text":"Use two or more pieces of evidence to authenticate to a system; such as username and password in addition to a token from a physical smart card or token generator.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Out-of-Band Communications Channel","text":"Create plans for leveraging a secure out-of-band communications channel, rather than existing in-network chat applications, in case of a security incident.","url":"https://attack.mitre.org/mitigations/M1060"},{"name":"User Training","text":"Develop and publish policies that define acceptable information to be stored in repositories.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Software Configuration","text":"Consider implementing data retention policies to automate periodically archiving and/or deleting data that is no longer needed.","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"User Account Management","text":"Enforce the principle of least-privilege. Consider implementing access control mechanisms that include both authentication and authorization.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1216","name":"System Script Proxy Execution","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1216","summary":"Adversaries may use trusted scripts, often signed with certificates, to proxy the execution of malicious files.","description":"Adversaries may use trusted scripts, often signed with certificates, to proxy the execution of malicious files. Several Microsoft signed scripts that have been downloaded from Microsoft or are default on Windows installations can be used to proxy execution of other files. This behavior may be abused by adversaries to execute malicious files that could bypass application control and signature validation on systems.","platforms":["Windows"],"detection":["Command Execution","File Creation","Module Load","Process Access","Process Creation"],"mitigations":[{"name":"Execution Prevention","text":"Certain signed scripts that can be used to execute other programs may not be necessary within a given environment.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1217","name":"Browser Information Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1217","summary":"Adversaries may enumerate information about browsers to learn more about compromised environments.","description":"Adversaries may enumerate information about browsers to learn more about compromised environments. Data saved by browsers (such as bookmarks, accounts, and browsing history) may reveal a variety of personal information about users (e.g., banking sites, relationships/interests, social media, etc.) as well as details about internal network resources such as servers, tools/dashboards, or other related infrastructure.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Access","File Creation","Process Creation"],"examples":["During the 3CX Supply Chain Attack, AppleJeus leveraged ICONICSTEALER to steal browser information to include browser history located on the infected host.","APT38 has collected browser bookmark information to learn more about compromised hosts, obtain personal information about users, and acquire details about internal network resources.","BeaverTail has searched the victim device for browser extensions including those commonly associated with cryptocurrency wallets.","Calisto collects information on bookmarks from Google Chrome."],"examplesTotal":29},{"id":"T1218","name":"System Binary Proxy Execution","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1218","summary":"Adversaries may bypass process and/or signature-based defenses by proxying execution of malicious content with signed, or otherwise trusted, binaries.","description":"Adversaries may bypass process and/or signature-based defenses by proxying execution of malicious content with signed, or otherwise trusted, binaries. Binaries used in this technique are often Microsoft-signed files, indicating that they have been either downloaded from Microsoft or are already native in the operating system. Binaries signed with trusted digital certificates can typically execute on Windows systems protected by digital signature validation.","platforms":["Linux","macOS","Windows"],"detection":["Module Load","Network Connection Creation","Process Creation"],"examples":["Lazarus Group lnk files used for persistence have abused the Windows Update Client (wuauclt.exe) to execute a malicious DLL.","Volt Typhoon has used native tools and processes including living off the land binaries or “LOLBins\" to maintain and expand access to the victim networks."],"examplesTotal":2,"mitigations":[{"name":"Exploit Protection","text":"Microsoft's Enhanced Mitigation Experience Toolkit (EMET) Attack Surface Reduction (ASR) feature can be used to block methods of using using trusted binaries to bypass application…","url":"https://attack.mitre.org/mitigations/M1050"},{"name":"Filter Network Traffic","text":"Use network appliances to filter ingress or egress traffic and perform protocol-based filtering. Configure software on endpoints to filter network traffic.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Privileged Account Management","text":"Restrict execution of particularly vulnerable binaries to privileged accounts or groups that need to use it to lessen the opportunities for malicious usage.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Execution Prevention","text":"Consider using application control to prevent execution of binaries that are susceptible to abuse and not required for a given system or network.","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Disable or Remove Feature or Program","text":"Many native binaries may not be necessary within a given environment.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1219","name":"Remote Access Tools","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1219","summary":"An adversary may use legitimate remote access tools to establish an interactive command and control channel within a network.","description":"An adversary may use legitimate remote access tools to establish an interactive command and control channel within a network. Remote access tools create a session between two trusted hosts through a graphical interface, a command line interaction, a protocol tunnel via development or management software, or hardware-level access such as KVM (Keyboard, Video, Mouse) over IP solutions.","platforms":["Linux","macOS","Windows"],"detection":["File Creation","Network Connection Creation","Process Creation","Service Creation","Windows Registry Key Creation","Windows Registry Key Modification"],"examples":["Akira uses legitimate utilities such as AnyDesk and PuTTy for maintaining remote access to victim environments.","BlackByte has used tools such as AnyDesk in victim environments.","Carbanak has a plugin for VNC and Ammyy Admin Tool.","Carbanak used legitimate programs such as AmmyyAdmin and Team Viewer for remote interactive C2 to target systems."],"examplesTotal":21,"mitigations":[{"name":"Execution Prevention","text":"Use application control to mitigate installation and use of unapproved software that can be used for remote access.","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Filter Network Traffic","text":"Properly configure firewalls, application firewalls, and proxies to limit outgoing traffic to sites and services used by remote access software.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Limit Hardware Installation","text":"Block the use of IP-based KVM devices within the network if they are not required.","url":"https://attack.mitre.org/mitigations/M1034"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures may be able to prevent traffic to remote access services.","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Disable or Remove Feature or Program","text":"Consider disabling unnecessary remote connection functionality, including both unapproved software installations and specific features built into supported applications.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1220","name":"XSL Script Processing","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1220","summary":"Adversaries may bypass application control and obscure execution of code by embedding scripts inside XSL files.","description":"Adversaries may bypass application control and obscure execution of code by embedding scripts inside XSL files. Extensible Stylesheet Language (XSL) files are commonly used to describe the processing and rendering of data within XML files. To support complex operations, the XSL standard includes support for embedded scripting in various languages. Adversaries may abuse this functionality to execute arbitrary files while potentially bypassing application control.","platforms":["Windows"],"detection":["Module Load","Process Creation"],"examples":["Astaroth executes embedded JScript or VBScript in an XSL stylesheet located on a remote domain.","Cobalt Group used msxsl.exe to bypass AppLocker and to invoke Jscript code from an XSL file.","Higaisa used an XSL file to run VBScript code.","During Operation Dream Job, Lazarus Group used a remote XSL script to download a Base64-encoded DLL custom downloader."],"examplesTotal":4,"mitigations":[{"name":"Execution Prevention","text":"If msxsl.exe is unnecessary, then block its execution to prevent abuse by adversaries.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1221","name":"Template Injection","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1221","summary":"Adversaries may create or modify references in user document templates to conceal malicious code or force authentication attempts.","description":"Adversaries may create or modify references in user document templates to conceal malicious code or force authentication attempts. For example, Microsoft’s Office Open XML (OOXML) specification defines an XML-based format for Office documents (.docx, xlsx, .pptx) to replace older binary formats (.doc, .xls, .ppt). OOXML files are packed together ZIP archives compromised of various XML files, referred to as parts, containing properties that collectively define how a document is rendered.","platforms":["Windows"],"detection":["Network Connection Creation","Process Creation"],"examples":["APT28 used weaponized Microsoft Word documents abusing the remote template function to retrieve a malicious macro.","Chaes changed the template target of the settings.xml file embedded in the Word document and populated that field with the downloaded URL of the next payload.","Confucius has used a weaponized Microsoft Word document with an embedded RTF exploit.","DarkHydrus used an open-source tool, Phishery, to inject malicious remote template URLs into Microsoft Word documents and then sent them to victims to enable Forced Authentication."],"examplesTotal":12,"mitigations":[{"name":"Antivirus/Antimalware","text":"Network/Host intrusion prevention systems, antivirus, and detonation chambers can be employed to prevent documents from fetching and/or executing malicious payloads.","url":"https://attack.mitre.org/mitigations/M1049"},{"name":"Network Intrusion Prevention","text":"Network/Host intrusion prevention systems, antivirus, and detonation chambers can be employed to prevent documents from fetching and/or executing malicious payloads.","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"User Training","text":"Train users to identify social engineering techniques and spearphishing emails that could be used to deliver malicious documents.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Disable or Remove Feature or Program","text":"Consider disabling Microsoft Office macros/active content to prevent the execution of malicious payloads in documents , though this setting may not mitigate the Forced…","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1222","name":"File and Directory Permissions Modification","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1222","summary":"Adversaries may modify file or directory permissions/attributes to evade access control lists (ACLs) and access protected files.","description":"Adversaries may modify file or directory permissions/attributes to evade access control lists (ACLs) and access protected files. File and directory permissions are commonly managed by ACLs configured by the file or directory owner, or users with the appropriate permissions. File and directory ACL implementations vary by platform, but generally explicitly designate which users or groups can perform which actions (read, write, execute, etc.).","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Active Directory Object Modification","Command Execution","File Creation","File Metadata","Process Creation"],"examples":["Qilin can use symbolic links to redirect file paths for remote and local objects and can use chmod +x to make its payload binary executable."],"examplesTotal":1,"mitigations":[{"name":"Restrict File and Directory Permissions","text":"Applying more restrictive permissions to files and directories could prevent adversaries from modifying their access control lists.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"Privileged Account Management","text":"Ensure critical system files as well as those known to be abused by adversaries have restrictive permissions and are owned by an appropriately privileged account, especially if…","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1480","name":"Execution Guardrails","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1480","summary":"Adversaries may use execution guardrails to constrain execution or actions based on adversary supplied and environment specific conditions that are expected to be present on the target.","description":"Adversaries may use execution guardrails to constrain execution or actions based on adversary supplied and environment specific conditions that are expected to be present on the target. Guardrails ensure that a payload only executes against an intended target and reduces collateral damage from an adversary’s campaign.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Command Execution","File Access","File Creation","Logon Session Creation","Module Load","Network Connection Creation","Process Creation","Process Modification","User Account Authentication","WMI Creation"],"examples":["APT-C-36 has used geolocation filtering in malware delivery to redirect traffic not coming from a targeted region or country, such as Ecuador or Colombia, to legitimate sites.","Akira _v2 will fail to execute if the targeted /vmfs/volumes/ path does not exist or is not defined.","Anchor can terminate itself if specific execution flags are not present.","Apostle's ransomware variant requires that a base64-encoded argument is passed when executed, that is used as the Public Key for subsequent encryption operations."],"examplesTotal":47,"mitigations":[{"name":"Do Not Mitigate","text":"Execution Guardrails likely should not be mitigated with preventative controls because it may protect unintended targets from being compromised.","url":"https://attack.mitre.org/mitigations/M1055"}]},{"id":"T1482","name":"Domain Trust Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1482","summary":"Adversaries may attempt to gather information on domain trust relationships that may be used to identify lateral movement opportunities in Windows multi-domain/forest environments.","description":"Adversaries may attempt to gather information on domain trust relationships that may be used to identify lateral movement opportunities in Windows multi-domain/forest environments. Domain trusts provide a mechanism for a domain to allow access to resources based on the authentication procedures of another domain. Domain trusts allow the users of the trusted domain to access resources in the trusting domain.","platforms":["Windows"],"detection":["Active Directory Object Access","Command Execution","Module Load","Process Access","Process Creation"],"examples":["AdFind can gather information about organizational units (OUs) and domain trusts from Active Directory.","Akira uses the built-in Nltest utility or tools such as AdFind to enumerate Active Directory trusts in victim environments.","BADHATCH can use nltest.exe /domain_trusts to discover domain trust relationships on a compromised machine.","Bazar can use Nltest tools to obtain information about the domain."],"examplesTotal":33,"mitigations":[{"name":"Audit","text":"Map the trusts within existing domains/forests and keep trust relationships to a minimum.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Network Segmentation","text":"Employ network segmentation for sensitive domains..","url":"https://attack.mitre.org/mitigations/M1030"}]},{"id":"T1484","name":"Domain or Tenant Policy Modification","tactics":["Defense Impairment","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1484","summary":"Adversaries may modify the configuration settings of a domain or identity tenant to evade defenses and/or escalate privileges in centrally managed environments.","description":"Adversaries may modify the configuration settings of a domain or identity tenant to evade defenses and/or escalate privileges in centrally managed environments. Such services provide a centralized means of managing identity resources such as devices and accounts, and often include configuration settings that may apply between domains or tenants such as trust relationships, identity syncing, or identity federation.","platforms":["Windows","Identity Provider"],"detection":["Active Directory Object Modification","Application Log Content","File Modification","Process Creation","User Account Authentication"],"mitigations":[{"name":"Audit","text":"Identify and correct GPO permissions abuse opportunities (ex: GPO modification privileges) using auditing tools such as BloodHound (version 1.5.1 and later).","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Privileged Account Management","text":"Use least privilege and protect administrative access to the Domain Controller and Active Directory Federation Services (AD FS) server.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"User Account Management","text":"Consider implementing WMI and security filtering to further tailor which users and computers a GPO will apply to.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1485","name":"Data Destruction","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1485","summary":"Adversaries may destroy data and files on specific systems or in large numbers on a network to interrupt availability to systems, services, and network resources.","description":"Adversaries may destroy data and files on specific systems or in large numbers on a network to interrupt availability to systems, services, and network resources. Data destruction is likely to render stored data irrecoverable by forensic techniques through overwriting files or data on local and remote drives.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Windows"],"detection":["Cloud Storage Deletion","Command Execution","File Creation","File Deletion","Process Creation","Process Termination","Volume Deletion"],"examples":["During the 2022 Ukraine Electric Power Attack, Sandworm Team deployed CaddyWiper on the victim’s IT environment systems to wipe files related to the OT capabilities, along with mapped drives, and physical drive partitions.","During the 2025 Poland Wiper Attacks, the adversaries utilized wiper malware to overwrite files using a 16-byte buffer that fully overwrites files 16 bytes or smaller or partially overwrites files greater than 16 bytes to speed up the…","APT38 has used a custom secure delete function to make deleted files unrecoverable.","AcidPour can perform an in-depth wipe of victim filesystems and attached storage devices through either data overwrite or calling various IOCTLS to erase them, similar to AcidRain."],"examplesTotal":36,"mitigations":[{"name":"Multi-factor Authentication","text":"Implement multi-factor authentication (MFA) delete for cloud storage resources, such as AWS S3 buckets, to prevent unauthorized deletion of critical data and infrastructure.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Data Backup","text":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data.","url":"https://attack.mitre.org/mitigations/M1053"},{"name":"User Account Management","text":"In cloud environments, limit permissions to modify cloud bucket lifecycle policies (e.g., PutLifecycleConfiguration in AWS) to only those accounts that require it.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1486","name":"Data Encrypted for Impact","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1486","summary":"Adversaries may encrypt data on target systems or on large numbers of systems in a network to interrupt availability to system and network resources.","description":"Adversaries may encrypt data on target systems or on large numbers of systems in a network to interrupt availability to system and network resources. They can attempt to render stored data inaccessible by encrypting files or data on local and remote drives and withholding access to a decryption key.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"detection":["Cloud Storage Modification","Command Execution","File Creation","File Modification","Process Creation"],"examples":["APT38 has used Hermes ransomware to encrypt files with AES256.","APT41 used a ransomware called Encryptor RaaS to encrypt files on the targeted systems and provide a ransom note to the user. APT41 also used Microsoft Bitlocker to encrypt workstations and Jetico’s BestCrypt to encrypt servers.","Akira encrypts files in victim environments as part of ransomware operations.","Akira can encrypt victim filesystems for financial extortion purposes including through the use of the ChaCha20 and ChaCha8 stream ciphers."],"examplesTotal":84,"mitigations":[{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable cloud-delivered protection and Attack Surface Reduction (ASR) rules to block the execution of files that resemble ransomware.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Data Backup","text":"Consider implementing IT disaster recovery plans that contain procedures for regularly taking and testing data backups that can be used to restore organizational data.","url":"https://attack.mitre.org/mitigations/M1053"}]},{"id":"T1489","name":"Service Stop","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1489","summary":"Adversaries may stop or disable services on a system to render those services unavailable to legitimate users.","description":"Adversaries may stop or disable services on a system to render those services unavailable to legitimate users. Stopping critical services or processes can inhibit or stop response to an incident or aid in the adversary's overall objectives to cause damage to the environment. Adversaries may accomplish this by disabling individual services of high importance to an organization, such as MSExchangeIS, which will make Exchange content inaccessible.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"detection":["File Deletion","Logon Session Metadata","Process Creation","Process Termination","Service Creation","Service Metadata"],"examples":["Akira _v2 can stop running virtual machines.","Avaddon looks for and attempts to stop database processes.","AvosLocker has terminated specific processes before encryption.","BRICKSTORM has terminated an existing process to ensure that its own new process can execute."],"examplesTotal":54,"mitigations":[{"name":"Network Segmentation","text":"Operate intrusion detection, analysis, and response systems on a separate network from the production environment to lessen the chances that an adversary can see and interfere…","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"User Account Management","text":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service configurations.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Out-of-Band Communications Channel","text":"Develop and enforce security policies that include the use of out-of-band communication channels for critical communications during a security incident.","url":"https://attack.mitre.org/mitigations/M1060"},{"name":"Restrict Registry Permissions","text":"Ensure proper registry permissions are in place to inhibit adversaries from disabling or interfering with critical services.","url":"https://attack.mitre.org/mitigations/M1024"},{"name":"Restrict File and Directory Permissions","text":"Ensure proper process and file permissions are in place to inhibit adversaries from disabling or interfering with critical services.","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1490","name":"Inhibit System Recovery","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1490","summary":"Adversaries may delete or remove built-in data and turn off services designed to aid in the recovery of a corrupted system to prevent recovery.","description":"Adversaries may delete or remove built-in data and turn off services designed to aid in the recovery of a corrupted system to prevent recovery. This may deny access to available backups and recovery options. Operating systems may contain features that can help fix corrupted systems, such as a backup catalog, volume shadow copies, and automatic repair features. Adversaries may disable or delete system recovery features to augment the effects of Data Destruction and Data Encrypted for Impact.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Cloud Storage Deletion","Command Execution","File Deletion","Process Creation","Service Metadata","Snapshot Deletion","Windows Registry Key Modification"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries deleted Windows Volume Shadow Copies using vssadmin delete shadows.","Akira will delete system volume shadow copies via PowerShell commands.","Avaddon deletes backups and shadow copies using native system tools.","BFG Agonizer wipes the boot sector of infected machines to inhibit system recovery."],"examplesTotal":56,"mitigations":[{"name":"Execution Prevention","text":"Consider using application control configured to block execution of utilities such as diskshadow.exe that may not be required for a given system or network to prevent potential…","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Operating System Configuration","text":"Consider technical controls to prevent the disabling of services or deletion of files involved in system recovery.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"User Account Management","text":"Limit the user accounts that have access to backups to only those required. In AWS environments, consider using Service Control Policies to restrict API calls to delete backups,…","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Data Backup","text":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data.","url":"https://attack.mitre.org/mitigations/M1053"}]},{"id":"T1491","name":"Defacement","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1491","summary":"Adversaries may modify visual content available internally or externally to an enterprise network, thus affecting the integrity of the original content.","description":"Adversaries may modify visual content available internally or externally to an enterprise network, thus affecting the integrity of the original content. Reasons for Defacement include delivering messaging, intimidation, or claiming (possibly false) credit for an intrusion. Disturbing or offensive images may be used as a part of Defacement in order to cause user discomfort, or to pressure compliance with accompanying messages.","platforms":["Windows","IaaS","Linux","macOS","ESXi"],"detection":["Application Log Content","Cloud Storage Access","File Creation","File Modification","Network Traffic Content","Process Creation"],"mitigations":[{"name":"Data Backup","text":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data.","url":"https://attack.mitre.org/mitigations/M1053"}]},{"id":"T1495","name":"Firmware Corruption","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1495","summary":"Adversaries may overwrite or corrupt the flash memory contents of system BIOS or other firmware in devices attached to a system in order to render them inoperable or unable to boot, thus denying the availability to use the devices…","description":"Adversaries may overwrite or corrupt the flash memory contents of system BIOS or other firmware in devices attached to a system in order to render them inoperable or unable to boot, thus denying the availability to use the devices and/or the system. Firmware is software that is loaded and executed from non-volatile memory on hardware devices in order to initialize and manage device functionality. These devices may include the motherboard, hard drive, or video cards.","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["Driver Load","Firmware Modification","Network Traffic Content","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, adversaries performed a factory-reset on compromised devices that hampered forensic investigations.","Bad Rabbit has used an executable that installs a modified bootloader to prevent normal boot-up.","TrickBot module \"Trickboot\" can write or erase the UEFI/BIOS firmware of a compromised device."],"examplesTotal":3,"mitigations":[{"name":"Update Software","text":"Patch the BIOS and other firmware as necessary to prevent successful use of known vulnerabilities.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Privileged Account Management","text":"Prevent adversary access to privileged accounts or access necessary to replace system firmware.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Boot Integrity","text":"Check the integrity of the existing BIOS and device firmware to determine if it is vulnerable to modification.","url":"https://attack.mitre.org/mitigations/M1046"}]},{"id":"T1496","name":"Resource Hijacking","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1496","summary":"Adversaries may leverage the resources of co-opted systems to complete resource-intensive tasks, which may impact system and/or hosted service availability.","description":"Adversaries may leverage the resources of co-opted systems to complete resource-intensive tasks, which may impact system and/or hosted service availability. Resource hijacking may take a number of different forms. For example, adversaries may: Leverage compute resources in order to mine cryptocurrency Sell network bandwidth to proxy networks Generate SMS traffic for profit Abuse cloud-based messaging services to send large quantities of spam messages In some cases, adversaries may leverage…","platforms":["Windows","IaaS","Linux","macOS","Containers","SaaS"],"detection":["Application Log Content","Cloud Service Modification","Host Status","Instance Start","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"]},{"id":"T1497","name":"Virtualization/Sandbox Evasion","tactics":["Stealth","Discovery"],"url":"https://attack.mitre.org/techniques/T1497","summary":"Adversaries may employ various means to detect and avoid virtualization and analysis environments.","description":"Adversaries may employ various means to detect and avoid virtualization and analysis environments. This may include changing behaviors based on the results of checks for the presence of artifacts indicative of a virtual machine environment (VME) or sandbox. If the adversary detects a VME, they may alter their malware to disengage from the victim or conceal the core functions of the implant. They may also search for VME artifacts before dropping secondary or additional payloads.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","Module Load","Process Creation"],"examples":["Agent Tesla has the ability to perform anti-sandboxing and anti-virtualization checks.","Bazar can attempt to overload sandbox analysis by sending 1550 calls to printf.","Bisonal can check to determine if the compromised system is running on VMware.","Black Basta can make a random number of calls to the kernel32.beep function to hinder log analysis."],"examplesTotal":26},{"id":"T1498","name":"Network Denial of Service","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1498","summary":"Adversaries may perform Network Denial of Service (DoS) attacks to degrade or block the availability of targeted resources to users.","description":"Adversaries may perform Network Denial of Service (DoS) attacks to degrade or block the availability of targeted resources to users. Network DoS can be performed by exhausting the network bandwidth services rely on. Example resources include specific websites, email services, DNS, and web-based applications. Adversaries have been observed conducting network DoS attacks for political purposes and to support other malicious activities, including distraction, hacktivism, and extortion.","platforms":["Windows","IaaS","Linux","macOS","Containers"],"detection":["Network Connection Creation","Network Traffic Flow","Process Creation"],"examples":["In 2016, APT28 conducted a distributed denial of service (DDoS) attack against the World Anti-Doping Agency.","Lucifer can execute TCP, UDP, and HTTP denial of service (DoS) attacks.","NKAbuse enables multiple types of network denial of service capabilities across several protocols post-installation."],"examplesTotal":3,"mitigations":[{"name":"Filter Network Traffic","text":"When flood volumes exceed the capacity of the network connection being targeted, it is typically necessary to intercept the incoming traffic upstream to filter out the attack…","url":"https://attack.mitre.org/mitigations/M1037"}]},{"id":"T1499","name":"Endpoint Denial of Service","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1499","summary":"Adversaries may perform Endpoint Denial of Service (DoS) attacks to degrade or block the availability of services to users.","description":"Adversaries may perform Endpoint Denial of Service (DoS) attacks to degrade or block the availability of services to users. Endpoint DoS can be performed by exhausting the system resources those services are hosted on or exploiting the system to cause a persistent crash condition. Example services include websites, email services, DNS, and web-based applications.","platforms":["Windows","Linux","macOS","Containers","IaaS"],"detection":["Application Log Content","Host Status","Instance Start","Network Traffic Flow","Process Creation"],"examples":["OnionDuke has the capability to use a Denial of Service module.","Sandworm Team temporarily disrupted service to Georgian government, non-government, and private sector websites after compromising a Georgian web hosting provider in 2019.","ZxShell has a feature to perform SYN flood attack on a host."],"examplesTotal":3,"mitigations":[{"name":"Filter Network Traffic","text":"Leverage services provided by Content Delivery Networks (CDN) or providers specializing in DoS mitigations to filter traffic upstream from services.","url":"https://attack.mitre.org/mitigations/M1037"}]},{"id":"T1505","name":"Server Software Component","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1505","summary":"Adversaries may abuse legitimate extensible development features of servers to establish persistent access to systems.","description":"Adversaries may abuse legitimate extensible development features of servers to establish persistent access to systems. Enterprise server applications may include features that allow developers to write and install software or scripts to extend the functionality of the main application. Adversaries may install malicious components to extend and abuse server applications.","platforms":["Windows","Linux","macOS","Network Devices","ESXi"],"detection":["Application Log Content","Command Execution","Network Traffic Content","Network Traffic Flow","Process Creation","Scheduled Job Creation"],"mitigations":[{"name":"Code Signing","text":"Ensure all application component binaries are signed by the correct application developers.","url":"https://attack.mitre.org/mitigations/M1045"},{"name":"Audit","text":"Regularly check component software on critical services that adversaries may target for persistence to verify the integrity of the systems and identify if unexpected changes have…","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Restrict Registry Permissions","text":"Consider using Group Policy to configure and block modifications to service and other critical server parameters in the Registry.","url":"https://attack.mitre.org/mitigations/M1024"},{"name":"Disable or Remove Feature or Program","text":"Consider disabling software components from servers when possible to prevent abuse by adversaries.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Boot Integrity","text":"Enabling secure boot allows validation of software and drivers during initial system boot.","url":"https://attack.mitre.org/mitigations/M1046"}]},{"id":"T1518","name":"Software Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1518","summary":"Adversaries may attempt to get a listing of software and software versions that are installed on a system or in a cloud environment.","description":"Adversaries may attempt to get a listing of software and software versions that are installed on a system or in a cloud environment. Adversaries may use the information from Software Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"detection":["Application Log Content","Cloud Service Enumeration","Command Execution","Process Creation"],"examples":["BRONZE BUTLER has used tools to enumerate software installed on an infected host.","Bazar can query the Registry for installed applications.","Bundlore has the ability to enumerate what browser is being used as well as version information for Safari.","CharmPower can list the installed applications on a compromised host."],"examplesTotal":52},{"id":"T1525","name":"Implant Internal Image","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1525","summary":"Adversaries may implant cloud or container images with malicious code to establish persistence after gaining access to an environment.","description":"Adversaries may implant cloud or container images with malicious code to establish persistence after gaining access to an environment. Amazon Web Services (AWS) Amazon Machine Images (AMIs), Google Cloud Platform (GCP) Images, and Azure Images as well as popular container runtimes such as Docker can be implanted or backdoored. Unlike Upload Malware, this technique focuses on adversaries implanting an image in a registry within a victim’s environment.","platforms":["IaaS","Containers"],"detection":["Image Creation","Image Modification","Instance Start"],"mitigations":[{"name":"Code Signing","text":"Several cloud service providers support content trust models that require container images be signed by trusted sources.","url":"https://attack.mitre.org/mitigations/M1045"},{"name":"Privileged Account Management","text":"Limit permissions associated with creating and modifying platform images or containers based on the principle of least privilege.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Audit","text":"Periodically check the integrity of images and containers used in cloud deployments to ensure they have not been modified to include malicious software.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1526","name":"Cloud Service Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1526","summary":"An adversary may attempt to enumerate the cloud services running on a system after gaining access.","description":"An adversary may attempt to enumerate the cloud services running on a system after gaining access. These methods can differ from platform-as-a-service (PaaS), to infrastructure-as-a-service (IaaS), or software-as-a-service (SaaS). Many services exist throughout the various cloud providers and can include Continuous Integration and Continuous Delivery (CI/CD), Lambda Functions, Entra ID, etc.","platforms":["IaaS","Identity Provider","Office Suite","SaaS"],"detection":["Cloud Service Enumeration","Logon Session Creation","User Account Metadata"],"examples":["AADInternals can enumerate information about a variety of cloud services, such as Office 365 and Sharepoint instances or OpenID Configurations.","Pacu can enumerate AWS services, such as CloudTrail and CloudWatch.","ROADTools can enumerate Azure AD applications and service principals.","Storm-0501 has discovered the victim environment’s protections to include Azure policies, resource locks, and Azure Storage immutability policies."],"examplesTotal":5},{"id":"T1528","name":"Steal Application Access Token","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1528","summary":"Adversaries can steal application access tokens as a means of acquiring credentials to access remote systems and resources.","description":"Adversaries can steal application access tokens as a means of acquiring credentials to access remote systems and resources. Application access tokens are used to make authorized API requests on behalf of a user or service and are commonly used as a way to access resources in cloud and container-based applications and software-as-a-service (SaaS).","platforms":["Containers","IaaS","Identity Provider","Office Suite","SaaS"],"detection":["Application Log Content","Cloud Service Enumeration","Cloud Service Modification","Cloud Storage Access","File Access","User Account Authentication"],"examples":["AADInternals can steal users’ access tokens via phishing emails containing malicious links.","APT28 has used several malicious applications to steal user OAuth access tokens including applications masquerading as \"Google Defender\" \"Google Email Protection,\" and \"Google Scanner\" for Gmail users.","APT29 uses stolen tokens to access victim accounts, without needing a password.","Leviathan abused access to compromised appliances to collect JSON Web Tokens (JWTs), used for creating virtual desktop sessions, during Leviathan Australian Intrusions."],"examplesTotal":7,"mitigations":[{"name":"Restrict Web-Based Content","text":"Administrators can block end-user consent to OAuth applications, disabling users from authorizing third-party apps through OAuth 2.0 and forcing administrative consent for all…","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Audit","text":"Administrators should audit all cloud and container accounts to ensure that they are necessary and that the permissions granted to them are appropriate.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"User Training","text":"Users need to be trained to not authorize third-party applications they don’t recognize. The user should pay particular attention to the redirect URL: if the URL is a misspelled…","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"User Account Management","text":"Enforce role-based access control to limit accounts to the least privileges they require. A Cloud Access Security Broker (CASB) can be used to set usage policies and manage user…","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1529","name":"System Shutdown/Reboot","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1529","summary":"Adversaries may shutdown/reboot systems to interrupt access to, or aid in the destruction of, those systems.","description":"Adversaries may shutdown/reboot systems to interrupt access to, or aid in the destruction of, those systems. Operating systems may contain commands to initiate a shutdown/reboot of a machine or network device. In some cases, these commands may also be used to initiate a shutdown/reboot of a remote computer or network device via Network Device CLI (e.g. reload). They may also include shutdown/reboot of a virtual machine via hypervisor / cloud consoles or command line tools.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Host Status","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries forced victim devices to reboot to finalize destruction of impacted systems.","APT37 has used malware that will issue the command shutdown /r /t 1 to reboot a system after wiping its MBR.","APT38 has used a custom MBR wiper named BOOTWRECK, which will initiate a system reboot after wiping the victim's MBR.","AcidPour includes functionality to reboot the victim system following wiping actions, similar to AcidRain."],"examplesTotal":30},{"id":"T1530","name":"Data from Cloud Storage","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1530","summary":"Adversaries may access data from cloud storage. Many IaaS providers offer solutions for online data object storage such as Amazon S3, Azure Storage, and Google Cloud Storage.","description":"Adversaries may access data from cloud storage. Many IaaS providers offer solutions for online data object storage such as Amazon S3, Azure Storage, and Google Cloud Storage. Similarly, SaaS enterprise platforms such as Office 365 and Google Workspace provide cloud-based document storage to users through services such as OneDrive and Google Drive, while SaaS application providers such as Slack, Confluence, Salesforce, and Dropbox may provide cloud storage solutions as a peripheral or primary…","platforms":["IaaS","Office Suite","SaaS"],"detection":["Cloud Storage Access","Network Traffic Content","User Account Authentication","User Account Metadata"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries leveraged stolen credentials within cloud services to download targeted data from SharePoint, and Teams.","AADInternals can collect files from a user’s OneDrive.","APT42 has collected data from Microsoft 365 environments.","During C0027, Scattered Spider accessed victim OneDrive environments to search for VPN and MFA enrollment information, help desk instructions, and new hire guides."],"examplesTotal":11,"mitigations":[{"name":"User Account Management","text":"Configure user permissions groups and roles for access to cloud storage. Implement strict Identity and Access Management (IAM) controls to prevent access to storage solutions…","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Encrypt Sensitive Information","text":"Encrypt data stored at rest in cloud storage. Managed encryption keys can be rotated by most providers.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Restrict File and Directory Permissions","text":"Use access control lists on storage systems and objects.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"Filter Network Traffic","text":"Cloud service providers support IP-based restrictions when accessing cloud resources. Consider using IP allowlisting along with user account management to ensure that data access…","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Audit","text":"Frequently check permissions on cloud storage to ensure proper permissions are set to deny open or unprivileged access to resources.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1531","name":"Account Access Removal","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1531","summary":"Adversaries may interrupt availability of system and network resources by inhibiting access to accounts utilized by legitimate users.","description":"Adversaries may interrupt availability of system and network resources by inhibiting access to accounts utilized by legitimate users. Accounts may be deleted, locked, or manipulated (ex: changed credentials, revoked permissions for SaaS platforms such as Sharepoint) to remove access to accounts. Adversaries may also subsequently log off and/or perform a System Shutdown/Reboot to set malicious changes into place.","platforms":["Linux","macOS","Windows","SaaS","IaaS","Office Suite","ESXi"],"detection":["Command Execution","Process Creation","User Account Authentication","User Account Deletion","User Account Modification"],"examples":["Akira deletes administrator accounts in victim networks prior to encryption.","DEADWOOD changes the password for local and domain users via net.exe to a random 32 character string to prevent these accounts from logging on.","LAPSUS$ has removed a targeted organization's global admin accounts to lock the organization out of all access.","LockerGoga has been observed changing account passwords and logging off current users."],"examplesTotal":6},{"id":"T1534","name":"Internal Spearphishing","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1534","summary":"After they already have access to accounts or systems within the environment, adversaries may use internal spearphishing to gain access to additional information or compromise other users within the same organization.","description":"After they already have access to accounts or systems within the environment, adversaries may use internal spearphishing to gain access to additional information or compromise other users within the same organization. Internal spearphishing is multi-staged campaign where a legitimate account is initially compromised either by controlling the user's device or by compromising the account credentials of the user.","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","Command Execution","Logon Session Creation","Logon Session Metadata","Network Traffic Content","Process Creation","User Account Authentication"],"examples":["APT-C-36 has used a compromised account to send a phishing email to an address likely used and monitored by the IT team within the same targeted organization.","Gamaredon Group has used an Outlook VBA module on infected systems to send phishing emails with malicious attachments to other employees within the organization.","HEXANE has conducted internal spearphishing attacks against executives, HR, and IT personnel to gain information and access.","Kimsuky has sent internal spearphishing emails for lateral movement after stealing victim information."],"examplesTotal":8},{"id":"T1535","name":"Unused/Unsupported Cloud Regions","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1535","summary":"Adversaries may create cloud instances in unused geographic service regions in order to evade detection.","description":"Adversaries may create cloud instances in unused geographic service regions in order to evade detection. Access is usually obtained through compromising accounts used to manage cloud infrastructure. Cloud service providers often provide infrastructure throughout the world in order to improve performance, provide redundancy, and allow customers to meet compliance requirements. Oftentimes, a customer will only use a subset of the available regions and may not actively monitor other regions.","platforms":["IaaS"],"detection":["Cloud Storage Creation","Instance Start","Network Connection Creation","User Account Metadata"],"mitigations":[{"name":"Software Configuration","text":"Cloud service providers may allow customers to deactivate unused regions.","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1537","name":"Transfer Data to Cloud Account","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1537","summary":"Adversaries may exfiltrate data by transferring the data, including through sharing/syncing and creating backups of cloud environments, to another cloud account they control on the same service.","description":"Adversaries may exfiltrate data by transferring the data, including through sharing/syncing and creating backups of cloud environments, to another cloud account they control on the same service. A defender who is monitoring for large transfers to outside the cloud environment through normal file transfers or over command and control channels may not be watching for data transfers to another account within the same cloud provider.","platforms":["IaaS","Office Suite","SaaS"],"detection":["Application Log Content","Cloud Storage Metadata","Cloud Storage Modification","Network Traffic Content","Snapshot Creation","Snapshot Metadata","Snapshot Modification"],"examples":["INC Ransom has used Megasync to exfiltrate data to the cloud.","RedCurl has used cloud storage to exfiltrate data, in particular the megatools utilities were used to exfiltrate data to Mega, a file storage service.","Storm-0501 has copied data from the victims environment to their own infrastructure leveraging AzCopy CLI."],"examplesTotal":3,"mitigations":[{"name":"Data Loss Prevention","text":"Data loss prevention can prevent and block sensitive data from being shared with individuals outside an organization.","url":"https://attack.mitre.org/mitigations/M1057"},{"name":"User Account Management","text":"Limit user account and IAM policies to the least privileges required.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Software Configuration","text":"Configure appropriate data sharing restrictions in cloud services. For example, external sharing in Microsoft SharePoint and Google Drive can be turned off altogether, blocked for…","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Filter Network Traffic","text":"Implement network-based filtering restrictions to prohibit data transfers to untrusted VPCs.","url":"https://attack.mitre.org/mitigations/M1037"}]},{"id":"T1538","name":"Cloud Service Dashboard","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1538","summary":"An adversary may use a cloud service dashboard GUI with stolen credentials to gain useful information from an operational cloud environment, such as specific services, resources, and features.","description":"An adversary may use a cloud service dashboard GUI with stolen credentials to gain useful information from an operational cloud environment, such as specific services, resources, and features. For example, the GCP Command Center can be used to view all assets, review findings of potential security risks, and run additional queries, such as finding public IP addresses and open ports.","platforms":["IaaS","SaaS","Office Suite","Identity Provider"],"detection":["Application Log Content","Cloud Storage Metadata","Logon Session Creation","User Account Authentication"],"examples":["Scattered Spider abused AWS Systems Manager Inventory to identify targets on the compromised network prior to lateral movement."],"examplesTotal":1,"mitigations":[{"name":"User Account Management","text":"Enforce the principle of least-privilege by limiting dashboard visibility to only the resources required.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1539","name":"Steal Web Session Cookie","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1539","summary":"An adversary may steal web application or service session cookies and use them to gain access to web applications or Internet services as an authenticated user without needing credentials.","description":"An adversary may steal web application or service session cookies and use them to gain access to web applications or Internet services as an authenticated user without needing credentials. Web applications and services often use session cookies as an authentication token after a user has authenticated to a website. Cookies are often valid for an extended period of time, even if the web application is not actively used.","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","File Access","File Modification","Logon Session Creation","Process Access","Process Creation","User Account Authentication"],"examples":["APT42 has used custom malware to steal login and cookie data from common browsers.","BLUELIGHT can harvest cookies from Internet Explorer, Edge, Chrome, and Naver Whale browsers.","Chaes has used a script that extracts the web session cookie and sends it to the C2 server.","CookieMiner can steal Google Chrome and Apple Safari browser cookies from the victim’s machine."],"examplesTotal":28,"mitigations":[{"name":"Audit","text":"Implement auditing for authentication activities and user logins to detect the use of stolen session cookies.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Software Configuration","text":"Configure browsers or tasks to regularly delete persistent cookies. Additionally, minimize the length of time a web cookie is viable to potentially reduce the impact of stolen…","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Restrict Web-Based Content","text":"Restrict or block web-based content that could be used to extract session cookies or credentials stored in browsers.","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Multi-factor Authentication","text":"Deploy hardware-based token (e.g., YubiKey or FIDO key), which incorporates the target login domain as part of the negotiation protocol, will prevent session cookie theft through…","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Update Software","text":"Regularly update web browsers, password managers, and all related software to the latest versions.","url":"https://attack.mitre.org/mitigations/M1051"}]},{"id":"T1542","name":"Pre-OS Boot","tactics":["Stealth","Persistence"],"url":"https://attack.mitre.org/techniques/T1542","summary":"Adversaries may abuse Pre-OS Boot mechanisms as a way to establish persistence on a system.","description":"Adversaries may abuse Pre-OS Boot mechanisms as a way to establish persistence on a system. During the booting process of a computer, firmware and various startup services are loaded before the operating system. These programs control flow of execution before the operating system takes control.","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Drive Access","Drive Modification","File Creation","File Modification","Firmware Modification","Process Creation"],"mitigations":[{"name":"Limit Access to Resource Over Network","text":"Prevent access to file shares, remote access to systems, unnecessary services. Mechanisms to limit access may include use of network concentrators, RDP gateways, etc.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Audit","text":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Update Software","text":"Patch the BIOS and EFI as necessary.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Privileged Account Management","text":"Ensure proper permissions are in place to help prevent adversary access to privileged accounts necessary to perform these actions","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Boot Integrity","text":"Use Trusted Platform Module technology and a secure or trusted boot process to prevent system integrity from being compromised.","url":"https://attack.mitre.org/mitigations/M1046"}]},{"id":"T1543","name":"Create or Modify System Process","tactics":["Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1543","summary":"Adversaries may create or modify system-level processes to repeatedly execute malicious payloads as part of persistence.","description":"Adversaries may create or modify system-level processes to repeatedly execute malicious payloads as part of persistence. When operating systems boot up, they can start processes that perform background system functions. On Windows and Linux, these system processes are referred to as services. On macOS, launchd processes known as Launch Daemon and Launch Agent are run to finish system initialization and load user specific parameters.","platforms":["Containers","Linux","macOS","Windows"],"detection":["Command Execution","Container Creation","File Modification","Process Creation","Service Creation","Windows Registry Key Modification"],"examples":["Akira _v2 can create a child process for encryption.","BOLDMOVE can free all resources and terminate itself on victim machines.","BRICKSTORM has created a new background session and has spawned a child process of a parent process when it determines it is not running in its intended state.","Exaramel for Linux has a hardcoded location that it uses to achieve persistence if the startup system is Upstart or System V and it is running as root."],"examplesTotal":7,"mitigations":[{"name":"User Account Management","text":"Limit privileges of user accounts and groups so that only authorized administrators can interact with system-level process changes and service configurations.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent an application from writing a signed vulnerable driver to the system.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Limit Software Installation","text":"Restrict software installation to trusted repositories only and be cautious of orphaned software packages.","url":"https://attack.mitre.org/mitigations/M1033"},{"name":"Privileged Account Management","text":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Operating System Configuration","text":"Ensure that Driver Signature Enforcement is enabled to restrict unsigned drivers from being installed.","url":"https://attack.mitre.org/mitigations/M1028"}]},{"id":"T1543.003","name":"Windows Service","tactics":["Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1543/003","summary":"Adversaries may create or modify Windows services to repeatedly execute malicious payloads as part of persistence.","description":"Adversaries may create or modify Windows services to repeatedly execute malicious payloads as part of persistence. When Windows boots up, it starts programs or applications called services that perform background system functions. Windows service configuration information, including the file path to the service's executable or recovery programs/commands, is stored in the Windows Registry.","platforms":["Windows"],"detection":["Driver Load","Process Creation","Service Creation","Windows Registry Key Modification"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used an arbitrary system service to load at system boot for persistence for Industroyer.","An APT19 Port 22 malware variant registers itself as a service.","APT3 has a tool that creates a new service for persistence.","APT32 modified Windows Services to ensure PowerShell scripts were loaded on the system. APT32 also creates a Windows service to establish persistence."],"examplesTotal":140,"mitigations":[{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent an application from writing a signed vulnerable driver to the system.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Operating System Configuration","text":"Ensure that Driver Signature Enforcement is enabled to restrict unsigned drivers from being installed.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"Audit","text":"Use auditing tools capable of detecting privilege and service abuse opportunities on systems within an enterprise and correct them.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Code Signing","text":"Enforce registration and execution of only legitimately signed service drivers where possible.","url":"https://attack.mitre.org/mitigations/M1045"},{"name":"User Account Management","text":"Limit privileges of user accounts and groups so that only authorized administrators can interact with service changes and service configurations.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1546","name":"Event Triggered Execution","tactics":["Privilege Escalation","Persistence"],"url":"https://attack.mitre.org/techniques/T1546","summary":"Adversaries may establish persistence and/or elevate privileges using system mechanisms that trigger execution based on specific events.","description":"Adversaries may establish persistence and/or elevate privileges using system mechanisms that trigger execution based on specific events. Various operating systems have means to monitor and subscribe to events such as logons or other user activity such as running specific applications/binaries. Cloud environments may also support various functions and services that monitor and can be invoked in response to specific cloud events.","platforms":["Linux","macOS","Windows","SaaS","IaaS","Office Suite"],"detection":["Cloud Service Modification","Command Execution","File Metadata","File Modification","Network Traffic Content","Process Creation","Scheduled Job Creation","Script Execution","WMI Creation","Windows Registry Key Modification"],"examples":["KV Botnet Activity involves managing events on victim systems via libevent to execute a callback function when any running process contains the following references in their path without also having a reference to bioset: busybox, wget,…","Pacu can set up S3 bucket notifications to trigger a malicious Lambda function when a CloudFormation template is uploaded to the bucket. It can also create Lambda functions that trigger upon the creation of users, roles, and groups.","UPSTYLE creates a .pth file beginning with the text import so that any time another process or script attempts to reference the modified item the malicious code will also run.","XCSSET's dfhsebxzod module searches for .xcodeproj directories within the user’s home folder and subdirectories. For each match, it locates the corresponding project.pbxproj file and embeds an encoded payload into a build rule, target…"],"examplesTotal":4,"mitigations":[{"name":"Privileged Account Management","text":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Update Software","text":"Perform regular software updates to mitigate exploitation risk.","url":"https://attack.mitre.org/mitigations/M1051"}]},{"id":"T1547","name":"Boot or Logon Autostart Execution","tactics":["Persistence","Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1547","summary":"Adversaries may configure system settings to automatically execute a program during system boot or logon to maintain persistence or gain higher-level privileges on compromised systems.","description":"Adversaries may configure system settings to automatically execute a program during system boot or logon to maintain persistence or gain higher-level privileges on compromised systems. Operating systems may have mechanisms for automatically running a program on system boot or account logon.","platforms":["Linux","macOS","Windows","Network Devices"],"detection":["File Creation","File Modification","Process Creation","Service Metadata","Windows Registry Key Modification"],"examples":["APT42 has modified the Registry to maintain persistence.","BoxCaon established persistence by setting the HKEY_CURRENT_USER\\Software\\Microsoft\\Windows NT\\CurrentVersion\\Windows\\load registry key to point to its executable.","Dtrack’s RAT makes a persistent target file with auto execution on the host start.","Mis-Type has created registry keys for persistence, including HKCU\\Software\\bkfouerioyou, HKLM\\SOFTWARE\\Microsoft\\Active Setup\\Installed Components\\{6afa8072-b2b1-31a8-b5c1-{Unique Identifier}, and HKLM\\SOFTWARE\\Microsoft\\Active…"],"examplesTotal":6},{"id":"T1548","name":"Abuse Elevation Control Mechanism","tactics":["Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1548","summary":"Adversaries may circumvent mechanisms designed to control privilege elevation to gain higher-level permissions.","description":"Adversaries may circumvent mechanisms designed to control privilege elevation to gain higher-level permissions. Most modern systems contain native elevation control mechanisms that are intended to limit privileges that a user can perform on a machine. Authorization has to be granted to specific users in order to perform tasks that can be considered of higher risk.","platforms":["Linux","macOS","Windows","IaaS","Office Suite","Identity Provider"],"detection":["File Metadata","Logon Session Metadata","OS API Execution","Process Creation","Process Metadata","User Account Modification","Windows Registry Key Modification"],"examples":["Raspberry Robin implements a variation of the ucmDccwCOMMethod technique abusing the Windows AutoElevate backdoor to bypass UAC while elevating privileges.","UNC3886 has used vSphere Installation Bundles (VIBs) that contained modified descriptor XML files with the acceptance-level set to partner which allowed for privilege escalation."],"examplesTotal":2,"mitigations":[{"name":"Execution Prevention","text":"System settings can prevent applications from running that haven't been downloaded from legitimate repositories which may help mitigate some of these issues.","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Operating System Configuration","text":"Applications with known vulnerabilities or known shell escapes should not have the setuid or setgid bits set to reduce potential damage if an application is compromised.","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"Update Software","text":"Perform regular software updates to mitigate exploitation risk.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"User Account Control","text":"Although UAC bypass techniques exist, it is still prudent to use the highest enforcement level for UAC when possible and mitigate bypass opportunities that exist with techniques…","url":"https://attack.mitre.org/mitigations/M1052"},{"name":"Privileged Account Management","text":"Remove users from the local administrator group on systems. By requiring a password, even if an adversary can get terminal access, they must know the password to run anything in…","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1550","name":"Use Alternate Authentication Material","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1550","summary":"Adversaries may use alternate authentication material, such as password hashes, Kerberos tickets, and application access tokens, in order to move laterally within an environment and bypass normal system access controls.","description":"Adversaries may use alternate authentication material, such as password hashes, Kerberos tickets, and application access tokens, in order to move laterally within an environment and bypass normal system access controls. Authentication processes generally require a valid identity (e.g., username) along with one or more authentication factors (e.g., password, pin, physical smart card, token generator, etc.).","platforms":["Containers","IaaS","Identity Provider","Linux","Office Suite","SaaS","Windows"],"detection":["Application Log Content","Logon Session Creation","Process Creation","User Account Authentication","User Account Metadata","Web Credential Usage"],"examples":["FoggyWeb can allow abuse of a compromised AD FS server's SAML token.","During the SolarWinds Compromise, APT29 used forged SAML tokens that allowed the actors to impersonate users and bypass MFA, enabling APT29 to access enterprise cloud applications and services."],"examplesTotal":2,"mitigations":[{"name":"Audit","text":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Password Policies","text":"Set and enforce secure password policies for accounts.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"Account Use Policies","text":"Where possible, consider restricting the use of authentication material outside of expected contexts.","url":"https://attack.mitre.org/mitigations/M1036"},{"name":"Privileged Account Management","text":"Limit credential overlap across systems to prevent the damage of credential compromise and reduce the adversary's ability to perform Lateral Movement between systems.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Active Directory Configuration","text":"Configure Active Directory to prevent use of certain techniques; use SID Filtering, etc.","url":"https://attack.mitre.org/mitigations/M1015"}]},{"id":"T1550.002","name":"Pass the Hash","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1550/002","summary":"Adversaries may “pass the hash” using stolen password hashes to move laterally within an environment, bypassing normal system access controls.","description":"Adversaries may “pass the hash” using stolen password hashes to move laterally within an environment, bypassing normal system access controls. Pass the hash (PtH) is a method of authenticating as a user without having access to the user's cleartext password. This method bypasses standard authentication steps that require a cleartext password, moving directly into the portion of the authentication that uses the password hash.","platforms":["Windows"],"detection":["Active Directory Credential Request","Logon Session Creation","Network Connection Creation","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries attempted to reuse password hash values to gain access to other systems.","The APT1 group is known to have used pass the hash.","APT28 has used pass the hash for lateral movement.","APT32 has used pass the hash for lateral movement."],"examplesTotal":22,"mitigations":[{"name":"Update Software","text":"Apply patch KB2871997 to Windows 7 and higher systems to limit the default access of accounts in the local administrator group.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"User Account Control","text":"Enable pass the hash mitigations to apply UAC restrictions to local accounts on network logon.","url":"https://attack.mitre.org/mitigations/M1052"},{"name":"User Account Management","text":"Do not allow a domain user to be in the local administrator group on multiple systems.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Privileged Account Management","text":"Limit credential overlap across systems to prevent the damage of credential compromise and reduce the adversary's ability to perform Lateral Movement between systems.","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1552","name":"Unsecured Credentials","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1552","summary":"Adversaries may search compromised systems to find and obtain insecurely stored credentials.","description":"Adversaries may search compromised systems to find and obtain insecurely stored credentials. These credentials can be stored and/or misplaced in many locations on a system, including plaintext files (e.g. Shell History), operating system or application-specific repositories (e.g. Credentials in Registry), or other specialized files/artifacts (e.g. Private Keys).","platforms":["Windows","SaaS","IaaS","Linux","macOS","Containers","Network Devices","Office Suite","Identity Provider"],"detection":["Application Log Content","Cloud Service Metadata","Command Execution","File Access","File Creation","Network Traffic Content","Process Creation","User Account Authentication","Windows Registry Key Modification"],"examples":["Astaroth uses an external software known as NetPass to recover passwords.","DarkGate uses NirSoft tools to steal user credentials from the infected machine. NirSoft tools are executed via process hollowing in a newly-created instance of vbc.exe or regasm.exe.","Leviathan gathered credentials hardcoded in binaries located on victim devices during Leviathan Australian Intrusions.","NPPSPY captures credentials by recording them through an alternative network listener registered to the mpnotify.exe process, allowing for cleartext recording of logon information."],"examplesTotal":6,"mitigations":[{"name":"Encrypt Sensitive Information","text":"When possible, store keys on separate cryptographic hardware instead of on the local system.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Update Software","text":"Apply patch KB2962486 which prevents credentials from being stored in GPPs.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"User Training","text":"Ensure that developers and system administrators are aware of the risk associated with having plaintext passwords in software configuration files that may be left on endpoint…","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Active Directory Configuration","text":"Remove vulnerable Group Policy Preferences.","url":"https://attack.mitre.org/mitigations/M1015"},{"name":"Password Policies","text":"Use strong passphrases for private keys to make cracking difficult. Do not store credentials within the Registry.","url":"https://attack.mitre.org/mitigations/M1027"}]},{"id":"T1553","name":"Subvert Trust Controls","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1553","summary":"Adversaries may undermine security controls that will either warn users of untrusted activity or prevent execution of untrusted programs.","description":"Adversaries may undermine security controls that will either warn users of untrusted activity or prevent execution of untrusted programs. Operating systems and security products may contain mechanisms to identify programs or websites as possessing some level of trust.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Creation","File Metadata","Process Creation","Windows Registry Key Modification"],"examples":["Axiom has used digital certificates to deliver malware.","Shai-Hulud has suppressed victim NPM warnings using process“exit’; which results in having all errors exit with code 0."],"examplesTotal":2,"mitigations":[{"name":"Execution Prevention","text":"System settings can prevent applications from running that haven't been downloaded through the Apple Store (or other legitimate repositories) which can help mitigate some of these…","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Operating System Configuration","text":"Windows Group Policy can be used to manage root certificates and the Flags value of HKLM\\\\SOFTWARE\\\\Policies\\\\Microsoft\\\\SystemCertificates\\\\Root\\\\ProtectedRoots can be set to 1…","url":"https://attack.mitre.org/mitigations/M1028"},{"name":"Privileged Account Management","text":"Manage the creation, modification, use, and permissions associated to privileged accounts, including SYSTEM and root.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Restrict Registry Permissions","text":"Ensure proper permissions are set for Registry hives to prevent users from modifying keys related to SIP and trust provider components.","url":"https://attack.mitre.org/mitigations/M1024"},{"name":"Software Configuration","text":"HTTP Public Key Pinning (HPKP) is one method to mitigate potential Adversary-in-the-Middle situations where and adversary uses a mis-issued or fraudulent certificate to intercept…","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1554","name":"Compromise Host Software Binary","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1554","summary":"Adversaries may modify host software binaries to establish persistent access to systems.","description":"Adversaries may modify host software binaries to establish persistent access to systems. Software binaries/executables provide a wide range of system commands or services, programs, and libraries. Common software binaries are SSH clients, FTP clients, email clients, web browsers, and many other user or server applications. Adversaries may establish persistence though modifications to host software binaries.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["File Creation","File Modification","Module Load","Process Creation"],"examples":["During the 2016 Ukraine Electric Power Attack, Sandworm Team used a trojanized version of Windows Notepad to add a layer of persistence for Industroyer.","APT5 has modified legitimate binaries and scripts for Pulse Secure VPNs including the legitimate DSUpgrade.pm file to install the ATRIUM webshell for persistence.","BFG Agonizer uses DLL unhooking to remove user mode inline hooks that security solutions often implement. BFG Agonizer also uses IAT unhooking to remove user-mode IAT hooks that security solutions also use.","BOLDMOVE contains a watchdog-like feature that monitors a particular file for modification. If modification is detected, the legitimate file is backed up and replaced with a trojanized file to allow for persistence through likely system…"],"examplesTotal":23,"mitigations":[{"name":"Code Signing","text":"Ensure all application component binaries are signed by the correct application developers.","url":"https://attack.mitre.org/mitigations/M1045"}]},{"id":"T1555","name":"Credentials from Password Stores","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1555","summary":"Adversaries may search for common password storage locations to obtain user credentials.","description":"Adversaries may search for common password storage locations to obtain user credentials. Passwords are stored in several places on a system, depending on the operating system or application holding the credentials. There are also specific applications and services that store passwords to make them easier for users to manage and maintain, such as password managers and cloud secrets vaults.","platforms":["IaaS","Linux","macOS","Windows"],"detection":["Cloud Service Enumeration","File Access","OS API Execution","Process Access","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries configured a native CLI to gather a targeted elevated users password using grep.","APT33 has used a variety of publicly available tools like LaZagne to gather credentials.","APT39 has used the Smartftp Password Decryptor tool to decrypt FTP passwords.","APT41 has obtained information about accounts, lists of employees, and plaintext and hashed passwords from databases."],"examplesTotal":39,"mitigations":[{"name":"Privileged Account Management","text":"Limit the number of accounts and services with permission to query information from password stores to only those required.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Update Software","text":"Perform regular software updates to mitigate exploitation risk.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Password Policies","text":"The password for the user's login keychain can be changed from the user's login password. This increases the complexity for an adversary because they need to know an additional…","url":"https://attack.mitre.org/mitigations/M1027"}]},{"id":"T1556","name":"Modify Authentication Process","tactics":["Defense Impairment","Persistence","Credential Access"],"url":"https://attack.mitre.org/techniques/T1556","summary":"Adversaries may modify authentication mechanisms and processes to access user credentials or enable otherwise unwarranted access to accounts.","description":"Adversaries may modify authentication mechanisms and processes to access user credentials or enable otherwise unwarranted access to accounts. The authentication process is handled by mechanisms, such as the Local Security Authentication Server (LSASS) process and the Security Accounts Manager (SAM) on Windows, pluggable authentication modules (PAM) on Unix-based systems, and authorization plugins on MacOS systems, responsible for gathering, storing, and validating credentials.","platforms":["IaaS","Identity Provider","Linux","macOS","Network Devices","Office Suite","SaaS","Windows"],"detection":["Cloud Service Modification","File Modification","Module Load","Process Access","Process Creation","User Account Modification","Windows Registry Key Modification"],"examples":["ArcaneDoor included modification of the AAA process to bypass authentication mechanisms.","DRYHOOK has intercepted and logged user credentials by modifying the Perl module in Ivanti Connect Secure VPN edge-devices located within /home/perl/DSAuth.pm.","Ebury can intercept private keys using a trojanized ssh-add function.","FIN13 has replaced legitimate KeePass binaries with trojanized versions to collect passwords from numerous applications."],"examplesTotal":6,"mitigations":[{"name":"Restrict Registry Permissions","text":"Restrict Registry permissions to disallow the modification of sensitive Registry keys such as HKEY_LOCAL_MACHINE\\SYSTEM\\CurrentControlSet\\Control\\NetworkProvider\\Order.","url":"https://attack.mitre.org/mitigations/M1024"},{"name":"Multi-factor Authentication","text":"Integrating multi-factor authentication (MFA) as part of organizational policy can greatly reduce the risk of an adversary gaining control of valid credentials that may be used…","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Password Policies","text":"Ensure that AllowReversiblePasswordEncryption property is set to disabled unless there are application requirements.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"Restrict File and Directory Permissions","text":"Restrict write access to the /Library/Security/SecurityAgentPlugins directory.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"User Account Management","text":"Ensure that proper policies are implemented to dictate the the secure enrollment and deactivation of authentication mechanisms, such as MFA, for user accounts.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1557","name":"Adversary-in-the-Middle","tactics":["Credential Access","Collection"],"url":"https://attack.mitre.org/techniques/T1557","summary":"Adversaries may attempt to position themselves between two or more networked devices using an adversary-in-the-middle (AiTM) technique to support follow-on behaviors such as Network Sniffing, Transmitted Data Manipulation, or replay…","description":"Adversaries may attempt to position themselves between two or more networked devices using an adversary-in-the-middle (AiTM) technique to support follow-on behaviors such as Network Sniffing, Transmitted Data Manipulation, or replay attacks (Exploitation for Credential Access). By abusing features of common networking protocols that can determine the flow of network traffic (e.g.","platforms":["Linux","macOS","Network Devices","Windows"],"detection":["Application Log Content","File Modification","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Windows Registry Key Modification"],"examples":["ArcaneDoor included interception of HTTP traffic to victim devices to identify and parse command and control information sent to the device.","Dok proxies web traffic to potentially monitor and alter victim HTTP(S) traffic.","Kimsuky has used modified versions of PHProxy to examine web traffic between the victim and the accessed website.","Line Runner intercepts HTTP requests to the victim Cisco ASA, looking for a request with a 32-character, victim dependent parameter."],"examplesTotal":8,"mitigations":[{"name":"Filter Network Traffic","text":"Use network appliances and host-based security software to block network traffic that is not necessary within the environment, such as legacy protocols that may be leveraged for…","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Encrypt Sensitive Information","text":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure web traffic that may…","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Limit Access to Resource Over Network","text":"Limit access to network infrastructure and resources that can be used to reshape traffic or otherwise produce AiTM conditions.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Disable or Remove Feature or Program","text":"Disable legacy network protocols that may be used to intercept network traffic if applicable, especially those that are not needed within an environment.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"User Training","text":"Train users to be suspicious about certificate errors. Adversaries may use their own certificates in an attempt to intercept HTTPS traffic.","url":"https://attack.mitre.org/mitigations/M1017"}]},{"id":"T1558","name":"Steal or Forge Kerberos Tickets","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1558","summary":"Adversaries may attempt to subvert Kerberos authentication by stealing or forging Kerberos tickets to enable Pass the Ticket.","description":"Adversaries may attempt to subvert Kerberos authentication by stealing or forging Kerberos tickets to enable Pass the Ticket. Kerberos is an authentication protocol widely used in modern Windows domain environments. In Kerberos environments, referred to as “realms”, there are three basic participants: client, service, and Key Distribution Center (KDC).","platforms":["Linux","macOS","Windows"],"detection":["Active Directory Credential Request","File Access","Logon Session Metadata","Process Access"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries used the Rubeus tool to forge a Diamond Ticket that is a modified legitimate Kerberos ticket.","Akira have used scripts to dump Kerberos authentication credentials."],"examplesTotal":2,"mitigations":[{"name":"Active Directory Configuration","text":"For containing the impact of a previously generated golden ticket, reset the built-in KRBTGT account password twice, which will invalidate any existing golden tickets that have…","url":"https://attack.mitre.org/mitigations/M1015"},{"name":"Credential Access Protection","text":"On Linux systems, protect resources with Security Enhanced Linux (SELinux) by defining entry points, process types, and file labels.","url":"https://attack.mitre.org/mitigations/M1043"},{"name":"Encrypt Sensitive Information","text":"Enable AES Kerberos encryption (or another stronger encryption algorithm), rather than RC4, where possible.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Password Policies","text":"Ensure strong password length (ideally 25+ characters) and complexity for service accounts and that these passwords periodically expire.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"Audit","text":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1559","name":"Inter-Process Communication","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1559","summary":"Adversaries may abuse inter-process communication (IPC) mechanisms for local code or command execution.","description":"Adversaries may abuse inter-process communication (IPC) mechanisms for local code or command execution. IPC is typically used by processes to share data, communicate with each other, or synchronize execution. IPC is also commonly used to avoid situations such as deadlocks, which occurs when processes are stuck in a cyclic waiting pattern. Adversaries may abuse IPC to execute arbitrary code or commands.","platforms":["Linux","macOS","Windows"],"detection":["File Access","Named Pipe Metadata","Process Access","Process Creation","Script Execution"],"examples":["During the 3CX Supply Chain Attack, AppleJeus's VEILEDSIGNAL creates and listens on a Windows named pipe to exchange messages between modules.","Cyclops Blink has the ability to create a pipe to enable inter-process communication.","The Havoc SMB demon can use named pipes for communication through a parent demon.","HyperStack can connect to the IPC$ share on remote machines."],"examplesTotal":17,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Registry keys specific to Microsoft Office feature control security can be set to disable automatic DDE/OLE execution.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Software Configuration","text":"Consider disabling embedded files in Office programs, such as OneNote, that do not work with Protected View.","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Application Isolation and Sandboxing","text":"Ensure all COM alerts and Protected View are enabled.","url":"https://attack.mitre.org/mitigations/M1048"},{"name":"Privileged Account Management","text":"Modify Registry settings (directly or using Dcomcnfg.exe) in HKEY_LOCAL_MACHINE\\\\SOFTWARE\\\\Classes\\\\AppID\\\\{AppID_GUID} associated with the process-wide security of individual COM…","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to prevent DDE attacks and spawning of child processes from Office programs.","url":"https://attack.mitre.org/mitigations/M1040"}]},{"id":"T1560","name":"Archive Collected Data","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1560","summary":"An adversary may compress and/or encrypt data that is collected prior to exfiltration.","description":"An adversary may compress and/or encrypt data that is collected prior to exfiltration. Compressing the data can help to obfuscate the collected data and minimize the amount of data sent over the network. Encryption can be used to hide information that is being exfiltrated from detection or make exfiltration less conspicuous upon inspection by a defender. Both compression and encryption are done prior to exfiltration, and can be performed using a utility, 3rd party library, or custom method.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Creation","Module Load","Process Creation"],"examples":["ADVSTORESHELL encrypts with the 3DES algorithm and a hardcoded key prior to exfiltration.","APT28 used a publicly available tool to gather and compress multiple documents on the DCCC and DNC networks.","APT32's backdoor has used LZMA compression and RC4 encryption before exfiltration.","Agent Tesla can encrypt data with 3DES before sending it over to a C2 server."],"examplesTotal":56,"mitigations":[{"name":"Audit","text":"System scans can be performed to identify unauthorized archival utilities.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1561","name":"Disk Wipe","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1561","summary":"Adversaries may wipe or corrupt raw disk data on specific systems or in large numbers in a network to interrupt availability to system and network resources.","description":"Adversaries may wipe or corrupt raw disk data on specific systems or in large numbers in a network to interrupt availability to system and network resources. With direct write access to a disk, adversaries may attempt to overwrite portions of disk data. Adversaries may opt to wipe arbitrary portions of disk data and/or wipe disk structures like the master boot record (MBR). A complete wipe of all disk sectors may be attempted.","platforms":["Linux","macOS","Windows","Network Devices"],"detection":["Command Execution","Drive Access","Drive Modification","Driver Load","Process Creation","User Account Authentication","User Account Metadata"],"mitigations":[{"name":"Data Backup","text":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data.","url":"https://attack.mitre.org/mitigations/M1053"}]},{"id":"T1563","name":"Remote Service Session Hijacking","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1563","summary":"Adversaries may take control of preexisting sessions with remote services to move laterally in an environment.","description":"Adversaries may take control of preexisting sessions with remote services to move laterally in an environment. Users may use valid credentials to log into a service specifically designed to accept remote connections, such as telnet, SSH, and RDP. When a user logs into a service, a session will be established that will allow them to maintain a continuous interaction with that service. Adversaries may commandeer these sessions to carry out actions on remote systems.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","Logon Session Creation","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"mitigations":[{"name":"Network Segmentation","text":"Enable firewall rules to block unnecessary traffic between network security zones within a network.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Disable or Remove Feature or Program","text":"Disable the remote service (ex: SSH, RDP, etc.) if it is unnecessary.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Password Policies","text":"Set and enforce secure password policies for accounts.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"User Account Management","text":"Limit remote user permissions if remote access is necessary.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Privileged Account Management","text":"Do not allow remote access to services as a privileged account unless necessary.","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1564","name":"Hide Artifacts","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1564","summary":"Adversaries may attempt to hide artifacts associated with their behaviors to evade detection.","description":"Adversaries may attempt to hide artifacts associated with their behaviors to evade detection. Operating systems may have features to hide various artifacts, such as important system files and administrative task execution, to avoid disrupting user work environments and prevent users from changing files or features on the system. Adversaries may abuse these features to hide artifacts such as files, directories, user accounts, or other system activity to evade detection.","platforms":["ESXi","Linux","macOS","Office Suite","Windows"],"detection":["Application Log Content","Command Execution","File Creation","File Metadata","Process Creation","Windows Registry Key Modification"],"examples":["Bundlore uses the mktemp utility to make unique file and directory names for payloads, such as TMP_DIR=mktemp -d -t x.","DarkTortilla has used %HiddenReg% and %HiddenKey% as part of its persistence via the Windows registry.","NOOPLDR can hide services used to aid execution.","OSX/Shlayer has used the mktemp utility to make random and unique filenames for payloads, such as export tmpDir=\"$(mktemp -d /tmp/XXXXXXXXXXXX)\" or mktemp -t Installer."],"examplesTotal":7,"mitigations":[{"name":"Limit Software Installation","text":"Restrict the installation of software that may be abused to create hidden desktops, such as hVNC, to user groups that require it.","url":"https://attack.mitre.org/mitigations/M1033"},{"name":"Application Developer Guidance","text":"Application developers should consider limiting the requirements for custom or otherwise difficult to manage file/folder exclusions.","url":"https://attack.mitre.org/mitigations/M1013"},{"name":"Audit","text":"Periodically audit virtual machines for abnormalities.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Antivirus/Antimalware","text":"Review and audit file/folder exclusions, and limit scope of exclusions to only what is required where possible.","url":"https://attack.mitre.org/mitigations/M1049"}]},{"id":"T1564.004","name":"NTFS File Attributes","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1564/004","summary":"Adversaries may use NTFS file attributes to hide their malicious data in order to evade detection.","description":"Adversaries may use NTFS file attributes to hide their malicious data in order to evade detection. Every New Technology File System (NTFS) formatted partition contains a Master File Table (MFT) that maintains a record for every file/directory on the partition. Within MFT entries are file attributes, such as Extended Attributes (EA) and Data [known as Alternate Data Streams (ADSs) when more than one Data attribute is present], that can be used to store arbitrary data (and even complete files).","platforms":["Windows"],"detection":["File Creation","File Metadata","OS API Execution","Process Creation"],"examples":["APT32 used NTFS alternate data streams to hide their payloads.","Anchor has used NTFS to hide files.","Astaroth can abuse alternate data streams (ADS) to store content for malicious payloads.","BitPaymer has copied itself to the :bin alternate data stream of a newly created file."],"examplesTotal":16,"mitigations":[{"name":"Restrict File and Directory Permissions","text":"Consider adjusting read and write permissions for NTFS EA, though this should be tested to ensure routine OS operations are not impeded.","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1565","name":"Data Manipulation","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1565","summary":"Adversaries may insert, delete, or manipulate data in order to influence external outcomes or hide activity, thus threatening the integrity of the data.","description":"Adversaries may insert, delete, or manipulate data in order to influence external outcomes or hide activity, thus threatening the integrity of the data. By manipulating data, adversaries may attempt to affect a business process, organizational understanding, or decision making. The type of modification and the impact it will have depends on the target application and process as well as the goals and objectives of the adversary.","platforms":["Linux","macOS","Windows"],"detection":["File Access","File Creation","File Metadata","File Modification","Network Traffic Content","OS API Execution"],"examples":["FIN13 has injected fraudulent transactions into compromised networks that mimic legitimate behavior to siphon off incremental amounts of money.","PHASEJAM has blocked legitimate upgrades of Ivanti Connect Secure systems and falsely indicates a successful upgrade while operating on an older version."],"examplesTotal":2,"mitigations":[{"name":"Encrypt Sensitive Information","text":"Consider encrypting important information to reduce an adversary’s ability to perform tailored data modifications.","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Remote Data Storage","text":"Consider implementing IT disaster recovery plans that contain procedures for taking regular data backups that can be used to restore organizational data.","url":"https://attack.mitre.org/mitigations/M1029"},{"name":"Network Segmentation","text":"Identify critical business and system processes that may be targeted by adversaries and work to isolate and secure those systems against unauthorized access and tampering.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Restrict File and Directory Permissions","text":"Ensure least privilege principles are applied to important information resources to reduce exposure to data manipulation risk.","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1566","name":"Phishing","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1566","summary":"Adversaries may send phishing messages to gain access to victim systems.","description":"Adversaries may send phishing messages to gain access to victim systems. All forms of phishing are electronically delivered social engineering. Phishing can be targeted, known as spearphishing. In spearphishing, a specific individual, company, or industry will be targeted by the adversary. More generally, adversaries can conduct non-targeted phishing, such as in mass malware spam campaigns.","platforms":["Identity Provider","Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","File Creation","Logon Session Creation","Process Creation"],"examples":["AppleJeus has used spearphishing emails to distribute malicious payloads.","Axiom has used spear phishing to initially compromise victims.","GOLD SOUTHFIELD has conducted malicious spam (malspam) campaigns to gain access to victim's machines.","Hikit has been spread through spear phishing."],"examplesTotal":11,"mitigations":[{"name":"Audit","text":"Perform audits or scans of systems, permissions, insecure software, insecure configurations, etc. to identify potential weaknesses.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Network Intrusion Prevention","text":"Network intrusion prevention systems and systems designed to scan and remove malicious email attachments or links can be used to block activity.","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Software Configuration","text":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM).","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Restrict Web-Based Content","text":"Determine if certain websites or attachment types (ex: .scr, .exe, .pif, .cpl, etc.) that can be used for phishing are necessary for business operations and consider blocking…","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Antivirus/Antimalware","text":"Anti-virus can automatically quarantine suspicious files.","url":"https://attack.mitre.org/mitigations/M1049"}]},{"id":"T1567","name":"Exfiltration Over Web Service","tactics":["Exfiltration"],"url":"https://attack.mitre.org/techniques/T1567","summary":"Adversaries may use an existing, legitimate external Web service to exfiltrate data rather than their primary command and control channel.","description":"Adversaries may use an existing, legitimate external Web service to exfiltrate data rather than their primary command and control channel. Popular Web services acting as an exfiltration mechanism may give a significant amount of cover due to the likelihood that hosts within a network are already communicating with them prior to compromise. Firewall rules may also already exist to permit traffic to these services.","platforms":["ESXi","Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","Command Execution","File Access","File Creation","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["APT28 can exfiltrate data over Google Drive.","During APT28 Nearest Neighbor Campaign, APT28 exfiltrated data over public-facing webservers – such as Google Drive.","During the Anthropic AI-orchestrated Campaign, the adversary utilized Claude Code to generate a detailed summary report of collected data, which is then reviewed and approved by the adversary prior to exfiltration of data over Claude.","AppleSeed has exfiltrated files using web services."],"examplesTotal":15,"mitigations":[{"name":"Restrict Web-Based Content","text":"Web proxies can be used to enforce an external network communication policy that prevents use of unauthorized external services.","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Data Loss Prevention","text":"Data loss prevention can be detect and block sensitive data being uploaded to web services via web browsers.","url":"https://attack.mitre.org/mitigations/M1057"}]},{"id":"T1568","name":"Dynamic Resolution","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1568","summary":"Adversaries may dynamically establish connections to command and control infrastructure to evade common detections and remediations.","description":"Adversaries may dynamically establish connections to command and control infrastructure to evade common detections and remediations. This may be achieved by using malware that shares a common algorithm with the infrastructure the adversary uses to receive the malware's communications. These calculations can be used to dynamically adjust parameters such as the domain name, IP address, or port number the malware uses for command and control.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["APT-C-36 has used DDNS services such as DuckDNS, noip[.]com, and con-ip[.]com to redirect victims to sites or repositories hosting malware implants.","APT29 has used Dynamic DNS providers for their malware C2 infrastructure.","AsyncRAT can be configured to use dynamic DNS.","BITTER has used DDNS for C2 communications."],"examplesTotal":24,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Restrict Web-Based Content","text":"In some cases a local DNS sinkhole may be used to help prevent behaviors associated with dynamic resolution.","url":"https://attack.mitre.org/mitigations/M1021"}]},{"id":"T1568.002","name":"Domain Generation Algorithms","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1568/002","summary":"Adversaries may make use of Domain Generation Algorithms (DGAs) to dynamically identify a destination domain for command and control traffic rather than relying on a list of static IP addresses or domains.","description":"Adversaries may make use of Domain Generation Algorithms (DGAs) to dynamically identify a destination domain for command and control traffic rather than relying on a list of static IP addresses or domains. This has the advantage of making it much harder for defenders to block, track, or take over the command and control channel, as there potentially could be thousands of domains that malware can check for instructions.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["APT41 has used DGAs to change their C2 servers monthly.","Aria-body has the ability to use a DGA for C2 communications.","Astaroth has used a DGA in C2 communications.","AsyncRAT use a DGA to generate a C2 domains."],"examplesTotal":24,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"Restrict Web-Based Content","text":"In some cases a local DNS sinkhole may be used to help prevent DGA-based command and control at a reduced cost.","url":"https://attack.mitre.org/mitigations/M1021"}]},{"id":"T1569","name":"System Services","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1569","summary":"Adversaries may abuse system services or daemons to execute commands or programs.","description":"Adversaries may abuse system services or daemons to execute commands or programs. Adversaries can execute malicious content by interacting with or creating services either locally or remotely. Many services are set to run at boot, which can aid in achieving persistence (Create or Modify System Process), but adversaries can also abuse services for one-time or temporary execution.","platforms":["Windows","macOS","Linux"],"detection":["File Modification","Process Creation","Service Creation","Windows Registry Key Modification"],"mitigations":[{"name":"Privileged Account Management","text":"Ensure that permissions disallow services that run at a higher permissions level from being created or interacted with by a user with a lower permission level.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"User Account Management","text":"Prevent users from installing their own launch agents or launch daemons.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Behavior Prevention on Endpoint","text":"On Windows 10, enable Attack Surface Reduction (ASR) rules to block processes created by PsExec from running.","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Restrict File and Directory Permissions","text":"Ensure that high permission level service binaries cannot be replaced or modified by users with a lower permission level.","url":"https://attack.mitre.org/mitigations/M1022"}]},{"id":"T1570","name":"Lateral Tool Transfer","tactics":["Lateral Movement"],"url":"https://attack.mitre.org/techniques/T1570","summary":"Adversaries may transfer tools or other files between systems in a compromised environment.","description":"Adversaries may transfer tools or other files between systems in a compromised environment. Once brought into the victim environment (i.e., Ingress Tool Transfer) files may then be copied from one system to another to stage adversary tools or other files over the course of an operation.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Command Execution","File Creation","File Metadata","Network Share Access","Process Creation"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team moved their tools laterally within the corporate network and between the ICS and corporate network.","During the 2016 Ukraine Electric Power Attack, Sandworm Team used move to transfer files to a network share.","During the 2022 Ukraine Electric Power Attack, Sandworm Team used a Group Policy Object (GPO) to copy CaddyWiper's executable msserver.exe from a staging server to a local hard drive before deployment.","During the 2025 Poland Wiper Attacks, the adversaries had placed the malicious payload on an accessible network share to facilitate propagation."],"examplesTotal":55,"mitigations":[{"name":"Filter Network Traffic","text":"Consider using the host firewall to restrict file sharing communications such as SMB.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware or unusual data transfer over known tools and…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1571","name":"Non-Standard Port","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1571","summary":"Adversaries may communicate using a protocol and port pairing that are typically not associated.","description":"Adversaries may communicate using a protocol and port pairing that are typically not associated. For example, HTTPS over port 8088 or port 587 as opposed to the traditional port 443. Adversaries may make changes to the standard port used by a protocol to bypass filtering or muddle analysis/parsing of network data. Adversaries may also make changes to victim systems to abuse non-standard ports.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Application Log Content","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["During the 2025 Poland Wiper Attacks, the adversaries had created a Reverse SOCKS Proxy and communicated over the non-standard port 8008.","APT-C-36 has used port 4050 for C2 communications.","An APT32 backdoor can use HTTP over a non-standard TCP port (e.g 14146) which is specified in the backdoor configuration.","APT33 has used HTTP over TCP ports 808 and 880 for command and control."],"examplesTotal":66,"mitigations":[{"name":"Network Segmentation","text":"Properly configure firewalls and proxies to limit outgoing traffic to only necessary ports for that particular network segment.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1572","name":"Protocol Tunneling","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1572","summary":"Adversaries may tunnel network communications to and from a victim system within a separate protocol to avoid detection/network filtering and/or enable access to otherwise unreachable systems.","description":"Adversaries may tunnel network communications to and from a victim system within a separate protocol to avoid detection/network filtering and/or enable access to otherwise unreachable systems. Tunneling involves explicitly encapsulating a protocol within another. This behavior may conceal malicious traffic by blending in with existing traffic and/or provide an outer layer of encryption (similar to a VPN).","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Application Log Content","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["During the 2022 Ukraine Electric Power Attack, Sandworm Team deployed the GOGETTER tunneler software to establish a “Yamux” TLS-based C2 channel with an external server(s).","BRICKSTORM has utilized a SOCKS proxy to tunnel access within the victim network and exfiltrate files from internal shares, code repositories, and other endpoints.","Brute Ratel C4 can use DNS over HTTPS for C2.","During C0027, Scattered Spider used SSH tunneling in targeted environments."],"examplesTotal":42,"mitigations":[{"name":"Filter Network Traffic","text":"Consider filtering network traffic to untrusted or known bad domains and resources.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1573","name":"Encrypted Channel","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1573","summary":"Adversaries may employ an encryption algorithm to conceal command and control traffic rather than relying on any inherent protections provided by a communication protocol.","description":"Adversaries may employ an encryption algorithm to conceal command and control traffic rather than relying on any inherent protections provided by a communication protocol. Despite the use of a secure algorithm, these implementations may be vulnerable to reverse engineering if secret keys are encoded and/or generated within malware samples/configuration files.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Application Log Content","Module Load","Network Connection Creation","Network Traffic Content","Network Traffic Flow","Process Creation"],"examples":["APT29 has used multiple layers of encryption within malware to protect C2 communication.","BITTER has encrypted their C2 communications.","Chaes has used encryption for its C2 channel.","Cryptoistic can engage in encrypted communications with C2."],"examplesTotal":17,"mitigations":[{"name":"Network Intrusion Prevention","text":"Network intrusion detection and prevention systems that use network signatures to identify traffic for specific adversary malware can be used to mitigate activity at the network…","url":"https://attack.mitre.org/mitigations/M1031"},{"name":"SSL/TLS Inspection","text":"SSL/TLS inspection can be used to see the contents of encrypted sessions to look for network-based indicators of malware communication protocols.","url":"https://attack.mitre.org/mitigations/M1020"}]},{"id":"T1574","name":"Hijack Execution Flow","tactics":["Stealth","Execution"],"url":"https://attack.mitre.org/techniques/T1574","summary":"Adversaries may execute their own malicious payloads by hijacking the way operating systems run programs.","description":"Adversaries may execute their own malicious payloads by hijacking the way operating systems run programs. Hijacking execution flow can be for the purposes of persistence, since this hijacked execution may reoccur over time. Adversaries may also use these mechanisms to elevate privileges or evade defenses, such as application control or other restrictions on execution.","platforms":["Linux","macOS","Windows"],"detection":["File Creation","File Modification","Module Load","Process Creation","Service Metadata","Windows Registry Key Modification"],"examples":["During C0017, APT41 established persistence by loading malicious libraries via modifications to the Import Address Table (IAT) within legitimate Microsoft binaries.","COATHANGER will remove and write malicious shared objects associated with legitimate system functions such as read(2).","DarkGate edits the Registry key HKCU\\Software\\Classes\\mscfile\\shell\\open\\command to execute a malicious AutoIt script. When eventvwr.exe is executed, this will call the Microsoft Management Console (mmc.exe), which in turn references the…","Denis replaces the nonexistent Windows DLL \"msfte.dll\" with its own malicious version, which is loaded by the SearchIndexer.exe and SearchProtocolHost.exe."],"examplesTotal":11,"mitigations":[{"name":"User Account Control","text":"Turn off UAC's privilege elevation for standard users [HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Policies\\System] to automatically deny elevation requests, add:…","url":"https://attack.mitre.org/mitigations/M1052"},{"name":"Behavior Prevention on Endpoint","text":"Some endpoint security solutions can be configured to block some types of behaviors related to process injection/memory tampering based on common sequences of indicators (ex:…","url":"https://attack.mitre.org/mitigations/M1040"},{"name":"Restrict Library Loading","text":"Disallow loading of remote DLLs. This is included by default in Windows Server 2012+ and is available by patch for XP+ and Server 2003+.","url":"https://attack.mitre.org/mitigations/M1044"},{"name":"Audit","text":"Use auditing tools capable of detecting hijacking opportunities on systems within an enterprise and correct them.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Application Developer Guidance","text":"When possible, include hash values in manifest files to help prevent side-loading of malicious libraries.","url":"https://attack.mitre.org/mitigations/M1013"}]},{"id":"T1578","name":"Modify Cloud Compute Infrastructure","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1578","summary":"An adversary may attempt to modify a cloud account's compute service infrastructure to evade defenses.","description":"An adversary may attempt to modify a cloud account's compute service infrastructure to evade defenses. A modification to the compute service infrastructure can include the creation, deletion, or modification of one or more components such as compute instances, virtual machines, and snapshots. Permissions gained from the modification of infrastructure components may bypass restrictions that prevent access to existing infrastructure.","platforms":["IaaS"],"detection":["Cloud Service Metadata","Instance Start","Instance Stop","Snapshot Creation","Snapshot Deletion","Snapshot Modification","Volume Creation","Volume Deletion","Volume Modification"],"mitigations":[{"name":"User Account Management","text":"Limit permissions for creating, deleting, and otherwise altering compute components in accordance with least privilege.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Audit","text":"Routinely monitor user permissions to ensure only the expected users have the capability to modify cloud compute infrastructure components.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1580","name":"Cloud Infrastructure Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1580","summary":"An adversary may attempt to discover infrastructure and resources that are available within an infrastructure-as-a-service (IaaS) environment.","description":"An adversary may attempt to discover infrastructure and resources that are available within an infrastructure-as-a-service (IaaS) environment. This includes compute service resources such as instances, virtual machines, and snapshots as well as resources of other services including the storage and database services. Cloud providers offer methods such as APIs and commands issued through CLIs to serve information about infrastructure.","platforms":["IaaS"],"detection":["Cloud Storage Enumeration","Instance Enumeration","Instance Metadata"],"examples":["Pacu can enumerate AWS infrastructure, such as EC2 instances.","Scattered Spider enumerates cloud environments including Amazon Web Services (AWS) S3 buckets to identify server and backup management infrastructure, resource access, databases and storage containers .","Storm-0501 has enumerated compromised cloud environments to identify critical assets, data stores, and back resources.","TruffleHog can enumerate AWS Infrastructure to include EC2 instances."],"examplesTotal":4,"mitigations":[{"name":"User Account Management","text":"Limit permissions to discover cloud infrastructure in accordance with least privilege. Organizations should limit the number of users within the organization with an IAM role that…","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1583","name":"Acquire Infrastructure","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1583","summary":"Adversaries may buy, lease, rent, or obtain infrastructure that can be used during targeting.","description":"Adversaries may buy, lease, rent, or obtain infrastructure that can be used during targeting. A wide variety of infrastructure exists for hosting and orchestrating adversary operations. Infrastructure solutions include physical or cloud servers, domains, and third-party web services. Some infrastructure providers offer free trial periods, enabling infrastructure acquisition at limited to no cost. Additionally, botnets are available for rent or purchase.","platforms":["PRE"],"detection":["Active DNS","Domain Registration","Passive DNS","Response Content","Response Metadata"],"examples":["Agrius typically uses commercial VPN services for anonymizing last-hop traffic to victim networks, such as ProtonVPN.","Contagious Interview has used services such as Astrill VPN.","Ember Bear uses services such as IVPN, SurfShark, and Tor to add anonymization to operations.","Indrik Spider has purchased access to victim VPNs to facilitate access to victim environments."],"examplesTotal":8,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1584","name":"Compromise Infrastructure","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1584","summary":"Adversaries may compromise third-party infrastructure that can be used during targeting.","description":"Adversaries may compromise third-party infrastructure that can be used during targeting. Infrastructure solutions include physical or cloud servers, domains, network devices, and third-party web and DNS services. Instead of buying, leasing, or renting infrastructure an adversary may compromise infrastructure and use it during other phases of the adversary lifecycle. Additionally, adversaries may compromise numerous machines to form a botnet they can leverage.","platforms":["PRE"],"detection":["Active DNS","Domain Registration","Passive DNS","Response Content","Response Metadata"],"examples":["During APT28 Nearest Neighbor Campaign, APT28 compromised third-party infrastructure in physical proximity to targets of interest for follow-on activities.","Indian Critical Infrastructure Intrusions included the use of compromised infrastructure, such as DVR and IP camera devices, for command and control purposes in ShadowPad activity."],"examplesTotal":2,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1585","name":"Establish Accounts","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1585","summary":"Adversaries may create and cultivate accounts with services that can be used during targeting.","description":"Adversaries may create and cultivate accounts with services that can be used during targeting. Adversaries can create accounts that can be used to build a persona to further operations. Persona development consists of the development of public information, presence, history and appropriate affiliations.","platforms":["PRE"],"detection":["Network Traffic Content","Social Media"],"examples":["APT17 has created and cultivated profile pages in Microsoft TechNet. To make profile pages appear more legitimate, APT17 has created biographical sections and posted in forum threads.","Contagious Interview has created and maintained personas on code repositories to distribute malicious payloads.","Ember Bear has created accounts on dark web forums to obtain various tools and malware.","Fox Kitten has created KeyBase accounts to communicate with ransomware victims."],"examplesTotal":6,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1586","name":"Compromise Accounts","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1586","summary":"Adversaries may compromise accounts with services that can be used during targeting.","description":"Adversaries may compromise accounts with services that can be used during targeting. For operations incorporating social engineering, the utilization of an online persona may be important. Rather than creating and cultivating accounts (i.e. Establish Accounts), adversaries may compromise existing accounts. Utilizing an existing persona may engender a level of trust in a potential victim if they have a relationship, or knowledge of, the compromised persona.","platforms":["PRE"],"detection":["Network Traffic Content","Social Media"],"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1587","name":"Develop Capabilities","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1587","summary":"Adversaries may build capabilities that can be used during targeting.","description":"Adversaries may build capabilities that can be used during targeting. Rather than purchasing, freely downloading, or stealing capabilities, adversaries may develop their own capabilities in-house. This is the process of identifying development requirements and building solutions such as malware, exploits, and self-signed certificates. Adversaries may develop capabilities to support their operations throughout numerous phases of the adversary lifecycle.","platforms":["PRE"],"detection":["Malware Content","Malware Metadata","Response Content"],"examples":["Contagious Interview developed malicious NPM packages for delivery to or retrieval by victims.","Kimsuky created and used a mailing toolkit to use in spearphishing attacks.","Moonstone Sleet developed malicious npm packages for delivery to or retrieval by victims."],"examplesTotal":3,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1588","name":"Obtain Capabilities","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1588","summary":"Adversaries may buy and/or steal capabilities that can be used during targeting.","description":"Adversaries may buy and/or steal capabilities that can be used during targeting. Rather than developing their own capabilities in-house, adversaries may purchase, freely download, or steal them. Activities may include the acquisition of malware, software (including licenses), exploits, certificates, and information relating to vulnerabilities. Adversaries may obtain capabilities to support their operations throughout numerous phases of the adversary lifecycle.","platforms":["PRE"],"detection":["Certificate Registration","Malware Content","Malware Metadata","Response Content"],"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1589","name":"Gather Victim Identity Information","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1589","summary":"Adversaries may gather information about the victim's identity that can be used during targeting.","description":"Adversaries may gather information about the victim's identity that can be used during targeting. Information about identities may include a variety of details, including personal data (ex: employee names, email addresses, security question responses, etc.) as well as sensitive details such as credentials or multi-factor authentication (MFA) configurations. Adversaries may gather this information in various ways, such as direct elicitation via Phishing for Information.","platforms":["PRE"],"detection":["Network Traffic Content"],"examples":["APT32 has conducted targeted surveillance against activists and bloggers.","Contagious Interview has researched specific professional groups such as software developers for targeting. Contagious Interview has also researched individuals who work in roles related to cryptocurrency and blockchain technologies.","FIN13 has researched employees to target for social engineering attacks.","HEXANE has identified specific potential victims at targeted organizations."],"examplesTotal":12,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1590","name":"Gather Victim Network Information","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1590","summary":"Adversaries may gather information about the victim's networks that can be used during targeting.","description":"Adversaries may gather information about the victim's networks that can be used during targeting. Information about networks may include a variety of details, including administrative data (ex: IP ranges, domain names, etc.) as well as specifics regarding its topology and operations. Adversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information.","platforms":["PRE"],"examples":["HAFNIUM gathered the fully qualified domain names (FQDNs) for targeted Exchange servers in the victim's environment.","Indrik Spider has downloaded tools, such as the Advanced Port Scanner utility and Lansweeper, to conduct internal reconnaissance of the victim network.","Volt Typhoon has conducted extensive pre-compromise reconnaissance to learn about the target organization’s network."],"examplesTotal":3,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1591","name":"Gather Victim Org Information","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1591","summary":"Adversaries may gather information about the victim's organization that can be used during targeting.","description":"Adversaries may gather information about the victim's organization that can be used during targeting. Information about an organization may include a variety of details, including the names of divisions/departments, specifics of business operations, as well as the roles and responsibilities of key employees. Adversaries may gather this information in various ways, such as direct elicitation via Phishing for Information.","platforms":["PRE"],"examples":["APT28 has used large language models (LLMs) to gather information about satellite capabilities.","FIN7 has compiled a list of victims by filtering companies by revenue using Zoominfo, which is a service that provides business information.","Kimsuky has collected victim organization information including but not limited to organization hierarchy, functions, press releases, and others.","Lazarus Group has studied publicly available information about a targeted organization to tailor spearphishing efforts against specific departments and/or individuals."],"examplesTotal":9,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1592","name":"Gather Victim Host Information","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1592","summary":"Adversaries may gather information about the victim's hosts that can be used during targeting.","description":"Adversaries may gather information about the victim's hosts that can be used during targeting. Information about hosts may include a variety of details, including administrative data (ex: name, assigned IP, functionality, etc.) as well as specifics regarding its configuration (ex: operating system, language, etc.). Adversaries may gather this information in various ways, such as direct collection actions via Active Scanning or Phishing for Information.","platforms":["PRE"],"detection":["Response Content"],"examples":["Volt Typhoon has conducted pre-compromise reconnaissance for victim host information."],"examplesTotal":1,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1593","name":"Search Open Websites/Domains","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1593","summary":"Adversaries may search freely available websites and/or domains for information about victims that can be used during targeting.","description":"Adversaries may search freely available websites and/or domains for information about victims that can be used during targeting. Information about victims may be available in various online sites, such as social media, new sites, or those hosting information about business operations such as hiring or requested/rewarded contracts. Adversaries may search in different online sites depending on what information they seek to gather.","platforms":["PRE"],"examples":["APT-C-36 has gathered information on Colombian financial institutions, including Bancolombia, BBVA, Banco Caja Social, and Davivienda to craft phishing pages.","Contagious Interview has utilized open-source indicator of compromise repositories to determine their exposure to include VirusTotal, and MalTrail.","Mustang Panda has used open-source research to identify information about victims to use in targeting to include creating weaponized phishing lures and attachments.","Sandworm Team researched Ukraine's unique legal entity identifier (called an \"EDRPOU\" number), including running queries on the EDRPOU website, in preparation for the NotPetya attack."],"examplesTotal":6,"mitigations":[{"name":"Audit","text":"Scan public code repositories for exposed credentials or other sensitive information before making commits.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Application Developer Guidance","text":"Application developers uploading to public code repositories should be careful to avoid publishing sensitive information such as credentials and API keys.","url":"https://attack.mitre.org/mitigations/M1013"}]},{"id":"T1594","name":"Search Victim-Owned Websites","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1594","summary":"Adversaries may search websites owned by the victim for information that can be used during targeting.","description":"Adversaries may search websites owned by the victim for information that can be used during targeting. Victim-owned websites may contain a variety of details, including names of departments/divisions, physical locations, and data about key employees such as names, roles, and contact info (ex: Email Addresses). These sites may also have details highlighting business operations and relationships. Adversaries may search victim-owned websites to gather actionable information.","platforms":["PRE"],"detection":["Application Log Content"],"examples":["APT41 DUST involved access of external victim websites for target development.","During Cutting Edge, threat actors peformed reconnaissance of victims' internal websites via proxied connections.","EXOTIC LILY has used contact forms on victim websites to generate phishing e-mails.","Kimsuky has searched for information on the target company's website."],"examplesTotal":9,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1595","name":"Active Scanning","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1595","summary":"Adversaries may execute active reconnaissance scans to gather information that can be used during targeting.","description":"Adversaries may execute active reconnaissance scans to gather information that can be used during targeting. Active scans are those where the adversary probes victim infrastructure via network traffic, as opposed to other forms of reconnaissance that do not involve direct interaction. Adversaries may perform different forms of active scanning depending on what information they seek to gather.","platforms":["PRE"],"detection":["Network Traffic Content","Network Traffic Flow"],"examples":["In the Triton Safety Instrumented System Attack, TEMP.Veles engaged in network reconnaissance against targets of interest."],"examplesTotal":1,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1596","name":"Search Open Technical Databases","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1596","summary":"Adversaries may search freely available technical databases for information about victims that can be used during targeting.","description":"Adversaries may search freely available technical databases for information about victims that can be used during targeting. Information about victims may be available in online databases and repositories, such as registrations of domains/certificates as well as public collections of network data/artifacts gathered from traffic and/or scans. Adversaries may search in different open databases depending on what information they seek to gather.","platforms":["PRE"],"examples":["APT28 has used large language models (LLMs) to assist in script development and deployment.","Kimsuky has used LLMs to better understand publicly reported vulnerabilities."],"examplesTotal":2,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1597","name":"Search Closed Sources","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1597","summary":"Adversaries may search and gather information about victims from closed (e.g., paid, private, or otherwise not freely available) sources that can be used during targeting.","description":"Adversaries may search and gather information about victims from closed (e.g., paid, private, or otherwise not freely available) sources that can be used during targeting. Information about victims may be available for purchase from reputable private sources and databases, such as paid subscriptions to feeds of technical/threat intelligence data. Adversaries may also purchase information from less-reputable sources such as dark web or cybercrime blackmarkets.","platforms":["PRE"],"examples":["EXOTIC LILY has searched for information on targeted individuals on business databases including RocketReach and CrunchBase."],"examplesTotal":1,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1598","name":"Phishing for Information","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1598","summary":"Adversaries may send phishing messages to elicit sensitive information that can be used during targeting.","description":"Adversaries may send phishing messages to elicit sensitive information that can be used during targeting. Phishing for information is an attempt to trick targets into divulging information, frequently credentials or other actionable information. Phishing for information is different from Phishing in that the objective is gathering data from the victim rather than executing malicious code. All forms of phishing are electronically delivered social engineering.","platforms":["PRE"],"detection":["Application Log Content","Network Traffic Content","Network Traffic Flow"],"examples":["APT28 has used spearphishing to compromise credentials.","Kimsuky has used tailored spearphishing emails to gather victim information including contat lists to identify additional targets.","Moonstone Sleet has interacted with victims to gather information via email.","Scattered Spider has used a combination of credential phishing and social engineering to capture one-time-password (OTP) codes."],"examplesTotal":5,"mitigations":[{"name":"User Training","text":"Users can be trained to identify social engineering techniques and spearphishing attempts.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Software Configuration","text":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM).","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1599","name":"Network Boundary Bridging","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1599","summary":"Adversaries may bridge network boundaries by compromising perimeter network devices or internal devices responsible for network segmentation.","description":"Adversaries may bridge network boundaries by compromising perimeter network devices or internal devices responsible for network segmentation. Breaching these devices may enable an adversary to bypass restrictions on traffic routing that otherwise separate trusted and untrusted networks. Devices such as routers and firewalls can be used to create boundaries between trusted and untrusted networks.","platforms":["Network Devices"],"detection":["Network Traffic Content","Network Traffic Flow"],"examples":["APT41 used NATBypass to bypass firewall restrictions and to access compromised systems via RDP.","Indian Critical Infrastructure Intrusions involved the use of FRP to bridge network boundaries and overcome NAT. Indian Critical Infrastructure Intrusions also involved the use of VPN tunnels with a potentially compromised MSP entity…"],"examplesTotal":2,"mitigations":[{"name":"Multi-factor Authentication","text":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Password Policies","text":"Refer to NIST guidelines when creating password policies.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"Privileged Account Management","text":"Restrict administrator accounts to as few individuals as possible, following least privilege principles.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Filter Network Traffic","text":"Upon identifying a compromised network device being used to bridge a network boundary, block the malicious packets using an unaffected network device in path, such as a firewall…","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Credential Access Protection","text":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.","url":"https://attack.mitre.org/mitigations/M1043"}]},{"id":"T1600","name":"Weaken Encryption","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1600","summary":"Adversaries may compromise a network device’s encryption capability in order to bypass encryption that would otherwise protect data communications.","description":"Adversaries may compromise a network device’s encryption capability in order to bypass encryption that would otherwise protect data communications. Encryption can be used to protect transmitted network traffic to maintain its confidentiality (protect against unauthorized disclosure) and integrity (protect against unauthorized changes). Encryption ciphers are used to convert a plaintext message to ciphertext and can be computationally intensive to decipher without the associated decryption key.","platforms":["Network Devices"],"detection":["File Modification","Module Load","Network Traffic Content"]},{"id":"T1601","name":"Modify System Image","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1601","summary":"Adversaries may make changes to the operating system of embedded network devices to weaken defenses and provide new capabilities for themselves.","description":"Adversaries may make changes to the operating system of embedded network devices to weaken defenses and provide new capabilities for themselves. On such devices, the operating systems are typically monolithic and most of the device functionality and capabilities are contained within a single file. To change the operating system, the adversary typically only needs to affect this one file, replacing or modifying it.","platforms":["Network Devices"],"detection":["Command Execution","File Modification"],"examples":["DRYHOOK has modified the Ivanti Connect Secure VPN authentication Perl module DSAuth.pm by reading its contents in the buffer, then finding and replacing select lines of code."],"examplesTotal":1,"mitigations":[{"name":"Multi-factor Authentication","text":"Use multi-factor authentication for user and privileged accounts. Most embedded network devices support TACACS+ and/or RADIUS.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Password Policies","text":"Refer to NIST guidelines when creating password policies.","url":"https://attack.mitre.org/mitigations/M1027"},{"name":"Credential Access Protection","text":"Some embedded network devices are capable of storing passwords for local accounts in either plain-text or encrypted formats.","url":"https://attack.mitre.org/mitigations/M1043"},{"name":"Code Signing","text":"Many vendors provide digitally signed operating system images to validate the integrity of the software used on their platform.","url":"https://attack.mitre.org/mitigations/M1045"},{"name":"Boot Integrity","text":"Some vendors of embedded network devices provide cryptographic signing to ensure the integrity of operating system images at boot time.","url":"https://attack.mitre.org/mitigations/M1046"}]},{"id":"T1602","name":"Data from Configuration Repository","tactics":["Collection"],"url":"https://attack.mitre.org/techniques/T1602","summary":"Adversaries may collect data related to managed devices from configuration repositories.","description":"Adversaries may collect data related to managed devices from configuration repositories. Configuration repositories are used by management systems in order to configure, manage, and control data on remote systems. Configuration repositories may also facilitate remote access and administration of devices. Adversaries may target these repositories in order to collect large quantities of sensitive system administration data.","platforms":["Network Devices"],"detection":["Network Connection Creation","Network Traffic Content"],"mitigations":[{"name":"Update Software","text":"Keep system images and software updated and migrate to SNMPv3.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Software Configuration","text":"Allowlist MIB objects and implement SNMP views.","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Network Segmentation","text":"Segregate SNMP traffic on a separate management network.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Filter Network Traffic","text":"Apply extended ACLs to block unauthorized protocols outside the trusted network.","url":"https://attack.mitre.org/mitigations/M1037"},{"name":"Network Intrusion Prevention","text":"Configure intrusion prevention devices to detect SNMP queries and commands from unauthorized sources.","url":"https://attack.mitre.org/mitigations/M1031"}]},{"id":"T1606","name":"Forge Web Credentials","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1606","summary":"Adversaries may forge credential materials that can be used to gain access to web applications or Internet services.","description":"Adversaries may forge credential materials that can be used to gain access to web applications or Internet services. Web applications and services (hosted in cloud SaaS environments or on-premise servers) often use session cookies, tokens, or other materials to authenticate and authorize user access. Adversaries may generate these credential materials in order to gain access to web resources.","platforms":["SaaS","Windows","macOS","Linux","IaaS","Office Suite","Identity Provider"],"detection":["File Access","Logon Session Creation","Network Traffic Content","Process Access","Web Credential Creation","Web Credential Usage"],"mitigations":[{"name":"Privileged Account Management","text":"Restrict permissions and access to the AD FS server to only originate from privileged access workstations.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Software Configuration","text":"Configure browsers/applications to regularly delete persistent web credentials (such as cookies).","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Audit","text":"Administrators should perform an audit of all access lists and the permissions they have been granted to access web applications and services.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"User Account Management","text":"Ensure that user accounts with administrative rights follow best practices, including use of privileged access workstations, Just in Time/Just Enough Administration (JIT/JEA), and…","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1608","name":"Stage Capabilities","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1608","summary":"Adversaries may upload, install, or otherwise set up capabilities that can be used during targeting.","description":"Adversaries may upload, install, or otherwise set up capabilities that can be used during targeting. To support their operations, an adversary may need to take capabilities they developed (Develop Capabilities) or obtained (Obtain Capabilities) and stage them on infrastructure under their control. These capabilities may be staged on infrastructure that was previously purchased/rented by the adversary (Acquire Infrastructure) or was otherwise compromised by them (Compromise Infrastructure).","platforms":["PRE"],"detection":["Response Content"],"examples":["Mustang Panda has used servers under their control to validate tracking pixels sent to phishing victims."],"examplesTotal":1,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1609","name":"Container Administration Command","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1609","summary":"Adversaries may abuse a container administration service to execute commands within a container.","description":"Adversaries may abuse a container administration service to execute commands within a container. A container administration service such as the Docker daemon, the Kubernetes API server, or the kubelet may allow remote management of containers within an environment. In Docker, adversaries may specify an entrypoint during container deployment that executes a script or command, or they may use a command such as docker exec to execute a command within a running container.","platforms":["Containers"],"detection":["Command Execution","Process Creation"],"examples":["Hildegard was executed through the kubelet API run command and by executing commands on running containers.","Kinsing was executed with an Ubuntu container entry point that runs shell scripts.","Peirates can use kubectl or the Kubernetes API to run commands.","Siloscape can send kubectl commands to victim clusters through an IRC channel and can run kubectl locally to spread once within a victim cluster."],"examplesTotal":5,"mitigations":[{"name":"User Account Management","text":"Enforce authentication and role-based access control on the container service to restrict users to the least privileges required.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Privileged Account Management","text":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers and…","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Disable or Remove Feature or Program","text":"Remove unnecessary tools and software from containers.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Limit Access to Resource Over Network","text":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Execution Prevention","text":"Use read-only containers, read-only file systems, and minimal images when possible to prevent the execution of commands.","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1610","name":"Deploy Container","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1610","summary":"Adversaries may deploy a container into an environment to facilitate execution or evade defenses.","description":"Adversaries may deploy a container into an environment to facilitate execution or evade defenses. In some cases, adversaries may deploy a new container to execute processes associated with a particular image or deployment, such as processes that execute or download malware. In others, an adversary may deploy a new container configured without network rules, user limitations, etc. to bypass existing defenses within the environment.","platforms":["Containers"],"detection":["Application Log Content","Container Start","Network Traffic Content","Process Creation"],"examples":["Doki was run through a deployed container.","Kinsing was run through a deployed Ubuntu container.","Peirates can deploy a pod that mounts its node’s root file system, then execute a command to create a reverse shell on the node.","TeamTNT has deployed different types of containers into victim environments to facilitate execution. TeamTNT has also transferred cryptocurrency mining software to Kubernetes clusters discovered within local IP address ranges."],"examplesTotal":4,"mitigations":[{"name":"User Account Management","text":"Enforce the principle of least privilege by limiting container dashboard access to only the necessary users.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Audit","text":"Scan images before deployment, and block those that are not in compliance with security policies.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Network Segmentation","text":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Limit Access to Resource Over Network","text":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH.","url":"https://attack.mitre.org/mitigations/M1035"}]},{"id":"T1611","name":"Escape to Host","tactics":["Privilege Escalation"],"url":"https://attack.mitre.org/techniques/T1611","summary":"Adversaries may break out of a container or virtualized environment to gain access to the underlying host.","description":"Adversaries may break out of a container or virtualized environment to gain access to the underlying host. This can allow an adversary access to other containerized or virtualized resources from the host level or to the host itself. In principle, containerized / virtualized resources should provide a clear separation of application functionality and be isolated from the host environment. There are multiple ways an adversary may escape from a container to a host environment.","platforms":["Windows","Linux","Containers","ESXi"],"detection":["Container Creation","File Creation","Kernel Module Load","OS API Execution","Process Creation","Volume Modification"],"examples":["Doki’s container was configured to bind the host root directory.","Hildegard has used the BOtB tool that can break out of containers.","Peirates can gain a reverse shell on a host node by mounting the Kubernetes hostPath.","Siloscape maps the host’s C drive to the container by creating a global symbolic link to the host through the calling of NtSetInformationSymbolicLink."],"examplesTotal":5,"mitigations":[{"name":"Update Software","text":"Ensure that hosts are kept up-to-date with security patches.","url":"https://attack.mitre.org/mitigations/M1051"},{"name":"Execution Prevention","text":"Use read-only containers, read-only file systems, and minimal images when possible to prevent the running of commands.","url":"https://attack.mitre.org/mitigations/M1038"},{"name":"Application Isolation and Sandboxing","text":"Consider utilizing seccomp, seccomp-bpf, or a similar solution that restricts certain system calls such as mount.","url":"https://attack.mitre.org/mitigations/M1048"},{"name":"Privileged Account Management","text":"Ensure containers are not running as root by default and do not use unnecessary privileges or mounted components.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Disable or Remove Feature or Program","text":"Remove unnecessary tools and software from containers.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1612","name":"Build Image on Host","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1612","summary":"Adversaries may build a container image directly on a host to bypass defenses that monitor for the retrieval of malicious images from a public registry.","description":"Adversaries may build a container image directly on a host to bypass defenses that monitor for the retrieval of malicious images from a public registry. A remote build request may be sent to the Docker API that includes a Dockerfile that pulls a vanilla base image, such as alpine, from a public or local registry and then builds a custom image upon it.","platforms":["Containers"],"detection":["Image Creation","Network Connection Creation"],"mitigations":[{"name":"Limit Access to Resource Over Network","text":"Limit communications with the container service to local Unix sockets or remote access via SSH.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"Privileged Account Management","text":"Ensure containers are not running as root by default. In Kubernetes environments, consider defining Pod Security Standards that prevent pods from running privileged containers.","url":"https://attack.mitre.org/mitigations/M1026"},{"name":"Network Segmentation","text":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Audit","text":"Audit images deployed within the environment to ensure they do not contain any malicious components.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1613","name":"Container and Resource Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1613","summary":"Adversaries may attempt to discover containers and other resources that are available within a containers environment.","description":"Adversaries may attempt to discover containers and other resources that are available within a containers environment. Other resources may include images, deployments, pods, nodes, and other information such as the status of a cluster. These resources can be viewed within web applications such as the Kubernetes dashboard or can be queried via the Docker and Kubernetes APIs.","platforms":["Containers"],"detection":["Container Enumeration","Pod Enumeration"],"examples":["Hildegard has used masscan to search for kubelets and the kubelet API for additional running containers.","Peirates can enumerate Kubernetes pods in a given namespace.","TeamTNT has checked for running containers with docker ps and for specific container names with docker inspect. TeamTNT has also searched for Kubernetes pods running in a local network."],"examplesTotal":3,"mitigations":[{"name":"Network Segmentation","text":"Deny direct remote access to internal systems through the use of network proxies, gateways, and firewalls.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Limit Access to Resource Over Network","text":"Limit communications with the container service to managed and secured channels, such as local Unix sockets or remote access via SSH.","url":"https://attack.mitre.org/mitigations/M1035"},{"name":"User Account Management","text":"Enforce the principle of least privilege by limiting dashboard visibility to only the required users.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1614","name":"System Location Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1614","summary":"Adversaries may gather information in an attempt to calculate the geographical location of a victim host.","description":"Adversaries may gather information in an attempt to calculate the geographical location of a victim host. Adversaries may use the information from System Location Discovery during automated discovery to shape follow-on behaviors, including whether or not the adversary fully infects the target and/or attempts specific actions. Adversaries may attempt to infer the location of a system using various system checks, such as time zone, keyboard layout, and/or language settings.","platforms":["IaaS","Linux","macOS","Windows"],"detection":["Command Execution","Network Traffic Content","OS API Execution","Process Creation"],"examples":["Amadey does not run any tasks or install additional malware if the victim machine is based in Russia.","AshTag can check geolocation on targeted systems.","Crimson can identify the geographical location of a victim host.","Cuckoo Stealer can determine the geographical location of a victim host by checking the language."],"examplesTotal":26},{"id":"T1615","name":"Group Policy Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1615","summary":"Adversaries may gather information on Group Policy settings to identify paths for privilege escalation, security measures applied within a domain, and to discover patterns in domain objects that can be manipulated or used to blend in…","description":"Adversaries may gather information on Group Policy settings to identify paths for privilege escalation, security measures applied within a domain, and to discover patterns in domain objects that can be manipulated or used to blend in the environment. Group Policy allows for centralized management of user and computer settings in Active Directory (AD).","platforms":["Windows"],"detection":["Active Directory Object Access","Command Execution","Network Traffic Content","Process Creation"],"examples":["BloodHound has the ability to collect local admin information via GPO.","DUSTTRAP can identify victim environment Group Policy information.","Emissary has the capability to execute gpresult.","Empire includes various modules for enumerating Group Policy."],"examplesTotal":7},{"id":"T1619","name":"Cloud Storage Object Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1619","summary":"Adversaries may enumerate objects in cloud storage infrastructure.","description":"Adversaries may enumerate objects in cloud storage infrastructure. Adversaries may use this information during automated discovery to shape follow-on behaviors, including requesting all or specific objects from cloud storage. Similar to File and Directory Discovery on a local host, after identifying available storage services (i.e. Cloud Infrastructure Discovery) adversaries may access the contents/objects stored in cloud infrastructure.","platforms":["IaaS"],"detection":["Cloud Storage Access","Cloud Storage Enumeration"],"examples":["Pacu can enumerate AWS storage services, such as S3 buckets and Elastic Block Store volumes.","Peirates can list AWS S3 buckets.","TruffleHog can enumerate cloud storage environments including Amazon Web Service (AWS) S3 buckets and Google Cloud Storage buckets."],"examplesTotal":3,"mitigations":[{"name":"User Account Management","text":"Restrict granting of permissions related to listing objects in cloud storage to necessary accounts.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1620","name":"Reflective Code Loading","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1620","summary":"Adversaries may reflectively load code into a process in order to conceal the execution of malicious payloads.","description":"Adversaries may reflectively load code into a process in order to conceal the execution of malicious payloads. Reflective loading involves allocating then executing payloads directly within the memory of the process, vice creating a thread or process backed by a file path on disk (e.g., Shared Modules). Reflectively loaded payloads may be compiled binaries, anonymous files (only present in RAM), or just snubs of fileless executable code (ex: position-independent shellcode).","platforms":["Linux","macOS","Windows"],"detection":["Module Load","OS API Execution","Process Access","Process Creation","Script Execution"],"examples":["During the 3CX Supply Chain Attack, AppleJeus leverages the publicly available open-source project DAVESHELL to convert PE-COFF files to position-independent code to reflectively load the payload into memory.","BADHATCH can copy a large byte array of 64-bit shellcode into process memory and execute it with a call to CreateThread.","BRUSHFIRE has executed its commands within memory and is not saved on disk.","Brute Ratel C4 has used reflective loading to execute malicious DLLs."],"examplesTotal":32},{"id":"T1621","name":"Multi-Factor Authentication Request Generation","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1621","summary":"Adversaries may attempt to bypass multi-factor authentication (MFA) mechanisms and gain access to accounts by generating MFA requests sent to users.","description":"Adversaries may attempt to bypass multi-factor authentication (MFA) mechanisms and gain access to accounts by generating MFA requests sent to users. Adversaries in possession of credentials to Valid Accounts may be unable to complete the login process if they lack access to the 2FA or MFA mechanisms required as an additional credential and security control.","platforms":["Windows","Linux","macOS","IaaS","SaaS","Office Suite","Identity Provider"],"detection":["Application Log Content","Logon Session Metadata","User Account Authentication"],"examples":["APT29 has used repeated MFA requests to gain access to victim accounts.","During C0027, Scattered Spider attempted to gain access by continuously sending MFA messages to the victim until they accept the MFA push challenge.","LAPSUS$ has spammed target users with MFA prompts in the hope that the legitimate user will grant necessary approval.","Scattered Spider has used multifactor authentication (MFA) fatigue by sending repeated MFA authentication requests to targets."],"examplesTotal":4,"mitigations":[{"name":"Multi-factor Authentication","text":"Implement more secure 2FA/MFA mechanisms in replacement of simple push or one-click 2FA/MFA options.","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Account Use Policies","text":"Enable account restrictions to prevent login attempts, and the subsequent 2FA/MFA service requests, from being initiated from suspicious locations or when the source of the login…","url":"https://attack.mitre.org/mitigations/M1036"},{"name":"User Training","text":"Train users to only accept 2FA/MFA requests from login attempts they initiated, to review source location of the login attempt prompting the 2FA/MFA requests, and to report…","url":"https://attack.mitre.org/mitigations/M1017"}]},{"id":"T1622","name":"Debugger Evasion","tactics":["Stealth","Discovery"],"url":"https://attack.mitre.org/techniques/T1622","summary":"Adversaries may employ various means to detect and avoid debuggers.","description":"Adversaries may employ various means to detect and avoid debuggers. Debuggers are typically used by defenders to trace and/or analyze the execution of potential malware payloads. Debugger evasion may include changing behaviors based on the results of the checks for the presence of artifacts indicative of a debugged environment.","platforms":["Linux","macOS","Windows"],"detection":["File Access","OS API Execution","Process Creation"],"examples":["ANELLDR can call ZwSetInformationThread with the second argument set to ThreadHideFromDebugger (0x11) to evade being debugged.","AsyncRAT can use the CheckRemoteDebuggerPresent function to detect the presence of a debugger.","The Black Basta dropper can check system flags, CPU registers, CPU instructions, process timing, system libraries, and APIs to determine if a debugger is present.","Bumblebee can search for tools used in static analysis."],"examplesTotal":26},{"id":"T1647","name":"Plist File Modification","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1647","summary":"Adversaries may modify property list files (plist files) to enable other malicious activity, while also potentially evading and bypassing system defenses.","description":"Adversaries may modify property list files (plist files) to enable other malicious activity, while also potentially evading and bypassing system defenses. macOS applications use plist files, such as the info.plist file, to store properties and configuration settings that inform the operating system how to handle the application at runtime. Plist files are structured metadata in key-value pairs formatted in XML based on Apple's Core Foundation DTD.","platforms":["macOS"],"detection":["Command Execution","File Modification","Process Creation"],"examples":["Cuckoo Stealer can create and populate property list (plist) files to enable execution.","In older versions, XCSSET uses the plutil command to modify the LSUIElement, DFBundleDisplayName, and CFBundleIdentifier keys in the /Contents/Info.plist file to change how XCSSET is visible on the system."],"examplesTotal":2,"mitigations":[{"name":"Application Developer Guidance","text":"Ensure applications are using Apple's developer guidance which enables hardened runtime.","url":"https://attack.mitre.org/mitigations/M1013"}]},{"id":"T1648","name":"Serverless Execution","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1648","summary":"Adversaries may abuse serverless computing, integration, and automation services to execute arbitrary code in cloud environments.","description":"Adversaries may abuse serverless computing, integration, and automation services to execute arbitrary code in cloud environments. Many cloud providers offer a variety of serverless resources, including compute engines, application integration services, and web servers. Adversaries may abuse these resources in various ways as a means of executing arbitrary commands. For example, adversaries may use serverless functions to execute malicious code, such as crypto-mining malware (i.e.","platforms":["SaaS","IaaS","Office Suite"],"detection":["Application Log Content","Cloud Service Modification"],"examples":["Pacu can create malicious Lambda functions."],"examplesTotal":1,"mitigations":[{"name":"Account Use Policies","text":"Where possible, consider restricting access to and use of serverless functions. For examples, conditional access policies can be applied to users attempting to create workflows in…","url":"https://attack.mitre.org/mitigations/M1036"},{"name":"User Account Management","text":"Remove permissions to create, modify, or run serverless resources from users that do not explicitly require them.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1649","name":"Steal or Forge Authentication Certificates","tactics":["Credential Access"],"url":"https://attack.mitre.org/techniques/T1649","summary":"Adversaries may steal or forge certificates used for authentication to access remote systems or resources.","description":"Adversaries may steal or forge certificates used for authentication to access remote systems or resources. Digital certificates are often used to sign and encrypt messages and/or files. Certificates are also used as authentication material. For example, Entra ID device certificates and Active Directory Certificate Services (AD CS) certificates bind to an identity and can be used as credentials for domain accounts. Authentication certificates can be both stolen and forged.","platforms":["Windows","Linux","macOS","Identity Provider"],"detection":["Active Directory Credential Request","Active Directory Object Modification","Application Log Content","Command Execution","File Access","Windows Registry Key Access"],"examples":["AADInternals can create and export various authentication certificates, including those associated with Azure AD joined/registered devices.","APT29 has abused misconfigured AD CS certificate templates to impersonate admin users and create additional authentication certificates.","Mimikatz's CRYPTO module can create and export various types of authentication certificates."],"examplesTotal":3,"mitigations":[{"name":"Active Directory Configuration","text":"Ensure certificate authorities (CA) are properly secured, including treating CA servers (and other resources hosting CA certificates) as tier 0 assets.","url":"https://attack.mitre.org/mitigations/M1015"},{"name":"Disable or Remove Feature or Program","text":"Consider disabling old/dangerous authentication protocols (e.g. NTLM), as well as unnecessary certificate features, such as potentially vulnerable AD CS web and other enrollment…","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Encrypt Sensitive Information","text":"Ensure certificates as well as associated private keys are appropriately secured. Consider utilizing additional hardware credential protections such as trusted platform modules…","url":"https://attack.mitre.org/mitigations/M1041"},{"name":"Audit","text":"Check and remediate unneeded existing authentication certificates as well as common abusable misconfigurations of CA settings and permissions, such as AD CS certificate enrollment…","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1650","name":"Acquire Access","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1650","summary":"Adversaries may purchase or otherwise acquire an existing access to a target system or network.","description":"Adversaries may purchase or otherwise acquire an existing access to a target system or network. A variety of online services and initial access broker networks are available to sell access to previously compromised systems. In some cases, adversary groups may form partnerships to share compromised systems with each other. Footholds to compromised systems may take a variety of forms, such as access to planted backdoors (e.g., Web Shell) or established access via External Remote Services.","platforms":["PRE"],"examples":["Medusa Group has purchased user credentials and other sensitive data from Initial Access Brokers (IABs)."],"examplesTotal":1,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1651","name":"Cloud Administration Command","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1651","summary":"Adversaries may abuse cloud management services to execute commands within virtual machines.","description":"Adversaries may abuse cloud management services to execute commands within virtual machines. Resources such as AWS Systems Manager, Azure RunCommand, and Runbooks allow users to remotely run scripts in virtual machines by leveraging installed virtual machine agents. If an adversary gains administrative access to a cloud environment, they may be able to abuse cloud management services to execute commands in the environment’s virtual machines.","platforms":["IaaS"],"detection":["Command Execution","Process Creation","Script Execution"],"examples":["AADInternals can execute commands on Azure virtual machines using the VM agent.","APT29 has used Azure Run Command and Azure Admin-on-Behalf-of (AOBO) to execute code on virtual machines.","Pacu can run commands on EC2 instances using AWS Systems Manager Run Command.","VOID MANTICORE has abused built-in remote wipe or factory reset commands to wipe devices managed within an organization’s Cloud management solution impacting laptops, servers, and mobile devices."],"examplesTotal":4,"mitigations":[{"name":"Privileged Account Management","text":"Limit the number of cloud accounts with permissions to remotely execute commands on virtual machines, and ensure that these are not used for day-to-day operations.","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1652","name":"Device Driver Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1652","summary":"Adversaries may attempt to enumerate local device drivers on a victim host.","description":"Adversaries may attempt to enumerate local device drivers on a victim host. Information about device drivers may highlight various insights that shape follow-on behaviors, such as the function/purpose of the host, present security tools (i.e. Security Software Discovery) or other defenses (e.g., Virtualization/Sandbox Evasion), as well as potential exploitable vulnerabilities (e.g., Exploitation for Privilege Escalation).","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Access","Process Creation","Windows Registry Key Modification"],"examples":["HOPLIGHT can enumerate device drivers located in the registry at HKLM\\Software\\WBEM\\WDM.","INC Ransomware can verify the presence of specific drivers on compromised hosts including Microsoft Print to PDF and Microsoft XPS Document Writer.","Medusa Group has queried drivers on the victim device through the command driverquery.","Remsec has a plugin to detect active drivers of some security products."],"examplesTotal":4},{"id":"T1653","name":"Power Settings","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1653","summary":"Adversaries may impair a system's ability to hibernate, reboot, or shut down in order to extend access to infected machines.","description":"Adversaries may impair a system's ability to hibernate, reboot, or shut down in order to extend access to infected machines. When a computer enters a dormant state, some or all software and hardware may cease to operate which can disrupt malicious activity. Adversaries may abuse system utilities and configuration settings to maintain access by preventing machines from entering a state, such as standby, that can terminate malicious activity.","platforms":["Windows","Linux","macOS","Network Devices"],"detection":["Command Execution","File Modification","Process Creation"],"examples":["ArcaneDoor involved exploitation of CVE-2024-20353 to force a victim Cisco ASA to reboot, triggering the automated unzipping and execution of the Line Runner implant.","Line Dancer can modify the crash dump process on infected machines to skip crash dump generation and proceed directly to device reboot for both persistence and forensic evasion purposes.","Line Runner used CVE-2024-20353 to trigger victim devices to reboot, in the process unzipping and installing the Line Dancer payload."],"examplesTotal":3,"mitigations":[{"name":"Audit","text":"Periodically inspect systems for abnormal and unexpected power settings that may indicate malicious activty.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1654","name":"Log Enumeration","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1654","summary":"Adversaries may enumerate system and service logs to find useful data.","description":"Adversaries may enumerate system and service logs to find useful data. These logs may highlight various types of valuable insights for an adversary, such as user authentication records (Account Discovery), security or vulnerable software (Software Discovery), or hosts within a compromised network (Remote System Discovery). Host binaries may be leveraged to collect system logs. Examples include using wevtutil.exe or PowerShell on Windows to access and/or export security event information.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"detection":["Command Execution","File Access","Process Creation"],"examples":["APT5 has used the BLOODMINE utility to parse and extract information from Pulse Secure Connect logs.","Akira _v2 can enumerate the trace, debug, error, info, and warning logs on targeted systems.","Aquatic Panda enumerated logs related to authentication in Linux environments prior to deleting selective entries for defense evasion purposes.","BeaverTail has identified .ldb and .log files stored in browser extension directories for collection and exfiltration."],"examplesTotal":10,"mitigations":[{"name":"User Account Management","text":"Limit the ability to access and export sensitive logs to privileged accounts where possible.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1657","name":"Financial Theft","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1657","summary":"Adversaries may steal monetary resources from targets through extortion, social engineering, technical theft, or other methods aimed at their own financial gain at the expense of the availability of these resources for victims.","description":"Adversaries may steal monetary resources from targets through extortion, social engineering, technical theft, or other methods aimed at their own financial gain at the expense of the availability of these resources for victims. Financial theft is the ultimate objective of several popular campaign types including extortion by ransomware, business email compromise (BEC) and fraud, \"pig butchering,\" bank hacking, and exploiting cryptocurrency networks.","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","Command Execution","File Modification","Logon Session Creation","Process Creation"],"examples":["Akira engages in double-extortion ransomware, exfiltrating files then encrypting them, in order to prompt victims to pay a ransom.","AppleJeus has targeted the cryptocurrency industry with the goal of stealing digital assets.","BeaverTail has searched the victim device for browser extensions commonly associated with cryptocurrency wallets.","Cinnamon Tempest has maintained leak sites for exfiltrated data in attempt to extort victims into paying a ransom."],"examplesTotal":23,"mitigations":[{"name":"User Training","text":"Train and encourage users to identify social engineering techniques used to enable financial theft.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"User Account Management","text":"Limit access/authority to execute sensitive transactions, and switch to systems and procedures designed to authenticate/approve payments and purchase requests outside of insecure…","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1659","name":"Content Injection","tactics":["Initial Access","Command and Control"],"url":"https://attack.mitre.org/techniques/T1659","summary":"Adversaries may gain access and continuously communicate with victims by injecting malicious content into systems through online network traffic.","description":"Adversaries may gain access and continuously communicate with victims by injecting malicious content into systems through online network traffic. Rather than luring victims to malicious payloads hosted on a compromised website (i.e., Drive-by Target followed by Drive-by Compromise), adversaries may initially access victims through compromised data-transfer channels where they can manipulate traffic and/or inject their own content.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","File Creation","Network Traffic Content","Process Creation"],"examples":["Disco has achieved initial access and execution through content injection into DNS, HTTP, and SMB replies to targeted hosts that redirect them to download malicious files.","MoustachedBouncer has injected content into DNS, HTTP, and SMB replies to redirect specifically-targeted victims to a fake Windows Update page to download malware."],"examplesTotal":2,"mitigations":[{"name":"Restrict Web-Based Content","text":"Consider blocking download/transfer and execution of potentially uncommon file types known to be used in adversary campaigns.","url":"https://attack.mitre.org/mitigations/M1021"},{"name":"Encrypt Sensitive Information","text":"Where possible, ensure that online traffic is appropriately encrypted through services such as trusted VPNs.","url":"https://attack.mitre.org/mitigations/M1041"}]},{"id":"T1665","name":"Hide Infrastructure","tactics":["Command and Control"],"url":"https://attack.mitre.org/techniques/T1665","summary":"Adversaries may manipulate network traffic in order to hide and evade detection of their C2 infrastructure.","description":"Adversaries may manipulate network traffic in order to hide and evade detection of their C2 infrastructure. This can be accomplished by identifying and filtering traffic from defensive tools, masking malicious domains to obfuscate the true destination from both automated scanning tools and security researchers, and otherwise hiding malicious artifacts to delay discovery and prolong the effectiveness of adversary infrastructure that could otherwise be identified, blocked, or taken down entirely.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Domain Registration","Network Connection Creation","Network Traffic Content","Process Creation","Response Content","Response Metadata"],"examples":["APT29 uses compromised residential endpoints, typically within the same ISP IP address range, as proxies to hide the true source of C2 traffic.","DarkGate command and control includes hard-coded domains in the malware masquerading as legitimate services such as Akamai CDN or Amazon Web Services.","JumbledPath can use a chain of jump hosts to communicate with compromised devices to obscure actor infrastructure.","During Operation Digital Eye, threat actors used public Cloud infrastructure to mask malicious activity."],"examplesTotal":8},{"id":"T1666","name":"Modify Cloud Resource Hierarchy","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1666","summary":"Adversaries may attempt to modify hierarchical structures in infrastructure-as-a-service (IaaS) environments in order to evade defenses.","description":"Adversaries may attempt to modify hierarchical structures in infrastructure-as-a-service (IaaS) environments in order to evade defenses. IaaS environments often group resources into a hierarchy, enabling improved resource management and application of policies to relevant groups. Hierarchical structures differ among cloud providers.","platforms":["IaaS"],"detection":["Cloud Service Modification"],"mitigations":[{"name":"Software Configuration","text":"In Azure environments, consider setting a policy to block subscription transfers. In AWS environments, consider using Service Control Policies to prevent the use of the…","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"User Account Management","text":"Limit permissions to add, delete, or modify resource groups to only those required.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Audit","text":"Periodically audit resource groups in the cloud management console to ensure that only expected items exist, especially close to the top of the hierarchy (e.g., AWS accounts and…","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1667","name":"Email Bombing","tactics":["Impact"],"url":"https://attack.mitre.org/techniques/T1667","summary":"Adversaries may flood targeted email addresses with an overwhelming volume of messages.","description":"Adversaries may flood targeted email addresses with an overwhelming volume of messages. This may bury legitimate emails in a flood of spam and disrupt business operations. An adversary may accomplish email bombing by leveraging an automated bot to register a targeted address for e-mail lists that do not validate new signups, such as online newsletters. The result can be a wave of thousands of e-mails that effectively overloads the victim’s inbox.","platforms":["Linux","Office Suite","Windows","macOS"],"detection":["Application Log Content","File Creation"],"examples":["Storm-1811 has deployed large volumes of non-malicious email spam to victims in order to prompt follow-on interactions with the threat actor posing as IT support or helpdesk to resolve the problem."],"examplesTotal":1,"mitigations":[{"name":"User Training","text":"Train users to be aware of access or manipulation attempts by an adversary to reduce the risk of successful social engineering via e-mail bombing.","url":"https://attack.mitre.org/mitigations/M1017"},{"name":"Software Configuration","text":"Use anti-spoofing and email authentication mechanisms to filter messages based on validity checks of the sender domain (using SPF) and integrity of messages (using DKIM).","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1668","name":"Exclusive Control","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1668","summary":"Adversaries who successfully compromise a system may attempt to maintain persistence by “closing the door” behind them – in other words, by preventing other threat actors from initially accessing or maintaining a foothold on the same…","description":"Adversaries who successfully compromise a system may attempt to maintain persistence by “closing the door” behind them – in other words, by preventing other threat actors from initially accessing or maintaining a foothold on the same system. For example, adversaries may patch a vulnerable, compromised system to prevent other threat actors from leveraging that vulnerability in the future.","platforms":["Linux","macOS","Windows"],"detection":["Command Execution","Process Creation","Process Termination"]},{"id":"T1669","name":"Wi-Fi Networks","tactics":["Initial Access"],"url":"https://attack.mitre.org/techniques/T1669","summary":"Adversaries may gain initial access to target systems by connecting to wireless networks.","description":"Adversaries may gain initial access to target systems by connecting to wireless networks. They may accomplish this by exploiting open Wi-Fi networks used by target devices or by accessing secured Wi-Fi networks — requiring Valid Accounts — belonging to a target organization. Establishing a connection to a Wi-Fi access point requires a certain level of proximity to both discover and maintain a stable network connection.","platforms":["Linux","Network Devices","Windows","macOS"],"detection":["Firewall Rule Modification","Network Connection Creation","Network Traffic Content","Network Traffic Flow","User Account Authentication"],"examples":["APT28 has exploited open Wi-Fi access points for initial access to target devices using the network.","During APT28 Nearest Neighbor Campaign, APT28 established wireless connections to secure, enterprise Wi-Fi networks belonging to a target organization for initial access into the environment."],"examplesTotal":2,"mitigations":[{"name":"Multi-factor Authentication","text":"Harden access requirements for Wi-Fi networks through using two or more pieces of evidence to authenticate, such as a username and password in addition to a token from a physical…","url":"https://attack.mitre.org/mitigations/M1032"},{"name":"Network Segmentation","text":"Network segmentation can be used to isolate infrastructure components that do not require broad network access.","url":"https://attack.mitre.org/mitigations/M1030"},{"name":"Encrypt Sensitive Information","text":"Ensure that all wired and/or wireless traffic is encrypted appropriately. Use best practices for authentication protocols, such as Kerberos, and ensure that web traffic that may…","url":"https://attack.mitre.org/mitigations/M1041"}]},{"id":"T1671","name":"Cloud Application Integration","tactics":["Persistence"],"url":"https://attack.mitre.org/techniques/T1671","summary":"Adversaries may achieve persistence by leveraging OAuth application integrations in a software-as-a-service environment.","description":"Adversaries may achieve persistence by leveraging OAuth application integrations in a software-as-a-service environment. Adversaries may create a custom application, add a legitimate application into the environment, or even co-opt an existing integration to achieve malicious ends. OAuth is an open standard that allows users to authorize applications to access their information on their behalf.","platforms":["Office Suite","SaaS"],"detection":["Active Directory Object Modification","Application Log Content","Cloud Service Modification"],"examples":["During Salesforce Data Exfiltration, threat actors deceived victims into authorizing malicious connected apps to their organization's Salesforce portal."],"examplesTotal":1,"mitigations":[{"name":"Disable or Remove Feature or Program","text":"Do not allow users to add new application integrations into a SaaS environment. In Entra ID environments, consider enforcing the “Do not allow user consent” option.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Audit","text":"Periodically review SaaS integrations for unapproved or potentially malicious applications.","url":"https://attack.mitre.org/mitigations/M1047"}]},{"id":"T1673","name":"Virtual Machine Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1673","summary":"An adversary may attempt to enumerate running virtual machines (VMs) after gaining access to a host or hypervisor.","description":"An adversary may attempt to enumerate running virtual machines (VMs) after gaining access to a host or hypervisor. For example, adversaries may enumerate a list of VMs on an ESXi hypervisor using a Hypervisor CLI such as esxcli or vim-cmd (e.g. esxcli vm process list or vim-cmd vmsvc/getallvms). Adversaries may also directly leverage a graphical user interface, such as VMware vCenter, in order to view virtual machines on a host.","platforms":["ESXi","Linux","macOS","Windows"],"detection":["Command Execution","Process Creation"],"examples":["Cheerscrypt has leveraged esxcli vm process list in order to gather a list of running virtual machines to terminate them.","PureCrypter can identify virtual machines by querying the WMI object Win32_ComputerSystem for manufacturer and model and check it against the regular expression Microsoft|VMWare|Virtual.","Qilin can detect virtual machine environments including ESXi hosts, datacenters, and clusters within vCenter environments.","UNC3886 has used scripts to enumerate ESXi hypervisors and their guest VMs."],"examplesTotal":5},{"id":"T1674","name":"Input Injection","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1674","summary":"Adversaries may simulate keystrokes on a victim’s computer by various means to perform any type of action on behalf of the user, such as launching the command interpreter using keyboard shortcuts, typing an inline script to be executed,…","description":"Adversaries may simulate keystrokes on a victim’s computer by various means to perform any type of action on behalf of the user, such as launching the command interpreter using keyboard shortcuts, typing an inline script to be executed, or interacting directly with a GUI-based application. These actions can be preprogrammed into adversary tooling or executed through physical devices such as Human Interface Devices (HIDs).","platforms":["Windows","macOS","Linux"],"detection":["Command Execution","Drive Creation","Process Creation","Script Execution"],"examples":["FIN7 has used malicious USBs to emulate keystrokes to launch PowerShell to download and execute malware from the adversary's server."],"examplesTotal":1,"mitigations":[{"name":"Limit Hardware Installation","text":"Limit the use of USB devices and removable media within a network.","url":"https://attack.mitre.org/mitigations/M1034"},{"name":"Execution Prevention","text":"Denylist scripting and use application control where appropriate. For example, PowerShell Constrained Language mode can be used to restrict access to sensitive or otherwise…","url":"https://attack.mitre.org/mitigations/M1038"}]},{"id":"T1675","name":"ESXi Administration Command","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1675","summary":"Adversaries may abuse ESXi administration services to execute commands on guest machines hosted within an ESXi virtual environment.","description":"Adversaries may abuse ESXi administration services to execute commands on guest machines hosted within an ESXi virtual environment. Persistent background services on ESXi-hosted VMs, such as the VMware Tools Daemon Service, allow for remote management from the ESXi server. The tools daemon service runs as vmtoolsd.exe on Windows guest operating systems, vmware-tools-daemon on macOS, and vmtoolsd on Linux.","platforms":["ESXi"],"detection":["Application Log Content"],"examples":["UNC3886 used vmtoolsd.exe to run commands on guest virtual machines from a compromised ESXi host.","VIRTUALPITA can execute commands on guest virtual machines from compromised ESXi hypervisors."],"examplesTotal":2,"mitigations":[{"name":"User Account Management","text":"If not required, restrict the permissions of users to perform Guest Operations on ESXi-hosted VMs.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1677","name":"Poisoned Pipeline Execution","tactics":["Execution"],"url":"https://attack.mitre.org/techniques/T1677","summary":"Adversaries may manipulate continuous integration / continuous development (CI/CD) processes by injecting malicious code into the build process.","description":"Adversaries may manipulate continuous integration / continuous development (CI/CD) processes by injecting malicious code into the build process. There are several mechanisms for poisoning pipelines: In a <b>Direct Pipeline Execution</b> scenario, the threat actor directly modifies the CI configuration file (e.g., gitlab-ci.yml in GitLab). They may include a command to exfiltrate credentials leveraged in the build process to a remote server, or to export them as a workflow artifact.","platforms":["SaaS"],"detection":["Cloud Service Metadata","Cloud Service Modification","Cloud Storage Access","Command Execution","File Metadata"],"examples":["Shai-Hulud has also leveraged GitHub actions from stolen accounts in order to create a malicious Github workflow within .github/workflows/discussion.yaml."],"examplesTotal":1,"mitigations":[{"name":"User Account Management","text":"Ensure that CI/CD pipelines only have permissions they require to complete their operations.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Software Configuration","text":"Where possible, avoid allowing pipelines to run unreviewed code. Where this is necessary, ensure that these pipelines are executed on isolated nodes without access to secrets.","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1678","name":"Delay Execution","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1678","summary":"Adversaries may employ various time-based methods to evade detection and analysis.","description":"Adversaries may employ various time-based methods to evade detection and analysis. These techniques often exploit system clocks, delays, or timing mechanisms to obscure malicious activity, blend in with benign activity, and avoid scrutiny. Adversaries can perform this behavior within virtualization/sandbox environments or natively on host systems. Adversaries may utilize programmatic sleep commands or native system scheduling functionality, for example Scheduled Task/Job.","platforms":["Linux","macOS","Windows"],"detection":["Module Load","Process Creation","Script Execution"],"examples":["During the 3CX Supply Chain Attack, AppleJeus's software generates a randomly selected date that is between 1-4 weeks in the future.","AshTag can use a set sleep time to delay C2 beaconing.","BRICKSTORM has embedded delayed-start logic that attempts to circumvent detection for long-term persistence. BRICKSTORM has been observed configured with a “delay” timer built-in that waited for a hard-coded date months in the future…","DynoWiper has utilized a five-second delay using Sleep(5000) between two of the three phases of the attack that involves file overwriting, file deletion, and system reboot."],"examplesTotal":19},{"id":"T1679","name":"Selective Exclusion","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1679","summary":"Adversaries may intentionally exclude certain files, folders, directories, file types, or system components from encryption or tampering during a ransomware or malicious payload execution.","description":"Adversaries may intentionally exclude certain files, folders, directories, file types, or system components from encryption or tampering during a ransomware or malicious payload execution. Some file extensions that adversaries may avoid encrypting include .dll, .exe, and .lnk.","platforms":["Windows"],"detection":["Command Execution","File Modification","Process Creation"],"examples":["DynoWiper has recursively enumerated directories with the exception of the following: System32, Windows, Program Files, Program Files(x86), Temp, Recycle.Bin, $Recycle.Bin, Boot, PerfLogs, AppData, Documents and Settings.","Embargo has avoided encrypting specific files and directories by leveraging a regular expression within the ransomware binary.","InvisibleFerret has the capability to scan for file names, file extensions, and avoids pre-designated path names and file types.","LazyWiper can enumerate the hostname of the system to determine if it is a domain controller and exclude it from being wiped if so."],"examplesTotal":7},{"id":"T1680","name":"Local Storage Discovery","tactics":["Discovery"],"url":"https://attack.mitre.org/techniques/T1680","summary":"Adversaries may enumerate local drives, disks, and/or volumes and their attributes like total or free space and volume serial number.","description":"Adversaries may enumerate local drives, disks, and/or volumes and their attributes like total or free space and volume serial number. This can be done to prepare for ransomware-related encryption, to perform Lateral Movement, or as a precursor to Direct Volume Access. On ESXi systems, adversaries may use Hypervisor CLI commands such as esxcli to list storage connected to the host as well as .vmdk files.","platforms":["ESXi","IaaS","Linux","macOS","Windows"],"detection":["Command Execution","Process Creation","User Account Authentication"],"examples":["Aria-body has the ability to identify disk information on a compromised host.","AshTag can use volumeserialnumber to enumerate volumes.","AsyncRAT can check the disk size through the values obtained with DeviceInfo.","Attor monitors the free disk space on the system."],"examplesTotal":101},{"id":"T1681","name":"Search Threat Vendor Data","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1681","summary":"Threat actors may seek information/indicators from closed or open threat intelligence sources gathered about their own campaigns, as well as those conducted by other adversaries that may align with their target industries,…","description":"Threat actors may seek information/indicators from closed or open threat intelligence sources gathered about their own campaigns, as well as those conducted by other adversaries that may align with their target industries, capabilities/objectives, or other operational concerns. These reports may include descriptions of behavior, detailed breakdowns of attacks, atomic indicators such as malware hashes or IP addresses, timelines of a group’s activity, and more.","platforms":["PRE"],"examples":["Contagious Interview has registered accounts with Threat Intelligence vendor services to check for reporting associated with their infrastructure and to evaluate new potential infrastructure.","UNC3886 has replaced indicators mentioned in open-source threat intelligence publications at times under a week after their release."],"examplesTotal":2,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1682","name":"Query Public AI Services","tactics":["Reconnaissance"],"url":"https://attack.mitre.org/techniques/T1682","summary":"Adversaries may query publicly accessible artificial intelligence (AI) services, such as large language models (LLMs), to support targeting and operations.","description":"Adversaries may query publicly accessible artificial intelligence (AI) services, such as large language models (LLMs), to support targeting and operations. In addition to searching websites or databases directly (i.e., Search Open Websites/Domains), adversaries may use AI services to synthesize, aggregate, and analyze publicly available information at scale.","platforms":["PRE"],"examples":["APT42 has leveraged LLMs to search for official emails to build target lists, and conduct reconnaissance on potential business partners.","Kimsuky has used LLMs to identify think tanks, government organizations, and experts to inform targeting for spearphishing campaigns."],"examplesTotal":2,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1683","name":"Generate Content","tactics":["Resource Development"],"url":"https://attack.mitre.org/techniques/T1683","summary":"Adversaries may create or generate content to support targeting and operations.","description":"Adversaries may create or generate content to support targeting and operations. This content may be used to establish personas, impersonate known individuals or organizations, and support Social Engineering, fraud, or influence activities. Written materials, audio, images, video, or other media may be developed and tailored to the target and objective. Content development may occur prior to or during an operation.","platforms":["PRE"],"examples":["During the Anthropic AI-orchestrated Campaign, the adversary utilized Claude Code to automatically generate comprehensive documentation throughout the phases of the attack, including discovered services, harvested credentials, sensitive…"],"examplesTotal":1,"mitigations":[{"name":"Pre-compromise","text":"This technique cannot be easily mitigated with preventive controls since it is based on behaviors performed outside of the scope of enterprise defenses and controls.","url":"https://attack.mitre.org/mitigations/M1056"}]},{"id":"T1684","name":"Social Engineering","tactics":["Stealth"],"url":"https://attack.mitre.org/techniques/T1684","summary":"Adversaries may use social engineering techniques to influence users to take actions that result in unauthorized access, approval of changes, disclosure of sensitive information, or execution of adversary-supplied instructions (i.e.,…","description":"Adversaries may use social engineering techniques to influence users to take actions that result in unauthorized access, approval of changes, disclosure of sensitive information, or execution of adversary-supplied instructions (i.e., introduction of malicious payloads or software), while minimizing technical indicators.","platforms":["Linux","macOS","Office Suite","SaaS","Windows"],"detection":["Application Log Content","Command Execution","File Access","File Creation","File Modification","Logon Session Creation","Network Connection Creation","Process Creation","User Account Authentication"],"mitigations":[{"name":"Account Use Policies","text":"Adds verification for helpdesk resets, approvals, and app consents commonly targeted by impersonation.","url":"https://attack.mitre.org/mitigations/M1036"},{"name":"Audit","text":"Enables correlation of email/identity/SaaS/endpoint activity that appears legitimate.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"User Training","text":"Reduces success of phishing/vishing/impersonation and modern “human interface” lures.","url":"https://attack.mitre.org/mitigations/M1017"}]},{"id":"T1685","name":"Disable or Modify Tools","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1685","summary":"Adversaries may disable, degrade, or tamper with security tools or applications (e.g., endpoint detection and response (EDR) tools, intrusion detection systems (IDS), antivirus, logging agents, sensors, etc.) to impair or reduce…","description":"Adversaries may disable, degrade, or tamper with security tools or applications (e.g., endpoint detection and response (EDR) tools, intrusion detection systems (IDS), antivirus, logging agents, sensors, etc.) to impair or reduce visibility of defensive capabilities. This may include stopping specific services, killing processes, modifying or deleting tool configuration files and Registry keys, or preventing tools from updating.","platforms":["Containers","ESXi","IaaS","Linux","macOS","Network Devices","Windows"],"detection":["Cloud Service Modification","Command Execution","Host Status","Process Creation","Process Termination","Service Creation","Service Metadata","Service Modification","Windows Registry Key Modification"],"examples":["During the 2015 Ukraine Electric Power Attack, Sandworm Team modified in-registry internet settings to lower internet security.","APT38 has unhooked DLLs to disable endpoint detection and response (EDR) or anti-virus (AV) tools.","APT41 developed a custom injector that enables an Event Tracing for Windows (ETW) bypass, making malicious processes invisible to Windows logging.","APT5 has used the CLEANPULSE utility to insert command line strings into a targeted process to prevent certain log events from occurring."],"examplesTotal":128,"mitigations":[{"name":"User Account Management","text":"Ensure proper user permissions are in place to prevent adversaries from disabling or interfering with security services.","url":"https://attack.mitre.org/mitigations/M1018"},{"name":"Audit","text":"Periodically verify that tools are functioning appropriately – for example, that all expected hosts with EDRs or monitoring agents are checking in to the central console.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Restrict File and Directory Permissions","text":"Ensure proper process and file permissions are in place to prevent adversaries from disabling or interfering with security services.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"Disable or Remove Feature or Program","text":"Consider removing previous versions of tools that are unnecessary to the environment when possible.","url":"https://attack.mitre.org/mitigations/M1042"},{"name":"Software Configuration","text":"Consider automatically relaunching forwarding mechanisms at recurring intervals (ex: temporal, on-logon, etc.) as well as applying appropriate change management to firewall rules…","url":"https://attack.mitre.org/mitigations/M1054"}]},{"id":"T1686","name":"Disable or Modify System Firewall","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1686","summary":"Adversaries may disable or modify host-based or network firewalls to impair defensive mechanisms and enable further action.","description":"Adversaries may disable or modify host-based or network firewalls to impair defensive mechanisms and enable further action. Once an adversary has gathered sufficient privileges, they can tamper with firewall services, policies, or rule sets to remove restrictions on inbound or outbound traffic.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Firewall Rule Modification","Process Creation","Windows Registry Key Modification"],"examples":["APT38 have created firewall exemptions on specific ports, including ports 443, 6443, 8443, and 9443.","The \"ZR\" variant of BACKSPACE will check to see if known host-based firewalls are installed on the infected systems. BACKSPACE will attempt to establish a C2 channel, then will examine open windows to identify a pop-up from the firewall…","BPFDoor starts a shell on a high TCP port starting at 42391 up to 43391, then changes the local iptables rules to redirect all packets from the attacker to the shell port.","BlackByte modified firewall rules on victim machines to enable remote system discovery."],"examplesTotal":30,"mitigations":[{"name":"Audit","text":"Routinely check account role permissions to ensure only expected users and roles have permission to modify system firewalls.","url":"https://attack.mitre.org/mitigations/M1047"},{"name":"Restrict Registry Permissions","text":"Ensure proper Registry permissions are in place to prevent adversaries from disabling or modifying firewall settings.","url":"https://attack.mitre.org/mitigations/M1024"},{"name":"Restrict File and Directory Permissions","text":"Ensure proper process and file permissions are in place to prevent adversaries from disabling or modifying firewall settings.","url":"https://attack.mitre.org/mitigations/M1022"},{"name":"User Account Management","text":"Ensure proper user permissions are in place to prevent adversaries from disabling or modifying firewall settings.","url":"https://attack.mitre.org/mitigations/M1018"}]},{"id":"T1687","name":"Exploitation for Defense Impairment","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1687","summary":"Adversaries may exploit vulnerabilities in security software, infrastructure, or defensive components to degrade, disable, or otherwise continue to impair their ability to prevent, detect, or respond to malicious activity.","description":"Adversaries may exploit vulnerabilities in security software, infrastructure, or defensive components to degrade, disable, or otherwise continue to impair their ability to prevent, detect, or respond to malicious activity. Adversaries may exploit a system or application vulnerability to directly interfere with defensive mechanisms.","platforms":["IaaS","Linux","macOS","SaaS","Windows"],"detection":["Application Log Content","Cloud Service Disable","Command Execution","Driver Load","Driver Metadata","Firewall Rule Modification","Instance Modification","Network Traffic Content","Process Creation","Process Metadata"]},{"id":"T1688","name":"Safe Mode Boot","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1688","summary":"Adversaries may abuse Windows safe mode to disable endpoint defenses.","description":"Adversaries may abuse Windows safe mode to disable endpoint defenses. Safe mode starts up the Windows operating system with a limited set of drivers and services. Third-party security software such as endpoint detection and response (EDR) tools may not start after booting Windows in safe mode. There are two versions of safe mode: Safe Mode and Safe Mode with Networking. It is possible to start additional services after a safe mode boot.","platforms":["Windows"],"detection":["Process Creation","Windows Registry Key Creation","Windows Registry Key Modification"],"examples":["AvosLocker can restart a compromised machine in safe mode.","Black Basta can reboot victim machines in safe mode with networking via bcdedit /set safeboot network.","Embargo has used a DLL variant of MDeployer to disable security solutions through Safe Mode.","LockBit 3.0 can reboot the infected host into Safe Mode."],"examplesTotal":7,"mitigations":[{"name":"Software Configuration","text":"Ensure that endpoint defenses run in safe mode.","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Privileged Account Management","text":"Restrict administrator accounts to as few individuals as possible, following least privilege principles, that may be abused to remotely boot a machine in safe mode.","url":"https://attack.mitre.org/mitigations/M1026"}]},{"id":"T1689","name":"Downgrade Attack","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1689","summary":"Adversaries may downgrade or use a version of system features that may be outdated, vulnerable, and/or does not support updated security controls.","description":"Adversaries may downgrade or use a version of system features that may be outdated, vulnerable, and/or does not support updated security controls. Downgrade attacks typically take advantage of a system’s backward compatibility to force it into less secure modes of operation.","platforms":["macOS","Windows","Linux"],"detection":["Command Execution","Process Creation","Process Metadata","Windows Registry Key Modification"],"examples":["BlackByte Ransomware enables SMBv1 during execution.","During FrostyGoop Incident, the adversary downgraded firmware on victim devices in order to impair visibility into the process environment.","SILENTTRINITY can downgrade NTLM to capture NTLM hashes."],"examplesTotal":3,"mitigations":[{"name":"Software Configuration","text":"Consider implementing policies on internal web servers, such HTTP Strict Transport Security, that enforce the use of HTTPS/network traffic encryption to prevent insecure…","url":"https://attack.mitre.org/mitigations/M1054"},{"name":"Disable or Remove Feature or Program","text":"Consider removing previous versions of tools that are unnecessary to the environment when possible.","url":"https://attack.mitre.org/mitigations/M1042"}]},{"id":"T1690","name":"Prevent Command History Logging","tactics":["Defense Impairment"],"url":"https://attack.mitre.org/techniques/T1690","summary":"Adversaries may impair command history logging to hide commands they run on a compromised system.","description":"Adversaries may impair command history logging to hide commands they run on a compromised system. Various command interpreters keep track of the commands users type in their terminal so that users can retrace what they have done. On Linux and macOS, command history is tracked in a file pointed to by the environment variable HISTFILE. When a user logs off a system, this information is flushed to a file in the user's home directory called ~/.bash_history.","platforms":["ESXi","Linux","macOS","Network Devices","Windows"],"detection":["Command Execution","Process Creation"],"examples":["APT38 has prepended a space to all of their terminal commands to operate without leaving traces in the HISTCONTROL environment.","ArcaneDoor included disabling logging on targeted Cisco ASA appliances.","BPFDoor sets the MYSQL_HISTFILE and HISTFILE to /dev/null preventing the shell and MySQL from logging history in /proc/<PID>/environ.","BRICKSTORM has impaired command logging through the use of dev/null which prevents generating output from the command and does not wait for input."],"examplesTotal":12,"mitigations":[{"name":"Environment Variable Permissions","text":"Prevent users from changing the HISTCONTROL, HISTFILE, and HISTFILESIZE environment variables.","url":"https://attack.mitre.org/mitigations/M1039"},{"name":"Operating System Configuration","text":"Make sure that the HISTCONTROL environment variable is set to “ignoredups” instead of “ignoreboth” or “ignorespace”.","url":"https://attack.mitre.org/mitigations/M1028"}]}];
